import sys
import argparse
from pathlib import Path

def process_file(file_path):
    try:
        content = file_path.read_text(encoding="utf-8")
        lines = content.splitlines()

        new_lines = []
        changed = False

        for line in lines:
            stripped = line.strip()
            if stripped.startswith("[") and stripped.endswith("]"):
                changed = True
                continue
            new_lines.append(line)

        if changed:
            file_path.write_text("\n".join(new_lines), encoding="utf-8")
            return True
    except Exception as e:
        print(f"Error processing {file_path}: {e}")

    return False

def main():
    parser = argparse.ArgumentParser(description="Clean bracketed headers from existing lyrics files")
    parser.add_argument("path", help="Library root path to scan")
    args = parser.parse_args()

    root = Path(args.path).expanduser().resolve()
    if not root.exists():
        print(f"Error: Path {root} does not exist")
        return

    print(f"Scanning for lyrics in: {root}")

    clean_count = 0
    total_found = 0

    for lyrics_file in root.rglob("Lyrics/*.txt"):
        total_found += 1
        if process_file(lyrics_file):
            print(f"Cleaned: {lyrics_file.relative_to(root)}")
            clean_count += 1

    print(f"\nFinished. Scanned {total_found} files, cleaned {clean_count} files.")

if __name__ == "__main__":
    main()



import os
import sys
import json
import re
import argparse
from pathlib import Path
import lyricsgenius

def clean_genius_lyrics(lyrics, title):
    if not lyrics:
        return ""

    lines = lyrics.split("\n")
    if lines and "Contributors" in lines[0]:
        lines.pop(0)

    filtered_lines =[]
    for line in lines:
        trimmed = line.strip()
        if trimmed.startswith("[") and trimmed.endswith("]"):
            continue
        filtered_lines.append(trimmed)

    cleaned = "\n".join(filtered_lines)

    cleaned = re.sub(r"\(\s*\n\s*", "(", cleaned)
    cleaned = re.sub(r"\s*\n\s*\)", ")", cleaned)
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned)

    cleaned = re.sub(r"[0-9]*Embed$", "", cleaned)
    cleaned = cleaned.strip()

    return cleaned

def sanitize_filename(name):
    return re.sub(r'[<>:"/\\|?*]', '_', name)

def fetch_album_lyrics(album_root_path, access_token):
    root = Path(album_root_path).expanduser().resolve()
    lock_file = root / "metadata.lock.json"

    if not lock_file.exists():
        print(f"Error: metadata.lock.json not found in {root}")
        return

    with open(lock_file, "r", encoding="utf-8") as f:
        data = json.load(f)

    album_artist = data.get("album", {}).get("albumartist")
    total_discs = int(data.get("album", {}).get("info", {}).get("total_discs", 1))
    tracks = data.get("tracks",[])

    if not album_artist or not tracks:
        print("Error: Invalid metadata structure in lock file.")
        return

    genius = lyricsgenius.Genius(access_token)
    genius.verbose = False
    genius.remove_section_headers = True

    lyrics_dir = root / "Lyrics"
    lyrics_dir.mkdir(exist_ok=True)

    print(f"Fetching lyrics for: {album_artist} - {data.get('album', {}).get('album')}")

    for track in tracks:
        title = track.get("title")
        track_num = str(track.get("tracknumber", "0")).zfill(2)
        disc_num = str(track.get("discnumber", "1"))

        if not title:
            continue

        safe_title = sanitize_filename(title)

        if total_discs > 1:
            filename = f"{disc_num}.{track_num} - {safe_title}.txt"
        else:
            filename = f"{track_num} - {safe_title}.txt"

        dest_path = lyrics_dir / filename

        if dest_path.exists():
            print(f"  Skipping: {title} (File exists)")
            continue

        try:
            song = genius.search_song(title, album_artist)
            if song:
                cleaned_text = clean_genius_lyrics(song.lyrics, title)
                with open(dest_path, "w", encoding="utf-8") as lf:
                    lf.write(cleaned_text)
                print(f"  Saved: {title}")
            else:
                print(f"  Not found: {title}")
        except Exception as e:
            print(f"  Error fetching {title}: {e}")

def main():
    parser = argparse.ArgumentParser(description="Fetch lyrics for a Vellum album using Genius API")
    parser.add_argument(
        "path",
        help="Path to the album root directory containing metadata.lock.json"
    )
    parser.add_argument(
        "--token",
        help="Genius API Access Token (or set GENIUS_ACCESS_TOKEN env var)"
    )

    args = parser.parse_args()

    token = args.token or os.environ.get("GENIUS_ACCESS_TOKEN")
    if not token:
        print("Error: Genius Access Token is required via --token or GENIUS_ACCESS_TOKEN environment variable.")
        sys.exit(1)

    fetch_album_lyrics(args.path, token)

if __name__ == "__main__":
    main()



import sys
import shutil
from pathlib import Path

def process_metadata_path(raw_path):
    clean_path = raw_path.strip().strip('"').strip("'")
    if not clean_path:
        return

    path = Path(clean_path).resolve()

    if not path.exists():
        print(f"IO_ERROR: Targeted manifest not found at \"{path}\"", file=sys.stderr)
        return

    mbid_path = path.parent / "mbid.toml"

    try:
        shutil.copy2(path, mbid_path)
    except Exception as e:
        print(f"COPY_ERROR: Failed to create mbid.toml for \"{path.parent.name}\": {e}", file=sys.stderr)
        return

    try:
        with open(path, "r", encoding="utf-8") as f:
            lines = f.readlines()
        with open(path, "w", encoding="utf-8") as f:
            for line in lines:
                if not line.lstrip().to_lowercase().startswith("musicbrainz_"):
                    f.write(line)
    except Exception as e:
        print(f"WRITE_ERROR: Failed to strip IDs from metadata.toml at \"{path}\": {e}", file=sys.stderr)

    allowed_prefixes = (
        "[album]",
        "albumartist",
        "album",
        "date",
        "[[tracks]]",
        "tracknumber",
        "title",
        "musicbrainz_"
    )

    try:
        with open(mbid_path, "r", encoding="utf-8") as f:
            lines = f.readlines()
        with open(mbid_path, "w", encoding="utf-8") as f:
            for line in lines:
                stripped = line.strip().lower()
                if not stripped:
                    f.write(line)
                    continue
                if any(stripped.startswith(p) for p in allowed_prefixes):
                    f.write(line)
    except Exception as e:
        print(f"WRITE_ERROR: Failed to filter mbid.toml at \"{mbid_path}\": {e}", file=sys.stderr)

    print(f"SUCCESS: Migrated \"{path.parent.name}\"")

def main():
    if len(sys.argv) > 1:
        for arg in sys.argv[1:]:
            process_metadata_path(arg)
    else:
        for line in sys.stdin:
            process_metadata_path(line)

if __name__ == "__main__":
    main()



import sys
from pathlib import Path
from mutagen.id3 import ID3
from mutagen.id3 import ID3NoHeaderError

def clean_flac_id3(directory):
    count = 0
    print(f"Scanning {directory} for FLAC files with ID3 tags...")
    for path in Path(directory).rglob("*.flac"):
        try:
            # Try to load an ID3 header. If it exists, delete it.
            id3_tags = ID3(path)
            id3_tags.delete(path)
            print(f"Removed ID3v2 tag from: {path.name}")
            count += 1
        except ID3NoHeaderError:
            # This is exactly what we want (no ID3 tag present)
            pass
        except Exception as e:
            print(f"Error processing {path.name}: {e}")

    print(f"\nDone! Cleaned {count} files.")

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python strip_flac_id3.py ")
        sys.exit(1)
    clean_flac_id3(sys.argv[1])



import tomllib
import os
from pathlib import Path

def resolve_config_path():
    env_path = os.environ.get("VELLUM_CONFIG_PATH")
    if env_path:
        p = Path(env_path).expanduser()
        if p.exists():
            return p

    home_config = Path("~/.config/vellum/config.toml").expanduser()
    if home_config.exists():
        return home_config

    curr = Path.cwd()
    for _ in range(5):
        for target in [curr / "config" / "config.toml", curr / "config.toml"]:
            if target.exists():
                return target
        if curr.parent == curr:
            break
        curr = curr.parent

    return None

def deep_merge(base, overlay):
    for k, v in overlay.items():
        if k == "import":
            continue
        if isinstance(v, dict) and k in base and isinstance(base[k], dict):
            deep_merge(base[k], v)
        else:
            base[k] = v
    return base

def load_config():
    cfg_path = resolve_config_path()
    if not cfg_path:
        raise FileNotFoundError("Could not locate vellum config.toml")

    visited = set()

    def load_recursive(path):
        canon = path.resolve()
        if canon in visited:
            return {}
        visited.add(canon)

        if not path.exists():
            return {}

        with open(path, "rb") as f:
            data = tomllib.load(f)

        merged = {}
        if "import" in data:
            imports = data["import"]
            if isinstance(imports, str):
                imports = [imports]

            base_dir = path.parent
            for rel in imports:
                imported_data = load_recursive(base_dir / rel)
                deep_merge(merged, imported_data)

        deep_merge(merged, data)
        return merged

    return load_recursive(cfg_path)



use crate::error::VellumError;
use serde_json::Value;
use sha2::{Digest, Sha256};
use std::collections::HashSet;
use std::path::Path;
use std::time::SystemTime;

pub struct ManifestData {
    pub json: Value,
    pub meta_hash: String,
    pub meta_mtime: u64,
    pub manifests_mtime_sum: u64,
}

pub fn load_and_merge(
    album_root: &Path,
    manifest_names: Option<&Vec>,
) -> Result {
    let metadata_path = album_root.join("metadata.toml");
    let meta = std::fs::metadata(&metadata_path)
        .map_err(|_| VellumError::MissingPrimaryManifest { path: album_root.to_path_buf() })?;

    let meta_mtime = meta
        .modified()
        .unwrap_or(SystemTime::UNIX_EPOCH)
        .duration_since(SystemTime::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();

    let manifests_mtime_sum = calculate_manifests_mtime_sum(album_root, manifest_names, meta_mtime);

    let content = std::fs::read_to_string(&metadata_path)?;
    let meta_hash = format!("{:x}", Sha256::digest(content.as_bytes()));

    let parsed_toml = toml::from_str::(&content)
        .map_err(|source| VellumError::ManifestParseError { path: metadata_path.clone(), source })?;
    let mut metadata_json = serde_json::to_value(parsed_toml)?;

    if let Some(manifests) = manifest_names {
        for m_val in manifests {
            if let Some(m_name) = m_val.as_str() {
                merge_auxiliary_manifest(album_root, m_name, &mut metadata_json)?;
            }
        }
    }

    Ok(ManifestData {
        json: metadata_json,
        meta_hash,
        meta_mtime,
        manifests_mtime_sum,
    })
}

fn calculate_manifests_mtime_sum(
    album_root: &Path,
    manifest_names: Option<&Vec>,
    base_mtime: u64,
) -> u64 {
    let mut sum = base_mtime;
    if let Some(manifests) = manifest_names {
        for m_val in manifests {
            if let Some(m_name) = m_val.as_str() {
                let m_path = album_root.join(m_name);
                if m_path.exists() {
                    sum += std::fs::metadata(&m_path)
                        .and_then(|m| m.modified())
                        .map(|t| t.duration_since(SystemTime::UNIX_EPOCH).unwrap_or_default().as_secs())
                        .unwrap_or(0);
                }
            }
        }
    }
    sum
}

fn merge_auxiliary_manifest(
    album_root: &Path,
    m_name: &str,
    primary_json: &mut Value,
) -> Result<(), VellumError> {
    let m_path = album_root.join(m_name);
    if !m_path.exists() {
        return Ok(());
    }
    let m_content = std::fs::read_to_string(&m_path)?;
    let parsed_aux = toml::from_str::(&m_content)
        .map_err(|source| VellumError::ManifestParseError { path: m_path.clone(), source })?;
    let mut m_json = serde_json::to_value(parsed_aux)?;

    if let Some(aux_album) = m_json.get_mut("album").and_then(Value::as_object_mut)
        && let Some(primary_album) = primary_json.get_mut("album").and_then(Value::as_object_mut) {
            for (k, v) in aux_album {
                if !primary_album.contains_key(k) {
                    primary_album.insert(k.clone(), v.clone());
                }
            }
        }

    if let Some(aux_tracks) = m_json.get_mut("tracks").and_then(Value::as_array_mut)
        && !aux_tracks.is_empty() {
            merge_aux_tracks(album_root, m_name, aux_tracks, primary_json)?;
        }
    Ok(())
}

fn merge_aux_tracks(
    album_root: &Path,
    m_name: &str,
    aux_tracks: &mut [Value],
    primary_json: &mut Value,
) -> Result<(), VellumError> {
    let primary_tracks = primary_json.get_mut("tracks")
        .and_then(Value::as_array_mut)
        .ok_or_else(|| VellumError::MissingTracksBlock { path: album_root.to_path_buf() })?;

    if aux_tracks.len() != primary_tracks.len() {
        return Err(VellumError::TrackCountMismatch {
            manifest: m_name.to_string(),
            path: album_root.to_path_buf(),
            primary_count: primary_tracks.len(),
            aux_count: aux_tracks.len(),
        });
    }

    let mut seen_identities = HashSet::new();
    for (idx, aux_t) in aux_tracks.iter_mut().enumerate() {
        let a_obj = aux_t.as_object_mut().ok_or_else(|| VellumError::InvalidManifestEntry { 
            manifest: m_name.to_string(), 
            path: album_root.to_path_buf(), 
            index: idx + 1 
        })?;

        let track_no = extract_strict_u32(a_obj.get("tracknumber"), "tracknumber", None)
            .map_err(|_| VellumError::MissingTrackIdentity {
                manifest: m_name.to_string(),
                path: album_root.to_path_buf(),
                index: idx + 1,
            })?;

        let disc_no = extract_strict_u32(a_obj.get("discnumber"), "discnumber", Some(1))?;

        if !seen_identities.insert((disc_no, track_no)) {
            return Err(VellumError::DuplicateTrackIdentity {
                manifest: m_name.to_string(),
                path: album_root.to_path_buf(),
                disc: disc_no,
                track: track_no,
            });
        }

        let mut found = false;
        for prim_t in primary_tracks.iter_mut() {
            let p_track_no: u32 = extract_strict_u32(prim_t.get("tracknumber"), "tracknumber", None)?;
            let p_disc_no: u32 = extract_strict_u32(prim_t.get("discnumber"), "discnumber", Some(1))?;

            if track_no == p_track_no && disc_no == p_disc_no {
                if let Some(p_obj) = prim_t.as_object_mut() {
                    for (k, v) in a_obj {
                        if k != "tracknumber" && k != "discnumber"
                            && !p_obj.contains_key(k) {
                                p_obj.insert(k.clone(), v.clone());
                            }
                    }
                }
                found = true;
                break;
            }
        }
        if !found {
            return Err(VellumError::OrphanedAuxiliaryData {
                manifest: m_name.to_string(),
                path: album_root.to_path_buf(),
                disc: disc_no,
                track: track_no,
            });
        }
    }
    Ok(())
}

pub fn extract_strict_u32(val: Option<&Value>, name: &str, default: Option) -> Result {
    let Some(v) = val else {
        return default.map_or_else(
            || Err(VellumError::InvalidIdentityFormat {
                field: name.to_string(),
                message: "Missing expected integer".to_string(),
            }),
            Ok,
        );
    };
    match v {
        Value::Number(n) => n
            .as_u64()
            .and_then(|i| u32::try_from(i).ok())
            .ok_or_else(|| VellumError::InvalidIdentityFormat {
                field: name.to_string(),
                message: "Value exceeds 32-bit integer limits".to_string(),
            }),
        Value::String(s) => {
            let base = s.split('/').next().unwrap_or("").trim();
            base.parse::().map_err(|_| VellumError::InvalidIdentityFormat {
                field: name.to_string(),
                message: format!("Cannot interpret string '{s}' as integer"),
            })
        }
        Value::Null => {
            default.map_or_else(
                || Err(VellumError::InvalidIdentityFormat {
                    field: name.to_string(),
                    message: "Field cannot be null".to_string(),
                }),
                Ok,
            )
        }
        _ => Err(VellumError::InvalidIdentityFormat {
            field: name.to_string(),
            message: "Unsupported data type found".to_string(),
        }),
    }
}



pub mod manifest;
pub mod validation;



use crate::error::VellumError;
use crate::compiler::manifest::extract_strict_u32;
use serde_json::{Map, Value};
use std::collections::HashSet;
use std::path::Path;

pub fn validate_track_indices(entries: &[Value], root: &Path) -> Result<(), VellumError> {
    let mut seen_ids = HashSet::new();
    for (idx, entry) in entries.iter().enumerate() {
        let t = extract_strict_u32(entry.get("tracknumber"), "tracknumber", None)
            .map_err(|_| VellumError::MissingTrackIdentity {
                manifest: "metadata.toml".to_string(),
                path: root.to_path_buf(),
                index: idx + 1,
            })?;
        let d = extract_strict_u32(entry.get("discnumber"), "discnumber", Some(1))?;

        if !seen_ids.insert((d, t)) {
            return Err(VellumError::DuplicateTrackIdentity {
                manifest: "metadata.toml".to_string(),
                path: root.to_path_buf(),
                disc: d,
                track: t,
            });
        }
    }
    Ok(())
}

pub fn validate_album_level_keys(
    album_source: &Value,
    track_entries: &[Value],
    registry: &Map,
    album_root: &Path,
) -> Result<(), VellumError> {
    for (key, meta) in registry {
        if meta.get("level").and_then(Value::as_str) != Some("album") {
            continue;
        }

        let mut seen_values: Vec<(Value, String)> = Vec::new();

        let check_val = |v: &Value| -> bool {
            match v {
                Value::Null => false,
                Value::String(s) => !s.trim().is_empty(),
                Value::Array(a) => !a.is_empty(),
                _ => true,
            }
        };

        if let Some(v) = album_source.get(key).filter(|v| check_val(v)) {
            seen_values.push((v.clone(), "album section".to_string()));
        }

        for (idx, track) in track_entries.iter().enumerate() {
            if let Some(v) = track.get(key).filter(|v| check_val(v)) {
                if let Some((first_val, source_name)) = seen_values.first() {
                    if v != first_val {
                        return Err(VellumError::GlobalKeyConflict {
                            path: Box::new(album_root.to_path_buf()),
                            key: Box::new(key.clone()),
                            val1: Box::new(first_val.to_string()),
                            source1: Box::new(source_name.clone()),
                            val2: Box::new(v.to_string()),
                            index: idx + 1,
                        });
                    }
                } else {
                    seen_values.push((v.clone(), format!("track {}", idx + 1)));
                }
            }
        }
    }
    Ok(())
}

pub fn merge_local_registry(album_root: &Path, registry: &mut Map) {
    let local_config_path = album_root.join("config.toml");
    if local_config_path.exists()
        && let Ok(local_content) = std::fs::read_to_string(&local_config_path)
            && let Ok(local_toml) = toml::from_str::(&local_content)
                && let Ok(local_json) = serde_json::to_value(local_toml)
                    && let Some(local_keys) = local_json
                        .get("compiler")
                        .and_then(|c| c.get("keys"))
                        .and_then(Value::as_object)
                    {
                        for (k, v) in local_keys {
                            if let Some(existing) = registry.get_mut(k) {
                                if let (Some(existing_obj), Some(new_obj)) = (existing.as_object_mut(), v.as_object()) {
                                    for (nk, nv) in new_obj {
                                        existing_obj.insert(nk.clone(), nv.clone());
                                    }
                                } else {
                                    registry.insert(k.clone(), v.clone());
                                }
                            } else {
                                registry.insert(k.clone(), v.clone());
                            }
                        }
                    }
}



use image::DynamicImage;
use kmeans_colors::get_kmeans_hamerly;
use palette::{FromColor, Lab, Srgb};
use rand::{SeedableRng, rngs::StdRng};
use rand::distr::{Distribution, Uniform};

pub fn extract(img: &DynamicImage, args: &str) -> Vec {
    let k = args.split(',')
        .find(|s| s.trim().starts_with("k="))
        .and_then(|s| s.trim().strip_prefix("k="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(10)
        .clamp(1, 24);

    let noise = args.split(',')
        .find(|s| s.trim().starts_with("noise="))
        .and_then(|s| s.trim().strip_prefix("noise="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.0);

    let conv = args.split(',')
        .find(|s| s.trim().starts_with("conv="))
        .and_then(|s| s.trim().strip_prefix("conv="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.000);

    let mut pixels: Vec = img.to_rgb8().pixels().map(|p| {
        Lab::from_color(Srgb::new(
            f32::from(p[0]) / 255.0,
            f32::from(p[1]) / 255.0,
            f32::from(p[2]) / 255.0,
        ))
    }).collect();

    if noise > 0.0 {
        let mut rng = StdRng::seed_from_u64(42);
        if let Ok(dist) = Uniform::new_inclusive(-noise, noise) {
            for pixel in &mut pixels {
                let offset = dist.sample(&mut rng);
                pixel.l = (pixel.l + offset).clamp(0.0, 100.0);
            }
        }
    }

    let result = get_kmeans_hamerly(k, 20, conv, false, &pixels, 42);

    result.centroids.into_iter().map(Srgb::from_color).collect()
}



use image::DynamicImage;
use kmeans_colors::get_kmeans_hamerly;
use palette::{FromColor, Lab, Oklch, Srgb};

pub fn extract(img: &DynamicImage, args: &str) -> Vec {
    let k = args.split(',')
        .find(|s| s.trim().starts_with("k="))
        .and_then(|s| s.trim().strip_prefix("k="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(24)
        .clamp(1, 64);

    let n = args.split(',')
        .find(|s| s.trim().starts_with("n="))
        .and_then(|s| s.trim().strip_prefix("n="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(8)
        .clamp(2, 24);

    let conv = args.split(',')
        .find(|s| s.trim().starts_with("conv="))
        .and_then(|s| s.trim().strip_prefix("conv="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.001);

    let pixels: Vec = img.to_rgb8().pixels().map(|p| {
        Lab::from_color(Srgb::new(
            f32::from(p[0]) / 255.0,
            f32::from(p[1]) / 255.0,
            f32::from(p[2]) / 255.0,
        ))
    }).collect();

    let result = get_kmeans_hamerly(k, 20, conv, false, &pixels, 42);
    let pool: Vec = result.centroids.into_iter().map(Srgb::from_color).collect();

    if pool.len() <= n {
        return pool;
    }

    let mut lch_pool: Vec<(Srgb, Oklch)> = pool.into_iter()
        .map(|s| (s, Oklch::from_color(s)))
        .collect();

    lch_pool.sort_by(|a, b| a.1.l.partial_cmp(&b.1.l).unwrap_or(std::cmp::Ordering::Equal));
    let darkest = lch_pool.remove(0);
    let lightest = lch_pool.pop().unwrap();

    lch_pool.sort_by(|a, b| b.1.chroma.partial_cmp(&a.1.chroma).unwrap_or(std::cmp::Ordering::Equal));

    let mut selected = vec![lightest, darkest];
    let vibrants_needed = (n - 2).min(lch_pool.len());
    for item in lch_pool.iter().take(vibrants_needed) {
        selected.push(*item);
    }

    selected.into_iter().map(|(s, _)| s).collect()
}



use image::DynamicImage;
use kmeans_colors::get_kmeans_hamerly;
use palette::{FromColor, Lab, Oklab, Oklch, Srgb};

fn get_oklab_dist(c1: &Oklab, c2: &Oklab) -> f32 {
    (c1.b - c2.b).mul_add(c1.b - c2.b, (c1.a - c2.a).mul_add(c1.a - c2.a, (c1.l - c2.l).powi(2))).sqrt()
}

pub fn extract(img: &DynamicImage, args: &str) -> Vec {
    let k = args.split(',')
        .find(|s| s.trim().starts_with("k="))
        .and_then(|s| s.trim().strip_prefix("k="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(24)
        .clamp(1, 64);

    let n = args.split(',')
        .find(|s| s.trim().starts_with("n="))
        .and_then(|s| s.trim().strip_prefix("n="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(8)
        .clamp(2, 24);

    let d_min = args.split(',')
        .find(|s| s.trim().starts_with("d="))
        .and_then(|s| s.trim().strip_prefix("d="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.12)
        .clamp(0.0, 1.0);

    let conv = args.split(',')
        .find(|s| s.trim().starts_with("conv="))
        .and_then(|s| s.trim().strip_prefix("conv="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.001);

    let pixels: Vec = img.to_rgb8().pixels().map(|p| {
        Lab::from_color(Srgb::new(
            f32::from(p[0]) / 255.0,
            f32::from(p[1]) / 255.0,
            f32::from(p[2]) / 255.0,
        ))
    }).collect();

    let result = get_kmeans_hamerly(k, 20, conv, false, &pixels, 42);
    let pool: Vec = result.centroids.into_iter().map(Srgb::from_color).collect();

    if pool.len() <= n {
        return pool;
    }

    let mut data: Vec<(Srgb, Oklab, Oklch)> = pool.into_iter()
        .map(|s| (s, Oklab::from_color(s), Oklch::from_color(s)))
        .collect();

    data.sort_by(|a, b| a.2.l.partial_cmp(&b.2.l).unwrap_or(std::cmp::Ordering::Equal));
    let darkest = data.remove(0);
    let lightest = data.pop().unwrap();

    data.sort_by(|a, b| b.2.chroma.partial_cmp(&a.2.chroma).unwrap_or(std::cmp::Ordering::Equal));

    let mut selected = vec![lightest, darkest];

    for candidate in &data {
        if selected.len() >= n { break; }

        let mut too_close = false;
        for (_, existing_ok, _) in &selected {
            if get_oklab_dist(&candidate.1, existing_ok) < d_min {
                too_close = true;
                break;
            }
        }

        if !too_close {
            selected.push(*candidate);
        }
    }

    if selected.len() < n {
        for candidate in data {
            if selected.len() >= n { break; }
            if !selected.iter().any(|s| s.0 == candidate.0) {
                selected.push(candidate);
            }
        }
    }

    selected.into_iter().map(|(s, _, _)| s).collect()
}



use image::DynamicImage;
use kmeans_colors::get_kmeans_hamerly;
use palette::{FromColor, Lab, Oklch, Srgb};

fn get_hue_dist(h1: f32, h2: f32) -> f32 {
    let diff = (h1 - h2).abs() % 360.0;
    if diff > 180.0 { 360.0 - diff } else { diff }
}

pub fn extract(img: &DynamicImage, args: &str) -> Vec {
    let k = args.split(',')
        .find(|s| s.trim().starts_with("k="))
        .and_then(|s| s.trim().strip_prefix("k="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(24)
        .clamp(1, 64);

    let n = args.split(',')
        .find(|s| s.trim().starts_with("n="))
        .and_then(|s| s.trim().strip_prefix("n="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(8)
        .clamp(2, 24);

    let h_min = args.split(',')
        .find(|s| s.trim().starts_with("h="))
        .and_then(|s| s.trim().strip_prefix("h="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(30.0)
        .clamp(0.0, 180.0);

    let conv = args.split(',')
        .find(|s| s.trim().starts_with("conv="))
        .and_then(|s| s.trim().strip_prefix("conv="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.001);

    let pixels: Vec = img.to_rgb8().pixels().map(|p| {
        Lab::from_color(Srgb::new(
            f32::from(p[0]) / 255.0,
            f32::from(p[1]) / 255.0,
            f32::from(p[2]) / 255.0,
        ))
    }).collect();

    let result = get_kmeans_hamerly(k, 20, conv, false, &pixels, 42);
    let pool: Vec = result.centroids.into_iter().map(Srgb::from_color).collect();

    if pool.len() <= n {
        return pool;
    }

    let mut lch_pool: Vec<(Srgb, Oklch)> = pool.into_iter()
        .map(|s| (s, Oklch::from_color(s)))
        .collect();

    lch_pool.sort_by(|a, b| a.1.l.partial_cmp(&b.1.l).unwrap_or(std::cmp::Ordering::Equal));
    let darkest = lch_pool.remove(0);
    let lightest = lch_pool.pop().unwrap();

    lch_pool.sort_by(|a, b| b.1.chroma.partial_cmp(&a.1.chroma).unwrap_or(std::cmp::Ordering::Equal));

    let mut selected = vec![lightest, darkest];

    for candidate in &lch_pool {
        if selected.len() >= n { break; }

        let mut too_close = false;
        for existing in &selected {
            if get_hue_dist(candidate.1.hue.into_raw_degrees(), existing.1.hue.into_raw_degrees()) < h_min {
                too_close = true;
                break;
            }
        }

        if !too_close {
            selected.push(*candidate);
        }
    }

    if selected.len() < n {
        for candidate in lch_pool {
            if selected.len() >= n { break; }
            if !selected.iter().any(|s| s.0 == candidate.0) {
                selected.push(candidate);
            }
        }
    }

    selected.into_iter().map(|(s, _)| s).collect()
}



use image::DynamicImage;
use kmeans_colors::get_kmeans_hamerly;
use palette::{FromColor, Lab, Oklab, Srgb};

fn get_oklab_dist(c1: &Oklab, c2: &Oklab) -> f32 {
    (c1.b - c2.b).mul_add(c1.b - c2.b, (c1.a - c2.a).mul_add(c1.a - c2.a, (c1.l - c2.l).powi(2))).sqrt()
}

pub fn extract(img: &DynamicImage, args: &str) -> Vec {
    let k = args.split(',')
        .find(|s| s.trim().starts_with("k="))
        .and_then(|s| s.trim().strip_prefix("k="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(24)
        .clamp(1, 64);

    let n = args.split(',')
        .find(|s| s.trim().starts_with("n="))
        .and_then(|s| s.trim().strip_prefix("n="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(6)
        .clamp(2, 24);

    let d_min = args.split(',')
        .find(|s| s.trim().starts_with("d="))
        .and_then(|s| s.trim().strip_prefix("d="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.1)
        .clamp(0.0, 1.0);

    let conv = args.split(',')
        .find(|s| s.trim().starts_with("conv="))
        .and_then(|s| s.trim().strip_prefix("conv="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.001);

    let pixels: Vec = img.to_rgb8().pixels().map(|p| {
        Lab::from_color(Srgb::new(
            f32::from(p[0]) / 255.0,
            f32::from(p[1]) / 255.0,
            f32::from(p[2]) / 255.0,
        ))
    }).collect();

    let result = get_kmeans_hamerly(k, 20, conv, false, &pixels, 42);
    let pool: Vec = result.centroids.into_iter().map(Srgb::from_color).collect();

    if pool.len() <= n {
        return pool;
    }

    let mut data: Vec<(Srgb, f32, f32, Oklab)> = pool.into_iter()
        .map(|s| {
            let ok = Oklab::from_color(s);
            let rgb_vividness = s.red.max(s.green).max(s.blue) - s.red.min(s.green).min(s.blue);
            (s, ok.l, rgb_vividness, ok)
        })
        .collect();

    data.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
    let darkest = data.remove(0);
    let lightest = data.pop().unwrap();

    data.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap_or(std::cmp::Ordering::Equal));

    let mut selected = vec![lightest, darkest];

    for candidate in &data {
        if selected.len() >= n { break; }

        let mut too_close = false;
        for existing in &selected {
            if get_oklab_dist(&candidate.3, &existing.3) < d_min {
                too_close = true;
                break;
            }
        }

        if !too_close {
            selected.push(*candidate);
        }
    }

    if selected.len() < n {
        for candidate in data {
            if selected.len() >= n { break; }
            if !selected.iter().any(|s| s.0 == candidate.0) {
                selected.push(candidate);
            }
        }
    }

    selected.into_iter().map(|(s, _, _, _)| s).collect()
}



use image::DynamicImage;
use palette::{FromColor, Oklab, Srgb};

pub fn extract(img: &DynamicImage, args: &str) -> Vec {
    let bw = args.split(',')
        .find(|s| s.trim().starts_with("bw="))
        .and_then(|s| s.trim().strip_prefix("bw="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.12);

    let eps = args.split(',')
        .find(|s| s.trim().starts_with("eps="))
        .and_then(|s| s.trim().strip_prefix("eps="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.0001);

    let max_iter = args.split(',')
        .find(|s| s.trim().starts_with("iter="))
        .and_then(|s| s.trim().strip_prefix("iter="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(20);

    let merge_threshold = args.split(',')
        .find(|s| s.trim().starts_with("mt="))
        .and_then(|s| s.trim().strip_prefix("mt="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.10);

    let chroma_gravity = args.split(',')
        .find(|s| s.trim().starts_with("cg="))
        .and_then(|s| s.trim().strip_prefix("cg="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0.0);

    let k = args.split(',')
        .find(|s| s.trim().starts_with("k="))
        .and_then(|s| s.trim().strip_prefix("k="))
        .and_then(|val| val.parse::().ok())
        .unwrap_or(0);

    let img_small = img.resize_exact(64, 64, image::imageops::FilterType::Nearest);
    let sample_pixels: Vec = img_small.to_rgb8().pixels().map(|p| {
        Oklab::from_color(Srgb::new(
            f32::from(p[0]) / 255.0,
            f32::from(p[1]) / 255.0,
            f32::from(p[2]) / 255.0,
        ))
    }).collect();

    let bw_sq = bw * bw;
    let mut converged = Vec::with_capacity(sample_pixels.len());

    for &seed in &sample_pixels {
        let mut current = seed;
        for _ in 0..max_iter {
            let mut sum_l = 0.0;
            let mut sum_a = 0.0;
            let mut sum_b = 0.0;
            let mut total_weight = 0.0;

            for &p in &sample_pixels {
                let dist_sq = (current.b - p.b).mul_add(current.b - p.b, (current.a - p.a).mul_add(current.a - p.a, (current.l - p.l).powi(2)));
                if dist_sq < bw_sq {
                    let chroma = p.a.hypot(p.b);
                    let weight = 1.0 + (chroma_gravity * chroma);

                    sum_l += p.l * weight;
                    sum_a += p.a * weight;
                    sum_b += p.b * weight;
                    total_weight += weight;
                }
            }

            if total_weight > 0.0 {
                let next = Oklab::new(sum_l / total_weight, sum_a / total_weight, sum_b / total_weight);
                let shift_sq = (next.b - current.b).mul_add(next.b - current.b, (next.a - current.a).mul_add(next.a - current.a, (next.l - current.l).powi(2)));
                current = next;
                if shift_sq < eps {
                    break;
                }
            } else {
                break;
            }
        }
        converged.push(current);
    }

    let merge_threshold_sq = merge_threshold * merge_threshold;
    let mut centers: Vec = Vec::new();

    for pos in converged {
        let mut found = false;
        for center in &centers {
            let dist_sq = (pos.b - center.b).mul_add(pos.b - center.b, (pos.a - center.a).mul_add(pos.a - center.a, (pos.l - center.l).powi(2)));
            if dist_sq < merge_threshold_sq {
                found = true;
                break;
            }
        }
        if !found {
            centers.push(pos);
        }
    }

    centers.sort_by(|a, b| {
        let chroma_a = a.a.hypot(a.b);
        let chroma_b = b.a.hypot(b.b);
        chroma_b.partial_cmp(&chroma_a).unwrap_or(std::cmp::Ordering::Equal)
    });

    if k > 0 && centers.len() > k {
        centers.truncate(k);
    }

    centers.into_iter().map(Srgb::from_color).collect()
}



