impl AppConfig {
    pub fn load() -> Result<(Self, Value, PathBuf)> {
        let config_path = Self::resolve_config_path()
            .context("Could not locate config.toml in home directory or project hierarchy")?;

        let mut visited = std::collections::HashSet::new();
        let raw_value = Self::load_recursive(&config_path, &mut visited)?;

        let config: Self = Value::try_into(raw_value.clone())?;
        Ok((config, raw_value, config_path))
    }

    fn resolve_config_path() -> Option {
        if let Some(home_config) = dirs::home_dir().map(|h| h.join(".config/vellum/config.toml"))
            && home_config.exists() {
                return Some(home_config);
            }

        if let Ok(env_path) = std::env::var("VELLUM_CONFIG_PATH") {
            let p = PathBuf::from(env_path);
            if p.exists() {
                return Some(p);
            }
        }

        let mut curr = std::env::current_dir().ok()?;
        loop {
            let local_nested = curr.join("config/config.toml");
            if local_nested.exists() {
                return Some(local_nested);
            }

            let local_root = curr.join("config.toml");
            if local_root.exists() {
                return Some(local_root);
            }

            if let Some(parent) = curr.parent() {
                curr = parent.to_path_buf();
            } else {
                break;
            }
        }

        None
    }

    fn load_recursive(
        path: &Path,
        visited: &mut std::collections::HashSet,
    ) -> Result {
        let canon_path = path.canonicalize().unwrap_or_else(|_| path.to_path_buf());
        if !visited.insert(canon_path) {
            return Err(anyhow::anyhow!(
                "Circular import detected: {}",
                path.display()
            ));
        }

        let content = fs::read_to_string(path)
            .with_context(|| format!("Failed to read config file: {}", path.display()))?;

        let mut current_value: Value = toml::from_str(&content)?;

        if let Some(imports) = current_value.get("import") {
            let import_paths = match imports {
                Value::String(s) => vec![s.clone()],
                Value::Array(arr) => arr
                    .iter()
                    .filter_map(|v| v.as_str().map(ToString::to_string))
                    .collect(),
                _ => vec![],
            };

            let mut merged_base = Value::Table(toml::map::Map::new());
            let base_dir = path.parent().unwrap_or_else(|| Path::new("."));

            for rel_path in import_paths {
                let abs_path = base_dir.join(rel_path);
                let imported_value = Self::load_recursive(&abs_path, visited)?;
                merged_base = Self::deep_merge(merged_base, imported_value);
            }

            current_value = Self::deep_merge(merged_base, current_value);
        }

        Ok(current_value)
    }

    fn deep_merge(base: Value, overlay: Value) -> Value {
        match (base, overlay) {
            (Value::Table(mut base_map), Value::Table(overlay_map)) => {
                for (k, v) in overlay_map {
                    if k == "import" {
                        continue;
                    }
                    let base_v = base_map.remove(&k);
                    let merged_v = match base_v {
                        Some(bv) => Self::deep_merge(bv, v),
                        None => v,
                    };
                    base_map.insert(k, merged_v);
                }
                Value::Table(base_map)
            }
            (_, overlay) => overlay,
        }
    }
}



use std::path::PathBuf;
use thiserror::Error;

#[derive(Error, Debug)]
pub enum VellumError {
    #[error("Missing primary manifest: metadata.toml not found in {path}")]
    MissingPrimaryManifest { path: PathBuf },

    #[error("IO Error: {0}")]
    ManifestIoError(#[from] std::io::Error),

    #[error("Parse Error: Failed to parse TOML in {path}: {source}")]
    ManifestParseError { path: PathBuf, source: toml::de::Error },

    #[error("Serialization Error: {0}")]
    JsonError(#[from] serde_json::Error),

    #[error("Schema Error: [[tracks]] array not found in metadata.toml for {path}")]
    MissingTracksBlock { path: PathBuf },

    #[error("Manifest Structure Violation: Auxiliary manifest '{manifest}' in {path} defines {aux_count} tracks, but metadata.toml defines {primary_count} tracks. Every manifest must describe the exact same track count.")]
    TrackCountMismatch { manifest: String, path: PathBuf, primary_count: usize, aux_count: usize },

    #[error("Manifest '{manifest}' at {path} has an invalid entry at index {index}: Track entries must be TOML tables.")]
    InvalidManifestEntry { manifest: String, path: PathBuf, index: usize },

    #[error("Inventory Mismatch in {path}: Found {files_count} audio files on disk but metadata.toml defines {tracks_count} tracks. Vellum requires an explicit 1:1 mapping between disk files and metadata entries.")]
    PhysicalInventoryMismatch { path: PathBuf, files_count: usize, tracks_count: usize },

    #[error("Identity Error: Manifest '{manifest}' in {path} is missing or has an invalid TRACKNUMBER field at track index {index}")]
    MissingTrackIdentity { manifest: String, path: PathBuf, index: usize },

    #[error("{message} for field '{field}'")]
    InvalidIdentityFormat { field: String, message: String },

    #[error("Identity Collision: Manifest '{manifest}' in {path} defines Disc {disc}, Track {track} more than once.")]
    DuplicateTrackIdentity { manifest: String, path: PathBuf, disc: u32, track: u32 },

    #[error("Orphaned Track Data: Manifest '{manifest}' in {path} contains data for Disc {disc}, Track {track}, but no such track exists in the primary metadata.toml.")]
    OrphanedAuxiliaryData { manifest: String, path: PathBuf, disc: u32, track: u32 },

    #[error("Integrity Violation in {path}: Key '{key}' is restricted to 'album' level, but conflicting values were detected ('{val1}' in {source1} versus '{val2}' in track {index}). All track-level overrides must match the album-level value.")]
    GlobalKeyConflict { 
        path: Box, 
        key: Box, 
        val1: Box, 
        source1: Box, 
        val2: Box, 
        index: usize 
    },

    #[error("Configuration Error: [compiler.keys] block is missing from config.toml")]
    MissingCompilerRegistry,

    #[error("Harvest Error: Failed to harvest metadata from audio file {path}: {source}")]
    HarvestError { path: PathBuf, source: anyhow::Error },
}



use anyhow::{Context, Result};
use lofty::config::ParseOptions;
use lofty::file::AudioFile;
use lofty::prelude::*;
use lofty::probe::Probe;
use lofty::tag::TagType;
use serde::Serialize;
use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};

#[derive(Serialize)]
pub struct TrackJson {
    pub path: PathBuf,
    pub tags: HashMap,
    pub physics: PhysicsData,
}

#[derive(Serialize)]
pub struct PhysicsData {
    pub file_size: u64,
    pub mtime: u64,
    pub duration_ms: u64,
    pub sample_rate: u32,
    pub bit_depth: Option,
    pub channels: u8,
    pub audio_bitrate: u32,
    pub overall_bitrate: u32,
    pub format: String,
}

#[must_use] 
pub fn sanitize_key(key: &str) -> String {
    key.chars()
        .map(|c| {
            if c.is_ascii_alphanumeric() {
                c.to_ascii_lowercase()
            } else {
                '_'
            }
        })
        .collect()
}

pub fn harvest_file(path: &Path) -> Result {
    let metadata = fs::metadata(path)?;
    let mut f = std::fs::File::open(path).context("Open failed")?;
    let probe = Probe::new(&mut f).guess_file_type().context("Guess failed")?;
    let file_type = probe.file_type();

    let tagged_file = Probe::open(path)?
        .options(ParseOptions::new().read_cover_art(false))
        .read()
        .context("Read failed")?;

    if file_type == Some(lofty::file::FileType::Flac)
        && tagged_file.tag(TagType::Id3v2).is_some() {
            log::warn!(
                "ID3v2 tag encountered in FLAC (incompatible with standards): {}",
                path.display()
            );
        }

    let physics = extract_physics(&metadata, &tagged_file);

    let mut tags = HashMap::new();
    let concrete_parsed = extract_concrete_tags(path, file_type, &mut tags)?;

    if !concrete_parsed {
        extract_fallback_tags(&tagged_file, &mut tags);
    }

    Ok(TrackJson {
        path: path.to_path_buf(),
        tags,
        physics,
    })
}

fn extract_physics(metadata: &std::fs::Metadata, tagged_file: &lofty::file::TaggedFile) -> PhysicsData {
    let file_size = metadata.len();
    let mtime = metadata
        .modified()
        .unwrap_or(std::time::SystemTime::UNIX_EPOCH)
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();

    let properties = tagged_file.properties();

    PhysicsData {
        file_size,
        mtime,
        duration_ms: u64::try_from(properties.duration().as_millis()).unwrap_or(u64::MAX),
        sample_rate: properties.sample_rate().unwrap_or(0),
        bit_depth: properties.bit_depth(),
        channels: properties.channels().unwrap_or(0),
        audio_bitrate: properties.audio_bitrate().unwrap_or(0),
        overall_bitrate: properties.overall_bitrate().unwrap_or(0),
        format: format!("{:?}", tagged_file.file_type()),
    }
}

fn extract_concrete_tags(
    path: &Path,
    file_type: Option,
    tags: &mut HashMap,
) -> Result {
    let mut file_content = std::fs::File::open(path)?;
    let mut concrete_parsed = false;
    match file_type {
        Some(lofty::file::FileType::Flac) => {
            if let Ok(flac) = lofty::flac::FlacFile::read_from(
                &mut file_content,
                ParseOptions::new().read_cover_art(false),
            )
                && let Some(comments) = flac.vorbis_comments() {
                    parse_vorbis_comments(comments.items(), tags);
                    concrete_parsed = true;
                }
        }
        Some(lofty::file::FileType::Vorbis) => {
            if let Ok(ogg) = lofty::ogg::VorbisFile::read_from(
                &mut file_content,
                ParseOptions::new().read_cover_art(false),
            ) {
                parse_vorbis_comments(ogg.vorbis_comments().items(), tags);
                concrete_parsed = true;
            }
        }
        Some(lofty::file::FileType::Opus) => {
            if let Ok(opus) = lofty::ogg::OpusFile::read_from(
                &mut file_content,
                ParseOptions::new().read_cover_art(false),
            ) {
                parse_vorbis_comments(opus.vorbis_comments().items(), tags);
                concrete_parsed = true;
            }
        }
        _ => {}
    }
    Ok(concrete_parsed)
}

fn parse_vorbis_comments<'a, I>(items: I, tags: &mut HashMap)
where
    I: Iterator
,
{
    for (k, v) in items {
        let key = sanitize_key(k);
        let value = v.trim();
        if !key.is_empty() && !value.is_empty() {
            tags.entry(key)
                .and_modify(|e: &mut String| {
                    if !e.contains(value) {
                        e.push_str("; ");
                        e.push_str(value);
                    }
                })
                .or_insert_with(|| value.to_string());
        }
    }
}

fn extract_fallback_tags(tagged_file: &lofty::file::TaggedFile, tags: &mut HashMap) {
    if let Some(tag) = tagged_file
        .primary_tag()
        .or_else(|| tagged_file.first_tag())
    {
        let tag_type = tag.tag_type();
        for item in tag.items() {
            let key_raw = item
                .key()
                .map_key(tag_type).map_or_else(|| format!("{:?}", item.key()), ToString::to_string);
            let key = sanitize_key(&key_raw);

            let Some(value) = item.value().text() else {
                continue;
            };
            let value = value.trim();

            if key.is_empty() || value.is_empty() {
                continue;
            }

            tags.entry(key)
                .and_modify(|existing: &mut String| {
                    if !existing.contains(value) {
                        existing.push_str("; ");
                        existing.push_str(value);
                    }
                })
                .or_insert_with(|| value.to_string());
        }
    }
}



