fn deserialize_vec_or_string<'de, D>(deserializer: D) -> Result<Vec, D::Error>
where
    D: Deserializer<'de>,
{
    #[derive(Deserialize)]
    #[serde(untagged)]
    enum VecOrString {
        Vec(Vec),
        String(String),
    }

    match VecOrString::deserialize(deserializer)? {
        VecOrString::Vec(v) => Ok(v),
        VecOrString::String(s) => Ok(s
            .split(';')
            .map(|part| part.trim().to_string())
            .filter(|part| !part.is_empty())
            .collect()),
    }
}

