use crate::error::VellumError;
use std::path::{Path, PathBuf};
use walkdir::WalkDir;

pub fn find_target_albums(path: &Path, max_depth: usize) -> Result<Vec, VellumError> {
    let mut results = std::collections::HashSet::new();
    if path.join("metadata.toml").exists() || path.join("album.nix").exists() {
        results.insert(path.to_path_buf());
    } else {
        for entry in WalkDir::new(path)
            .max_depth(max_depth)
        {
            match entry {
                Ok(e) => {
                    if (e.file_name() == "metadata.toml" || e.file_name() == "album.nix")
                        && let Some(parent) = e.path().parent() {
                            results.insert(parent.to_path_buf());
                        }
                }
                Err(e) => {
                    if let Some(io_err) = e.into_io_error() {
                        return Err(VellumError::ManifestIoError(io_err));
                    }
                }
            }
        }
    }
    let mut vec_results: Vec = results.into_iter().collect();
    vec_results.sort();
    Ok(vec_results)
}

pub fn scan_audio_files(root: &Path, extensions: &[&str]) -> Vec {
    let mut files: Vec = WalkDir::new(root)
        .max_depth(3)
        .into_iter()
        .filter_map(Result::ok)
        .filter(|e| e.file_type().is_file())
        .map(|e| e.path().to_path_buf())
        .filter(|p| {
            p.extension()
                .and_then(|ext| ext.to_str())
                .is_some_and(|ext| {
                    extensions.contains(&format!(".{}", ext.to_lowercase()).as_str())
                })
        })
        .collect();
    files.sort_by(|a, b| alphanumeric_sort::compare_path(a, b));
    files
}



use crate::error::VellumError;
use serde::{Deserialize, Serialize};
use std::fs;
use std::path::Path;
use std::time::SystemTime;

#[derive(Serialize, Deserialize, Debug, PartialEq, Eq)]
pub enum TrustState {
    Valid,
    Missing,
    BrokenIntent,
    BrokenPhysics,
    BrokenAssets,
}

pub fn verify_trust(album_root: &Path, manifests: Option<&Vec>) -> Result {
    let lock_path = album_root.join("metadata.lock.json");
    if !lock_path.exists() {
        return Ok(TrustState::Missing);
    }

    let lock_content = fs::read_to_string(&lock_path)
        .map_err(VellumError::ManifestIoError)?;

    let lock_json: serde_json::Value = serde_json::from_str(&lock_content)
        .map_err(VellumError::JsonError)?;

    let Some(album_data) = lock_json.get("album") else {
        return Ok(TrustState::Missing);
    };

    if check_manifest_mtimes(album_root, album_data, manifests) == TrustState::BrokenIntent {
        return Ok(TrustState::BrokenIntent);
    }

    if check_cover_integrity(album_root, album_data) == TrustState::BrokenAssets {
        return Ok(TrustState::BrokenAssets);
    }

    if check_tracks_integrity(album_root, &lock_json) == TrustState::BrokenPhysics {
        return Ok(TrustState::BrokenPhysics);
    }

    Ok(TrustState::Valid)
}

fn check_manifest_mtimes(album_root: &Path, album_data: &serde_json::Value, manifests: Option<&Vec>) -> TrustState {
    let lock_meta_mtime = album_data
        .get("metadata_toml_mtime")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(0);

    let lock_manifests_sum = album_data
        .get("manifests_mtime_sum")
        .and_then(serde_json::Value::as_u64)
        .unwrap_or(0);

    let metadata_path = album_root.join("metadata.toml");
    let current_meta_mtime = fs::metadata(&metadata_path)
        .and_then(|m| m.modified())
        .map(|t| {
            t.duration_since(SystemTime::UNIX_EPOCH)
                .unwrap_or_default()
                .as_secs()
        })
        .unwrap_or(0);

    if current_meta_mtime != lock_meta_mtime && lock_meta_mtime != 0 {
        return TrustState::BrokenIntent;
    }

    let mut current_manifests_sum: u64 = current_meta_mtime;
    if let Some(names) = manifests {
        for name in names {
            let p = album_root.join(name);
            if p.exists() {
                current_manifests_sum += fs::metadata(&p)
                    .and_then(|m| m.modified())
                    .map(|t| {
                        t.duration_since(SystemTime::UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs()
                    })
                    .unwrap_or(0);
            }
        }
    }

    if current_manifests_sum != lock_manifests_sum && lock_manifests_sum != 0 {
        return TrustState::BrokenIntent;
    }

    TrustState::Valid
}

fn check_cover_integrity(album_root: &Path, album_data: &serde_json::Value) -> TrustState {
    let lock_cover_path = album_data
        .get("cover_path")
        .and_then(serde_json::Value::as_str)
        .unwrap_or("");
    if !lock_cover_path.is_empty() && lock_cover_path != "default_cover.png" {
        let abs_cover = album_root.join(lock_cover_path);
        if !abs_cover.exists() {
            return TrustState::BrokenAssets;
        }

        let lock_cover_size = album_data
            .get("cover_byte_size")
            .and_then(serde_json::Value::as_u64)
            .unwrap_or(0);
        let current_cover_size = fs::metadata(&abs_cover).map(|m| m.len()).unwrap_or(0);

        if lock_cover_size != current_cover_size {
            return TrustState::BrokenAssets;
        }
    }
    TrustState::Valid
}

fn check_tracks_integrity(album_root: &Path, lock_json: &serde_json::Value) -> TrustState {
    if let Some(tracks) = lock_json
        .get("tracks")
        .and_then(serde_json::Value::as_array)
    {
        for track in tracks {
            let rel_path = track
                .get("track_path")
                .and_then(serde_json::Value::as_str)
                .unwrap_or("");
            if rel_path.is_empty() {
                return TrustState::BrokenPhysics;
            }

            let abs_path = album_root.join(rel_path);
            let Ok(meta) = fs::metadata(&abs_path) else {
                return TrustState::BrokenPhysics;
            };

            let lock_track_mtime = track
                .get("track_mtime")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0);
            let lock_track_size = track
                .get("track_size")
                .and_then(serde_json::Value::as_u64)
                .unwrap_or(0);

            let current_track_mtime = meta
                .modified()
                .map(|t| {
                    t.duration_since(SystemTime::UNIX_EPOCH)
                        .unwrap_or_default()
                        .as_secs()
                })
                .unwrap_or(0);
            let current_track_size = meta.len();

            if lock_track_mtime != current_track_mtime || lock_track_size != current_track_size {
                return TrustState::BrokenPhysics;
            }
        }
    }
    TrustState::Valid
}



use regex::Regex;
use std::sync::LazyLock;

pub static INTERPOLATION_RE: LazyLock = LazyLock::new(|| {
    Regex::new(r"\$\{([^}]+)\}").unwrap()
});

pub static PATTERN_LITERAL_RE: LazyLock = LazyLock::new(|| {
    Regex::new(r"%\{([^}]+)\}").unwrap()
});

pub static STANDARD_LITERAL_RE: LazyLock = LazyLock::new(|| {
    Regex::new(r"\{([^}]+)\}").unwrap()
});

fn sql_quote(s: &str) -> String {
    s.replace('\'', "''")
}

pub fn expand_shorthand(input: &str) -> String {
    let mut res = input.to_string();

    res = INTERPOLATION_RE.replace_all(&res, |caps: &regex::Captures| {
        let inner = &caps[1];
        let path = if inner.starts_with("$.") {
            inner.to_string()
        } else {
            format!("$.{inner}")
        };
        format!("json_extract(metadata, '{path}')")
    }).to_string();

    res = PATTERN_LITERAL_RE.replace_all(&res, |caps: &regex::Captures| {
        format!("'%{}%'", sql_quote(&caps[1]))
    }).to_string();

    res = STANDARD_LITERAL_RE.replace_all(&res, |caps: &regex::Captures| {
        format!("'{}'", sql_quote(&caps[1]))
    }).to_string();

    res
}



use std::path::PathBuf;

#[must_use]
pub fn expand_path(path_str: &str) -> PathBuf {
    if path_str.starts_with('~')
        && let Some(home) = dirs::home_dir() {
            if path_str == "~" {
                return home;
            }
            if let Some(stripped) = path_str.strip_prefix("~/") {
                return home.join(stripped);
            }
        }
    PathBuf::from(path_str)
}



