pub mod assets;
pub mod context;

use libvellum::error::VellumError;
use libvellum::compiler::manifest::{load_and_merge, extract_strict_u32};
use libvellum::compiler::validation::{validate_track_indices, validate_album_level_keys, merge_local_registry};
use crate::compile::builder::context::{AlbumContext, TrackContext};
use crate::compile::resolvers;
use crate::expand_path;
use crate::harvest;
use serde_json::{Value, json, Map};
use std::path::Path;

struct PreparedContext {
    audio_files: Vec,
    registry: Map,
    library_root: std::path::PathBuf,
}

pub fn build(
    album_root: &Path,
    project_root: &Path,
    config: &Value,
    manifest_cfg: &Value,
    _active_flags: &[String],
) -> Result {
    let manifest_names = config.get("compiler").and_then(|c| c.get("manifests")).and_then(Value::as_array);
    let manifest_data = load_and_merge(album_root, manifest_names)?;

    let (c_path, c_hash, c_mtime, c_size) = assets::resolve_cover_info(album_root);
    let loaded_image =
        assets::load_or_create_thumbnail(config, album_root, c_path.as_deref(), &c_hash);

    let cover_metrics = resolve_cover_metrics(config, &c_hash, loaded_image.as_ref(), &manifest_data);

    let PreparedContext { audio_files, registry, library_root } = prepare_build_context(config, manifest_cfg, album_root)?;

    let track_entries = manifest_data.json
        .get("tracks")
        .and_then(Value::as_array)
        .ok_or_else(|| VellumError::MissingTracksBlock { path: album_root.to_path_buf() })?;

    if audio_files.len() != track_entries.len() {
        return Err(VellumError::PhysicalInventoryMismatch {
            path: album_root.to_path_buf(),
            files_count: audio_files.len(),
            tracks_count: track_entries.len(),
        });
    }

    validate_track_indices(track_entries, album_root)?;

    let empty_obj = json!({});
    let album_source = manifest_data.json.get("album").unwrap_or(&empty_obj);

    validate_album_level_keys(album_source, track_entries, &registry, album_root)?;

    let (final_tracks, harvested_cache) = process_tracks(
        audio_files,
        track_entries,
        album_source,
        album_root,
        &library_root,
        &registry,
    )?;

    let album_ctx = AlbumContext {
        source: album_source,
        tracks: &final_tracks,
        album_root,
        library_root: &library_root,
        meta_hash: &manifest_data.meta_hash,
        meta_mtime: manifest_data.meta_mtime,
        manifests_mtime_sum: manifest_data.manifests_mtime_sum,
        cover_hash: &c_hash,
        cover_path: c_path.as_deref(),
        cover_mtime: c_mtime,
        cover_byte_size: c_size,
        cover_metrics: cover_metrics.as_ref(),
        config,
    };

    let album_obj = build_album(&album_ctx, &registry);

    let final_json = json!({
        "album": album_obj,
        "tracks": final_tracks,
        "ctx": {
            "config": config,
            "registry": registry,
            "metadata": manifest_data.json,
            "harvest": harvested_cache,
            "paths": {
                "album_root": album_root.to_string_lossy(),
                "project_root": project_root.to_string_lossy(),
                "library_root": library_root.to_string_lossy()
            }
        }
    });

    Ok(final_json)
}

fn prepare_build_context(
    config: &Value,
    manifest_cfg: &Value,
    album_root: &Path,
) -> Result {
    let exts: Vec<&str> = manifest_cfg
        .get("supported_extensions")
        .and_then(Value::as_array)
        .map_or_else(
            || vec![".flac"],
            |arr| arr.iter().filter_map(Value::as_str).collect(),
        );

    let audio_files = libvellum::scanner::scan_audio_files(album_root, &exts);

    let lib_root_raw = config
        .get("storage")
        .and_then(|s| s.get("library_root"))
        .and_then(Value::as_str)
        .unwrap_or(".");
    let library_root = expand_path(lib_root_raw)
        .canonicalize()
        .unwrap_or_else(|_| expand_path(lib_root_raw));

    let mut registry = config
        .get("compiler")
        .and_then(|c| c.get("keys"))
        .and_then(Value::as_object)
        .ok_or_else(|| VellumError::MissingCompilerRegistry)?
        .clone();

    merge_local_registry(album_root, &mut registry);

    Ok(PreparedContext { audio_files, registry, library_root })
}

fn resolve_cover_metrics(
    config: &Value,
    c_hash: &str,
    loaded_image: Option<&image::DynamicImage>,
    manifest_data: &libvellum::compiler::manifest::ManifestData,
) -> Option {
    if c_hash.is_empty() {
        return None;
    }

    let cache_str = config.get("storage").and_then(|s| s.get("cache")).and_then(Value::as_str).unwrap_or("~/.cache/vellum");
    let cache_root = crate::expand_path(cache_str);
    let metrics_dir = cache_root.join("cover_data");
    std::fs::create_dir_all(&metrics_dir).ok();

    let metrics_path = metrics_dir.join(format!("{c_hash}.json"));

    let palette_cfg = config.get("compiler").and_then(|c| c.get("cover_palette"));
    let cover_palette_raw = manifest_data.json.get("album").and_then(|a| a.get("cover_palette"));

    let palette_params = format!("{palette_cfg:?}|{cover_palette_raw:?}");

    let mut metrics = if metrics_path.exists() {
        std::fs::read_to_string(&metrics_path).map_or(None, |content| serde_json::from_str::(&content).ok())
    } else { 
        None 
    }.unwrap_or_else(|| assets::CoverMetrics {
        hash: c_hash.to_string(),
        entropy: None,
        chroma: None,
        palette: None,
        palette_params: None,
    });

    let mut needs_save = false;

    if let Some(img) = loaded_image {
        if metrics.chroma.is_none() {
            metrics.chroma = Some(libvellum::images::cover_chroma::calculate_chroma(img));
            needs_save = true;
        }
        if metrics.entropy.is_none() {
            metrics.entropy = Some(libvellum::images::cover_entropy::calculate_entropy(img));
            needs_save = true;
        }

        if (metrics.palette_params.as_deref() != Some(&palette_params) || metrics.palette.is_none())
            && let Some(palette_val) = resolvers::cover_palette::resolve_core(img, palette_cfg, cover_palette_raw) {
                metrics.palette = Some(palette_val);
                metrics.palette_params = Some(palette_params);
                needs_save = true;
            }
    }

    if needs_save
        && let Ok(content) = serde_json::to_string(&metrics) {
            let _ = std::fs::write(&metrics_path, content);
        }

    Some(metrics)
}

fn process_tracks(
    audio_files: Vec,
    track_entries: &[Value],
    album_source: &Value,
    album_root: &Path,
    library_root: &Path,
    registry: &Map,
) -> Result<(Vec, Vec), VellumError> {
    let mut harvested_spine = Vec::new();
    for path in audio_files {
        harvested_spine.push(harvest::harvest_file(&path).map_err(|source| VellumError::HarvestError { path: path.clone(), source })?);
    }

    let mut total_discs = 1;
    for t in track_entries {
        if let Ok(d) = extract_strict_u32(t.get("discnumber"), "discnumber", Some(1))
            && d > total_discs {
                total_discs = d;
            }
    }

    let mut final_tracks = Vec::new();
    let mut harvested_cache = Vec::new();

    for (idx, h_data) in harvested_spine.into_iter().enumerate() {
        let track_number: u32 = extract_strict_u32(track_entries[idx].get("tracknumber"), "tracknumber", None)
            .map_err(|_| VellumError::MissingTrackIdentity {
                manifest: "metadata.toml".to_string(),
                path: album_root.to_path_buf(),
                index: idx + 1,
            })?;
        let disc_number: u32 = extract_strict_u32(track_entries[idx].get("discnumber"), "discnumber", Some(1))?;

        let t_ctx = TrackContext {
            track_number,
            disc_number,
            harvest: &h_data,
            source: &track_entries[idx],
            album_source,
            album_root,
            library_root,
        };

        let t_obj = build_track(&t_ctx, total_discs, registry);
        final_tracks.push(t_obj);
        harvested_cache.push(serde_json::to_value(h_data)?);
    }

    Ok((final_tracks, harvested_cache))
}

fn construct_track_info(ctx: &TrackContext, total_discs: u32) -> Value {
    let mut info = serde_json::Map::new();

    let lyrics_path = ctx
        .source
        .get("lyrics_path")
        .and_then(Value::as_str)
        .map(ToString::to_string)
        .or_else(|| {
            resolvers::native::resolve_lyrics_path(
                ctx.album_root,
                ctx.track_number,
                ctx.disc_number,
                total_discs,
            )
        });

    info.insert(
        "track_path".to_string(),
        json!(resolvers::native::rel_path(
            &ctx.harvest.path,
            ctx.album_root
        )),
    );
    info.insert(
        "track_library_path".to_string(),
        json!(resolvers::native::rel_path(
            &ctx.harvest.path,
            ctx.library_root
        )),
    );
    info.insert(
        "track_duration".to_string(),
        json!(ctx.harvest.physics.duration_ms),
    );
    info.insert(
        "track_duration_time".to_string(),
        json!(resolvers::standard::format_ms(
            ctx.harvest.physics.duration_ms
        )),
    );
    info.insert("encoding".to_string(), json!(ctx.harvest.physics.format));
    info.insert(
        "sample_rate".to_string(),
        json!(ctx.harvest.physics.sample_rate),
    );
    info.insert(
        "bits_per_sample".to_string(),
        json!(ctx.harvest.physics.bit_depth.unwrap_or(0)),
    );
    info.insert("channels".to_string(), json!(ctx.harvest.physics.channels));
    info.insert("track_mtime".to_string(), json!(ctx.harvest.physics.mtime));
    info.insert(
        "track_size".to_string(),
        json!(ctx.harvest.physics.file_size),
    );
    info.insert(
        "lyrics_path".to_string(),
        json!(lyrics_path.unwrap_or_default()),
    );

    Value::Object(info)
}

fn build_track(
    ctx: &TrackContext,
    total_discs: u32,
    registry: &Map,
) -> Value {
    let mut obj = serde_json::Map::new();

    obj.insert("info".to_string(), construct_track_info(ctx, total_discs));

    obj.insert("title".to_string(), resolvers::resolve_top_level_track_key("title", ctx));
    obj.insert("artist".to_string(), resolvers::resolve_top_level_track_key("artist", ctx));
    obj.insert("tracknumber".to_string(), json!(ctx.track_number));
    obj.insert("discnumber".to_string(), json!(ctx.disc_number));

    let mut tags = serde_json::Map::new();
    for (key, meta) in registry {
        let level = meta.get("level").and_then(Value::as_str).unwrap_or("");
        if level != "tracks" && level != "track" {
            continue;
        }

        if["title", "artist", "tracknumber", "discnumber"].contains(&key.as_str()) {
            continue;
        }
        let val = resolvers::resolve_track_key(key, meta, ctx).unwrap_or(Value::Null);
        tags.insert(key.clone(), val);
    }
    obj.insert("tags".to_string(), Value::Object(tags));
    Value::Object(obj)
}

fn construct_album_info(ctx: &AlbumContext) -> Value {
    let mut info = serde_json::Map::new();
    let dur: u64 = ctx
        .tracks
        .iter()
        .filter_map(|t| {
            t.get("info")
                .and_then(|i| i.get("track_duration"))
                .and_then(Value::as_u64)
        })
        .sum();

    info.insert(
        "album_path".to_string(),
        json!(resolvers::native::rel_path(
            ctx.album_root,
            ctx.library_root
        )),
    );
    info.insert(
        "unix_added".to_string(),
        json!(resolvers::native::resolve_album_info_unix_added(ctx, "")),
    );
    info.insert(
        "date_added".to_string(),
        resolvers::native::resolve_album_info_date_added(ctx, "").unwrap_or_else(|| json!("")),
    );
    info.insert("album_duration".to_string(), json!(dur));
    info.insert(
        "album_duration_time".to_string(),
        json!(resolvers::standard::format_ms(dur)),
    );
    info.insert(
        "total_discs".to_string(),
        json!(resolvers::native::calculate_total_discs(ctx.tracks)),
    );
    info.insert("total_tracks".to_string(), json!(ctx.tracks.len()));
    info.insert("metadata_toml_hash".to_string(), json!(ctx.meta_hash));
    info.insert("metadata_toml_mtime".to_string(), json!(ctx.meta_mtime));
    info.insert("manifests_mtime_sum".to_string(), json!(ctx.manifests_mtime_sum));
    info.insert(
        "cover_path".to_string(),
        json!(ctx.cover_path.unwrap_or("default_cover.png")),
    );
    info.insert("cover_hash".to_string(), json!(ctx.cover_hash));
    info.insert("cover_mtime".to_string(), json!(ctx.cover_mtime));
    info.insert("cover_byte_size".to_string(), json!(ctx.cover_byte_size));

    Value::Object(info)
}

fn build_album(
    ctx: &AlbumContext,
    registry: &Map,
) -> Value {
    let mut obj = serde_json::Map::new();

    obj.insert("info".to_string(), construct_album_info(ctx));
    obj.insert("album".to_string(), resolvers::resolve_top_level_album_key("album", ctx));
    obj.insert("albumartist".to_string(), resolvers::resolve_top_level_album_key("albumartist", ctx));
    obj.insert("date".to_string(), resolvers::resolve_top_level_album_key("date", ctx));
    obj.insert("genre".to_string(), resolvers::resolve_top_level_album_key("genre", ctx));
    obj.insert("comment".to_string(), resolvers::resolve_top_level_album_key("comment", ctx));
    obj.insert("original_yyyy_mm".to_string(), resolvers::resolve_top_level_album_key("original_yyyy_mm", ctx));
    obj.insert("release_yyyy_mm".to_string(), resolvers::resolve_top_level_album_key("release_yyyy_mm", ctx));

    let mut tags = serde_json::Map::new();
    for (key, meta) in registry {
        if meta.get("level").and_then(Value::as_str) != Some("album") {
            continue;
        }

        if["album", "albumartist", "date", "genre", "comment", "original_yyyy_mm", "release_yyyy_mm"].contains(&key.as_str()) {
            continue;
        }
        let val = resolvers::resolve_album_key(key, meta, ctx).unwrap_or(Value::Null);
        tags.insert(key.clone(), val);
    }

    if let Some(palette_cfg) = ctx.config.get("compiler").and_then(|c| c.get("cover_palette"))
        && let Some(val) = resolvers::native::resolve_cover_palette(ctx, palette_cfg) {
            tags.insert("cover_palette".to_string(), val);
        }

    obj.insert("tags".to_string(), Value::Object(tags));
    Value::Object(obj)
}



pub mod stream;
pub mod verify;



use crate::compile::{ExportTarget, builder, engine::verify};
use libvellum::error::VellumError;
use anyhow::Result;
use rayon::prelude::*;
use serde_json::{Value, json};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::mpsc;

pub struct AlbumUpdateSignal {
    pub path: PathBuf,
    pub artist: String,
    pub album: String,
}

pub struct StreamContext {
    pub albums: Vec,
    pub config: Arc,
    pub project_root: Arc,
    pub manifest_cfg: Arc,
    pub active_flags: Arc<Vec>,
    pub target: ExportTarget,
    pub jobs: Option,
    pub notify_tx: Option<mpsc::Sender>,
}

pub async fn run(ctx: StreamContext) -> Result<()> {
    let (dtx, mut drx) = mpsc::channel::(512);

    let notify = ctx.notify_tx.clone().map(Arc::new);
    let build_handle = spawn_builders(&ctx, dtx);

    let d_notify = notify.clone();
    let target = ctx.target;
    let direct_handle = tokio::spawn(async move {
        while let Some(v) = drx.recv().await {
            let n = d_notify.as_ref().map(Arc::clone);
            tokio::task::spawn_blocking(move || {
                let _ = finalize(v, target, n);
            });
        }
    });

    let _ = build_handle.await;
    let _ = direct_handle.await;
    Ok(())
}

fn spawn_builders(
    ctx: &StreamContext,
    dtx: mpsc::Sender,
) -> tokio::task::JoinHandle<()> {
    let albums = ctx.albums.clone();
    let cfg = Arc::clone(&ctx.config);
    let root = Arc::clone(&ctx.project_root);
    let mcfg = Arc::clone(&ctx.manifest_cfg);
    let flags = Arc::clone(&ctx.active_flags);
    let jobs = ctx.jobs;

    tokio::task::spawn_blocking(move || {
        let pool = rayon::ThreadPoolBuilder::new()
            .num_threads(jobs.unwrap_or(1))
            .build()
            .unwrap();
        pool.install(|| {
            albums.par_iter().for_each(|ar| {
                match builder::build(ar, &root, &cfg, &mcfg, &flags) {
                    Ok(man) => {
                        let _ = dtx.blocking_send(man);
                    }
                    Err(e) => match e {
                        VellumError::ManifestIoError(_) 
                        | VellumError::ManifestParseError { .. }
                        | VellumError::JsonError(_) 
                        | VellumError::MissingCompilerRegistry => {
                            log::error!("SYSTEM FAILURE: {e}");
                        }
                        _ => {
                            log::warn!("VALIDATION REJECTED: {e}");
                        }
                    }
                }
            });
        });
    })
}

fn strip_empty_values(value: &mut Value) {
    match value {
        Value::Object(map) => {
            map.retain(|_, v| match v {
                Value::String(s) => !s.is_empty(),
                Value::Null => false,
                _ => true,
            });
            for v in map.values_mut() {
                strip_empty_values(v);
            }
        }
        Value::Array(arr) => {
            for v in arr.iter_mut() {
                strip_empty_values(v);
            }
        }
        _ => {}
    }
}

fn format_json_value(value: &Value, indent: usize, out: &mut String) {
    let pad = "  ".repeat(indent);
    match value {
        Value::Object(map) => {
            if map.is_empty() {
                out.push_str("{}");
                return;
            }
            out.push_str("{\n");
            let mut it = map.iter().peekable();
            while let Some((k, v)) = it.next() {
                out.push_str(&pad);
                out.push_str("  ");
                out.push_str(&serde_json::to_string(k).unwrap_or_default());
                out.push_str(": ");
                format_json_value(v, indent + 1, out);
                if it.peek().is_some() {
                    out.push_str(",\n");
                } else {
                    out.push('\n');
                }
            }
            out.push_str(&pad);
            out.push('}');
        }
        Value::Array(arr) => {
            if arr.is_empty() {
                out.push_str("[]");
                return;
            }

            let is_simple = arr.iter().all(|v| !matches!(v, Value::Object(_) | Value::Array(_)));

            if is_simple {
                out.push('[');
                let mut it = arr.iter().peekable();
                while let Some(v) = it.next() {
                    format_json_inline(v, out);
                    if it.peek().is_some() {
                        out.push_str(", ");
                    }
                }
            } else {
                out.push_str("[\n");
                let mut it = arr.iter().peekable();
                while let Some(v) = it.next() {
                    out.push_str(&pad);
                    out.push_str("  ");
                    format_json_value(v, indent + 1, out);
                    if it.peek().is_some() {
                        out.push_str(",\n");
                    } else {
                        out.push('\n');
                    }
                }
                out.push_str(&pad);
            }
            out.push(']');
        }
        _ => {
            out.push_str(&serde_json::to_string(value).unwrap_or_default());
        }
    }
}

fn format_json_inline(value: &Value, out: &mut String) {
    if let Value::Array(arr) = value {
        out.push('[');
        let mut it = arr.iter().peekable();
        while let Some(v) = it.next() {
            format_json_inline(v, out);
            if it.peek().is_some() {
                out.push_str(", ");
            }
        }
        out.push(']');
    } else if let Value::Object(_) = value {
        out.push_str("{}");
    } else {
        out.push_str(&serde_json::to_string(value).unwrap_or_default());
    }
}

fn finalize(
    mut v: Value,
    target: ExportTarget,
    notify_tx: Option<Arc<mpsc::Sender>>,
) -> Result<()> {
    let artist = v.get("album").and_then(|a| a.get("albumartist")).and_then(Value::as_str).unwrap_or("Unknown").to_string();
    let album = v.get("album").and_then(|a| a.get("album")).and_then(Value::as_str).unwrap_or("Unknown").to_string();

    let ctx = v
        .as_object_mut()
        .and_then(|o| o.remove("ctx"))
        .unwrap_or_else(|| json!({}));
    let harvest = ctx.get("harvest").cloned().unwrap_or_else(|| json!([]));
    let h_arr = harvest.as_array().map_or(&[][..], Vec::as_slice);

    let subset_keys_val = ctx
        .get("config")
        .and_then(|c| c.get("compiler"))
        .and_then(|c| c.get("file_subset_match"))
        .and_then(Value::as_array);

    let default_keys = vec![
        "album".to_string(),
        "albumartist".to_string(),
        "date".to_string(),
        "genre".to_string(),
        "comment".to_string(),
        "title".to_string(),
        "artist".to_string(),
        "tracknumber".to_string(),
        "discnumber".to_string(),
    ];

    let subset_keys: Vec = subset_keys_val.map_or_else(
        || default_keys, 
        |arr| arr.iter().filter_map(|val| val.as_str().map(ToString::to_string)).collect()
    );

    let is_match = verify::calculate_file_tag_subset_match(&v, h_arr, &subset_keys);

    if let Some(info) = v
        .get_mut("album")
        .and_then(|a| a.get_mut("info"))
        .and_then(|i| i.as_object_mut())
    {
        info.insert("file_tag_subset_match".to_string(), json!(is_match));
    }

    strip_empty_values(&mut v);

    let album_root_str = ctx
        .get("paths")
        .and_then(|p| p.get("album_root"))
        .and_then(Value::as_str);

    if let Some(path) = album_root_str {
        let album_root = Path::new(path);

        let mut content = String::new();
        format_json_value(&v, 0, &mut content);

        if target == ExportTarget::Stdout {
            println!("{content}");
        } else {
            std::fs::write(album_root.join("metadata.lock.json"), content)?;
            if let Some(tx_arc) = notify_tx {
                let root_clone = album_root.to_path_buf();
                let tx = (*tx_arc).clone();
                tokio::spawn(async move {
                    let _ = tx.send(AlbumUpdateSignal {
                        path: root_clone,
                        artist,
                        album,
                    }).await;
                });
            }
        }
    }
    Ok(())
}



use serde_json::Value;

pub fn calculate_file_tag_subset_match(
    enriched: &Value,
    harvest: &[Value],
    subset_keys: &[String],
) -> bool {
    let Some(album_obj) = enriched.get("album").and_then(Value::as_object) else {
        return false;
    };
    let Some(tracks_arr) = enriched.get("tracks").and_then(Value::as_array) else {
        return false;
    };
    if tracks_arr.len() != harvest.len() {
        return false;
    }

    for (idx, compiled_track) in tracks_arr.iter().enumerate() {
        let Some(t_obj) = compiled_track.as_object() else {
            return false;
        };
        let Some(p_tags) = harvest[idx].get("tags").and_then(Value::as_object) else {
            return false;
        };

        for key in subset_keys {
            let k_lower = key.to_lowercase();

            let mut compiled_val = t_obj.get(&k_lower);
            if compiled_val.is_none() {
                compiled_val = t_obj.get("tags").and_then(|tags| tags.get(&k_lower));
            }
            if compiled_val.is_none() {
                compiled_val = album_obj.get(&k_lower);
            }
            if compiled_val.is_none() {
                compiled_val = album_obj.get("tags").and_then(|tags| tags.get(&k_lower));
            }

            if let Some(v) = compiled_val {
                let p_val = p_tags
                    .get(&k_lower)
                    .and_then(Value::as_str)
                    .unwrap_or("");
                if !compare_values(&k_lower, v, p_val) {
                    return false;
                }
            }
        }
    }
    true
}

fn compare_values(key: &str, compiled: &Value, physical: &str) -> bool {
    let s_comp = match compiled {
        Value::String(s) => s.clone(),
        Value::Array(arr) => arr
            .iter()
            .map(|v| v.as_str().unwrap_or("").trim())
            .filter(|s| !s.is_empty())
            .collect::<Vec>()
            .join("; "),
        Value::Null => return physical.is_empty(),
        _ => compiled.to_string().replace('"', ""),
    };
    let (s_c, s_p) = (s_comp.trim(), physical.trim());
    let k_lower = key.to_lowercase();
    if k_lower == "tracknumber" || k_lower == "discnumber" {
        let parse = |s: &str| {
            s.split('/')
                .next()
                .unwrap_or("0")
                .trim()
                .parse::()
                .unwrap_or(0)
        };
        return parse(s_c) == parse(s_p);
    }
    s_c == s_p
}



pub use libvellum::images::cover_palette::process_image_to_palette;
pub use libvellum::images::cover_palette::resolve_core;



pub mod native;
pub mod standard;
pub mod cover_palette;

use crate::compile::builder::context::{AlbumContext, TrackContext};
use serde_json::{Value, json};

pub fn resolve_top_level_album_key(key: &str, ctx: &AlbumContext) -> Value {
    match key {
        "album" => standard::resolve_generic_string(ctx.source, "album", "", "Untitled"),
        "albumartist" => standard::resolve_generic_string(ctx.source, "albumartist", "artistartist", "Unknown"),
        "date" => standard::resolve_generic_string(ctx.source, "date", "year,originalyear", "0000"),
        "genre" => {
            let mut list = standard::resolve_generic_list(ctx.source, "genre", "");
            if let Value::Array(ref arr) = list
                && arr.is_empty() {
                    list = json!(["Unknown"]);
                }
            list
        },
        "comment" => json!(native::resolve_comment(ctx, "")),
        "original_yyyy_mm" => json!(native::resolve_yyyy_mm(ctx, "original_yyyy_mm", "")),
        "release_yyyy_mm" => json!(native::resolve_yyyy_mm(ctx, "release_yyyy_mm", "")),
        _ => Value::Null,
    }
}

pub fn resolve_top_level_track_key(key: &str, ctx: &TrackContext) -> Value {
    match key {
        "title" => standard::resolve_generic_string(ctx.source, "title", "", "Untitled"),
        "artist" => standard::resolve_generic_string_fallback(
            ctx.source, ctx.album_source, "artist", "albumartist", "Unknown"
        ),
        _ => Value::Null,
    }
}

pub fn resolve_album_key(key: &str, meta: &Value, ctx: &AlbumContext) -> Option {
    let class = meta.get("class").and_then(Value::as_str).unwrap_or("generic");
    let type_ = meta.get("type").and_then(Value::as_str).unwrap_or("string");
    let args = meta.get("args").and_then(Value::as_str).unwrap_or("");

    if class == "function" {
        let res = match key {
            "cover_chroma" => native::resolve_cover_chroma(ctx, args),
            "cover_entropy" => native::resolve_cover_entropy(ctx, args),
            "original_yyyy_mm" => Some(json!(native::resolve_yyyy_mm(ctx, "original_yyyy_mm", args))),
            "release_yyyy_mm" => Some(json!(native::resolve_yyyy_mm(ctx, "release_yyyy_mm", args))),
            "comment" => Some(json!(native::resolve_comment(ctx, args))),
            "unix_added" => Some(json!(native::resolve_album_info_unix_added(ctx, args))),
            _ => {
                log::warn!("Native function for key '{key}' not found, falling back to generic.");
                None
            }
        };
        if res.is_some() {
            return res;
        }
    }

    if standard::get_raw_value(ctx.source, key, args).is_some() {
        match type_ {
            "list" => Some(standard::resolve_generic_list(ctx.source, key, args)),
            "integer" => Some(standard::resolve_generic_integer(ctx.source, key, args)),
            "float" => Some(standard::resolve_generic_float(ctx.source, key, args)),
            "bool" => Some(standard::resolve_generic_bool(ctx.source, key, args)),
            _ => Some(standard::resolve_generic_string(ctx.source, key, args, "")),
        }
    } else {
        if let Some(first_track) = ctx.tracks.first()
            && let Some(tags) = first_track.get("tags")
                && let Some(t_val) = tags.get(key) {
                    return Some(t_val.clone());
                }
        None
    }
}

pub fn resolve_track_key(key: &str, meta: &Value, ctx: &TrackContext) -> Option {
    let class = meta.get("class").and_then(Value::as_str).unwrap_or("generic");
    let type_ = meta.get("type").and_then(Value::as_str).unwrap_or("string");
    let args = meta.get("args").and_then(Value::as_str).unwrap_or("");

    if class == "function" {
        let res = {
            log::warn!("Native function for track key '{key}' not found, falling back to generic.");
            None
        };
        if res.is_some() {
            return res;
        }
    }

    let source = if standard::get_raw_value(ctx.source, key, args).is_some() {
        Some(ctx.source)
    } else if standard::get_raw_value(ctx.album_source, key, args).is_some() {
        Some(ctx.album_source)
    } else {
        None
    };

    source.map(|src| match type_ {
        "list" => standard::resolve_generic_list(src, key, args),
        "integer" => standard::resolve_generic_integer(src, key, args),
        "float" => standard::resolve_generic_float(src, key, args),
        "bool" => standard::resolve_generic_bool(src, key, args),
        _ => standard::resolve_generic_string(src, key, args, ""),
    })
}



use crate::compile::builder::context::AlbumContext;
use crate::compile::resolvers::standard;
use serde_json::{Value, json};
use std::path::Path;

pub fn calculate_total_discs(tracks: &[Value]) -> u32 {
    let mut discs = std::collections::HashSet::new();
    for t in tracks {
        let val = match t.get("discnumber") {
            Some(Value::Number(n)) => n.as_u64().unwrap_or(0),
            Some(Value::String(s)) => s
                .split('/')
                .next()
                .unwrap_or("0")
                .parse::()
                .unwrap_or(0),
            _ => 0,
        };
        if val > 0 {
            discs.insert(val);
        }
    }
    if discs.is_empty() {
        1
    } else {
        u32::try_from(discs.len()).unwrap_or(u32::MAX)
    }
}

pub fn resolve_album_info_unix_added(ctx: &AlbumContext, args: &str) -> u64 {
    let mut keys = Vec::new();

    if let Some(fallbacks) = ctx.config.get("compiler").and_then(|c| c.get("unix_added")).and_then(Value::as_array) {
        for f in fallbacks {
            if let Some(s) = f.as_str() {
                keys.push(s.to_string());
            }
        }
    }

    if !args.is_empty() {
        keys.extend(args.split(',').map(str::trim).filter(|s| !s.is_empty()).map(String::from));
    }

    let mut found_timestamps = Vec::new();

    for key in &keys {
        if let Some(val) = ctx.source.get(key) {
            if let Some(s) = val.as_str() {
                if let Ok(ts) = s.parse::() {
                    found_timestamps.push(ts);
                }
            } else if let Some(u) = val.as_u64() {
                found_timestamps.push(u);
            }
        }
    }

    let smallest_ts = found_timestamps.into_iter().filter(|&ts| ts > 0).min();

    if let Some(ts) = smallest_ts {
        return ts;
    }

    if let Some(val) = ctx.source.get("unix_generated") {
        if let Some(s) = val.as_str() {
            if let Ok(ts) = s.parse::() {
                return ts;
            }
        } else if let Some(u) = val.as_u64() {
            return u;
        }
    }

    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

pub fn resolve_album_info_date_added(ctx: &AlbumContext, _args: &str) -> Option {
    let ts = resolve_album_info_unix_added(ctx, "");
    if let Some(fmt) = ctx.config.get("compiler").and_then(|c| c.get("date_added")).and_then(Value::as_str)
        && let Some(dt) = chrono::DateTime::from_timestamp(i64::try_from(ts).unwrap_or(0), 0) {
            return Some(json!(dt.format(fmt).to_string()));
        }
    None
}

pub fn rel_path(target: &Path, base: &Path) -> String {
    target.strip_prefix(base).map_or_else(
        |_| target.to_string_lossy().to_string(),
        |p| p.to_string_lossy().to_string(),
    )
}

pub fn resolve_cover_chroma(ctx: &AlbumContext, _args: &str) -> Option {
    ctx.cover_metrics.and_then(|m| m.chroma).map(|c| json!(c))
}

pub fn resolve_cover_entropy(ctx: &AlbumContext, _args: &str) -> Option {
    ctx.cover_metrics.and_then(|m| m.entropy).map(|e| json!(e))
}

pub fn resolve_cover_palette(ctx: &AlbumContext, _cfg: &Value) -> Option {
    ctx.cover_metrics.and_then(|m| m.palette.clone())
}

pub fn resolve_comment(ctx: &AlbumContext, _args: &str) -> String {
    if let Some(v) = ctx.source.get("comment").and_then(Value::as_str)
        && !v.is_empty()
    {
        return v.to_string();
    }

    let country = standard::resolve_generic_string(ctx.source, "country", "", "").as_str().unwrap_or("").to_string();
    let label = standard::resolve_generic_string(ctx.source, "label", "", "").as_str().unwrap_or("").to_string();
    let cat = standard::resolve_generic_string(ctx.source, "catalognumber", "", "").as_str().unwrap_or("").to_string();
    if country.is_empty() && label.is_empty() && cat.is_empty() {
        return String::new();
    }
    let yyyy_mm = resolve_yyyy_mm(ctx, "release_yyyy_mm", "");
    let year = if yyyy_mm.len() >= 4 {
        &yyyy_mm[0..4]
    } else {
        ""
    };

    let parts =[
        year,
        &country,
        &label,
        &cat,
    ];

    parts
        .iter()
        .filter(|s| !s.is_empty())
        .copied()
        .collect::<Vec>()
        .join(" ")
}

pub fn resolve_yyyy_mm(ctx: &AlbumContext, key: &str, _args: &str) -> String {
    if let Some(v) = ctx.source.get(key).and_then(Value::as_str) {
        return v.to_string();
    }
    let d = standard::resolve_generic_string(ctx.source, "date", "year,originalyear", "0000").as_str().unwrap_or("0000").to_string();
    if d.len() >= 4 {
        format!("{}-00", &d[0..4])
    } else {
        "0000-00".to_string()
    }
}

pub fn resolve_lyrics_path(
    album_root: &Path,
    track_num: u32,
    disc_num: u32,
    total_discs: u32,
) -> Option {
    let folders =[
        "lyrics",
        "Lyrics",
    ];
    let mut candidates = Vec::new();

    for folder in folders {
        let dir = album_root.join(folder);
        let Ok(entries) = std::fs::read_dir(dir) else {
            continue;
        };

        for entry in entries.filter_map(Result::ok) {
            let path = entry.path();
            if !path.is_file() {
                continue;
            }

            let Some(ext) = path
                .extension()
                .and_then(|e| e.to_str())
                .map(str::to_lowercase)
            else {
                continue;
            };
            if ext != "lrc" && ext != "txt" {
                continue;
            }

            let Some(name) = path.file_name().and_then(|n| n.to_str()) else {
                continue;
            };

            let is_match = if total_discs > 1 {
                name.find('.').is_some_and(|dot_idx| {
                    let disc_part = &name[..dot_idx];
                    let remaining = &name[dot_idx + 1..];
                    let track_part = remaining
                        .chars()
                        .take_while(char::is_ascii_digit)
                        .collect::();

                    let d_match = disc_part.parse::().is_ok_and(|d| d == disc_num);
                    let t_match = track_part.parse::().is_ok_and(|t| t == track_num);
                    d_match && t_match
                })
            } else {
                let track_part = name
                    .chars()
                    .take_while(char::is_ascii_digit)
                    .collect::();
                track_part.parse::().is_ok_and(|t| t == track_num)
            };

            if is_match {
                candidates.push((rel_path(&path, album_root), ext));
            }
        }
    }

    if candidates.is_empty() {
        return None;
    }

    if let Some(lrc) = candidates.iter().find(|(_, ext)| ext == "lrc") {
        return Some(lrc.0.clone());
    }

    candidates.first().map(|(path, _)| path.clone())
}



use serde_json::{Value, json};

pub fn get_raw_value<'a>(source: &'a Value, key: &str, args: &str) -> Option<&'a Value> {
    let check = |k: &str| -> Option<&'a Value> {
        let v = source.get(k)?;
        match v {
            Value::Null => None,
            Value::String(s) if s.trim().is_empty() => None,
            Value::Array(a) if a.is_empty() => None,
            _ => Some(v),
        }
    };

    if let Some(v) = check(key) {
        return Some(v);
    }

    if !args.is_empty() {
        for fallback in args.split(',').map(str::trim).filter(|s| !s.is_empty()) {
            if let Some(v) = check(fallback) {
                return Some(v);
            }
        }
    }
    None
}

pub fn resolve_generic_string(source: &Value, key: &str, args: &str, default: &str) -> Value {
    get_raw_value(source, key, args).map_or_else(
        || json!(default),
        |v| match v {
            Value::String(s) => json!(s.trim()),
            Value::Array(arr) => json!(arr.iter().filter_map(|x| x.as_str()).collect::<Vec>().join("; ")),
            _ => json!(v.to_string().replace('"', "").trim()),
        }
    )
}

pub fn resolve_generic_list(source: &Value, key: &str, args: &str) -> Value {
    get_raw_value(source, key, args).map_or_else(
        || json!(Vec::::new()),
        |v| match v {
            Value::Array(arr) => {
                let list: Vec = arr.iter().filter_map(|x| x.as_str().map(|s| s.trim().to_string())).filter(|s| !s.is_empty()).collect();
                json!(list)
            }
            Value::String(s) => {
                let list: Vec = s.split(';').map(|x| x.trim().to_string()).filter(|x| !x.is_empty()).collect();
                json!(list)
            }
            _ => json!([v.to_string().replace('"', "").trim()]),
        }
    )
}

pub fn resolve_generic_integer(source: &Value, key: &str, args: &str) -> Value {
    get_raw_value(source, key, args).map_or_else(
        || json!(0),
        |v| match v {
            Value::Number(n) => json!(n.as_i64().unwrap_or(0)),
            Value::String(s) => json!(s.trim().parse::().unwrap_or(0)),
            _ => json!(0),
        }
    )
}

pub fn resolve_generic_float(source: &Value, key: &str, args: &str) -> Value {
    get_raw_value(source, key, args).map_or_else(
        || json!(0.0),
        |v| match v {
            Value::Number(n) => json!(n.as_f64().unwrap_or(0.0)),
            Value::String(s) => json!(s.trim().parse::().unwrap_or(0.0)),
            _ => json!(0.0),
        }
    )
}

pub fn resolve_generic_bool(source: &Value, key: &str, args: &str) -> Value {
    get_raw_value(source, key, args).map_or_else(
        || json!(false),
        |v| match v {
            Value::Bool(b) => json!(*b),
            Value::String(s) => {
                let s = s.trim().to_lowercase();
                json!(s == "true" || s == "1" || s == "yes")
            }
            Value::Number(n) => json!(n.as_i64().unwrap_or(0) > 0),
            _ => json!(false),
        }
    )
}

pub fn resolve_generic_string_fallback(
    source: &Value,
    album_source: &Value,
    key: &str,
    album_key: &str,
    default: &str,
) -> Value {
    let check = |v: &Value| -> Option {
        match v {
            Value::String(s) if !s.trim().is_empty() => Some(s.trim().to_string()),
            Value::Array(a) if !a.is_empty() => Some(a.iter().filter_map(|x| x.as_str()).collect::<Vec>().join("; ")),
            Value::Null => None,
            _ => Some(v.to_string().replace('"', "").trim().to_string()),
        }
    };

    source.get(key).and_then(check).map_or_else(
        || album_source.get(album_key).and_then(check).map_or_else(|| json!(default), |v| json!(v)),
        |v| json!(v)
    )
}

pub fn format_ms(ms: u64) -> String {
    let s = (ms / 1000) % 60;
    let m = (ms / (1000 * 60)) % 60;
    let h = ms / (1000 * 60 * 60);
    if h > 0 {
        format!("{h}:{m:02}:{s:02}")
    } else {
        format!("{m}:{s:02}")
    }
}



pub mod builder;
pub mod engine;
pub mod resolvers;

use libvellum::config::AppConfig;
use anyhow::{Context, Result};
use serde_json::json;
use std::path::PathBuf;
use std::sync::Arc;
use tokio::sync::mpsc;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum CompileMode {
    Standard,
    Intermediary,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ExportTarget {
    File,
    Stdout,
}

pub struct CompileFlags {
    pub mode: CompileMode,
    pub target: ExportTarget,
    pub pretty: bool,
}

pub struct CompileOptions {
    pub target_path: PathBuf,
    pub flags: Vec,
    pub specific_albums: Option<Vec>,
    pub jobs: Option,
    pub notify_tx: Option<mpsc::Sender>,
    pub compile_flags: CompileFlags,
}

pub async fn run(mut options: CompileOptions) -> Result<()> {
    let (config, _raw, path): (AppConfig, toml::Value, PathBuf) = AppConfig::load().context("Config failed")?;
    let project_root = path.parent().unwrap().to_path_buf();
    if !options.flags.contains(&"default".to_string()) {
        options.flags.push("default".to_string());
    }

    let albums = if let Some(l) = options.specific_albums {
        l
    } else {
        let scan_depth = config.compiler.as_ref().and_then(|c| c.scan_depth).unwrap_or(4);
        libvellum::scanner::find_target_albums(&options.target_path, scan_depth)?
    };

    if albums.is_empty() {
        return Ok(());
    }
    let config_json = serde_json::to_value(&config)?;
    let manifest_cfg = config_json
        .get("manifest")
        .cloned()
        .unwrap_or_else(|| json!({}));
    let active_flags = Arc::new(options.flags);

    if options.compile_flags.mode == CompileMode::Intermediary {
        for root in &albums {
            let m = builder::build(
                root,
                &project_root,
                &config_json,
                &manifest_cfg,
                &active_flags,
            )?;
            if options.compile_flags.pretty {
                println!("{}", serde_json::to_string_pretty(&m)?);
            } else {
                println!("{}", serde_json::to_string(&m)?);
            }
        }
        return Ok(());
    }

    let ctx = engine::stream::StreamContext {
        albums: albums.clone(),
        config: Arc::new(config_json.clone()),
        project_root: Arc::new(project_root.clone()),
        manifest_cfg: Arc::new(manifest_cfg),
        active_flags,
        target: options.compile_flags.target,
        jobs: options.jobs,
        notify_tx: options.notify_tx,
    };

    engine::stream::run(ctx).await
}



use anyhow::Result;
use rayon::prelude::*;
use std::io::{self, Write};
use std::path::{Path, PathBuf};
use std::sync::mpsc;
use std::thread;
use walkdir::WalkDir;

pub use libvellum::harvest::{harvest_file, sanitize_key, TrackJson};

pub fn run(roots: Vec, pretty: bool) {
    let extensions = ["flac", "mp3", "m4a", "ogg", "wav", "opus"];
    let mut files = Vec::new();

    for root in roots {
        files.extend(scan_files(&root, &extensions));
    }

    if files.is_empty() {
        return;
    }

    let (tx, rx) = mpsc::channel::();

    let printer_handle = thread::spawn(move || {
        let stdout = io::stdout();
        let mut handle = io::BufWriter::new(stdout.lock());
        for line in rx {
            writeln!(handle, "{line}").ok();
        }
    });

    files.par_iter().for_each_with(tx, |tx, path| {
        if let Ok(payload) = harvest_file(path) {
            let json_res = if pretty {
                serde_json::to_string_pretty(&payload)
            } else {
                serde_json::to_string(&payload)
            };

            if let Ok(json) = json_res {
                tx.send(json).ok();
            }
        }
    });

    printer_handle.join().unwrap();
}

fn scan_files(root: &Path, extensions: &[&str]) -> Vec {
    if root.is_file() {
        return vec![root.to_path_buf()];
    }

    WalkDir::new(root)
        .follow_links(true)
        .into_iter()
        .filter_map(Result::ok)
        .filter(|e| e.file_type().is_file())
        .map(|e| e.path().to_path_buf())
        .filter(|p| {
            p.extension()
                .and_then(|ext| ext.to_str())
                .is_some_and(|ext| extensions.contains(&ext.to_lowercase().as_str()))
        })
        .collect()
}



use crate::harvest::sanitize_key;
use indexmap::IndexMap;
use serde_json::Value;
use std::collections::HashSet;
use toml::Value as TomlValue;

pub fn compress(
    mut raw_tracks: Vec<serde_json::Map>,
    manifest_layout: Option<&IndexMap>,
) -> (
    serde_json::Map,
    Vec<serde_json::Map>,
) {
    if raw_tracks.is_empty() {
        return (serde_json::Map::new(), Vec::new());
    }

    let mut forced_track_keys = HashSet::new();
    if let Some(layout) = manifest_layout {
        for (key, meta) in layout {
            if let Some(table) = meta.as_table()
                && table.get("level").and_then(|v| v.as_str()) == Some("track") {
                    forced_track_keys.insert(sanitize_key(key));
                }
        }
    }

    let first_track = &raw_tracks[0];
    let mut candidate_keys: HashSet = first_track.keys().cloned().collect();

    for track in raw_tracks.iter().skip(1) {
        candidate_keys.retain(|k| track.contains_key(k));
    }

    let mut album_pool = serde_json::Map::new();
    let mut keys_to_promote = Vec::new();

    for key in candidate_keys {
        let is_identical = raw_tracks
            .iter()
            .all(|t| t.get(&key) == first_track.get(&key));

        if is_identical {
            let s_key = sanitize_key(&key);
            if forced_track_keys.contains(&s_key) {
                continue;
            }
            keys_to_promote.push(key.clone());
            album_pool.insert(key.clone(), first_track.get(&key).unwrap().clone());
        }
    }

    for track in &mut raw_tracks {
        for k in &keys_to_promote {
            track.remove(k);
        }
    }

    (album_pool, raw_tracks)
}



use crate::harvest::sanitize_key;
use indexmap::IndexMap;
use serde_json::Value;
use std::collections::HashSet;

fn format_toml_value(val: &Value) -> String {
    match val {
        Value::String(s) => serde_json::to_string(s).unwrap_or_default(),
        Value::Number(n) => n.to_string(),
        Value::Bool(b) => b.to_string(),
        Value::Array(arr) => {
            let formatted: Vec = arr.iter().map(format_toml_value).collect();
            format!("[{}]", formatted.join(", "))
        }
        _ => serde_json::to_string(val).unwrap_or_default(),
    }
}

fn format_toml_value_with_cast(val: &Value, key: &str) -> String {
    if (key == "tracknumber" || key == "discnumber")
        && let Some(s) = val.as_str() {
            let clean = s.split('/').next().unwrap_or("").trim();
            if clean.parse::().is_ok() {
                return clean.to_string();
            }
        }
    format_toml_value(val)
}

pub fn render_toml_block(
    pool: &serde_json::Map,
    layout: Option<&IndexMap>,
    level: &str,
) -> Vec {
    let mut lines = Vec::new();
    let mut layout_keys = HashSet::new();

    if let Some(lay) = layout {
        for key in lay.keys() {
            layout_keys.insert(sanitize_key(key));
        }

        for (key, meta) in lay {
            if let Some(meta_table) = meta.as_table() {
                let key_level = meta_table.get("level").and_then(|v| v.as_str()).unwrap_or("");
                if key_level == level {
                    let s_key = sanitize_key(key);
                    let val = pool.get(&s_key).or_else(|| pool.get(key));

                    let rendered_val = val.map_or_else(
                        || "\"\"".to_string(), 
                        |v| format_toml_value_with_cast(v, &s_key)
                    );

                    let newline = meta_table
                        .get("newline")
                        .and_then(toml::Value::as_bool)
                        .unwrap_or(false);

                    if newline {
                        lines.push(String::new());
                    }

                    lines.push(format!("{s_key} = {rendered_val}"));
                }
            }
        }
    }

    let mut appendix_keys: Vec = pool
        .keys()
        .filter(|k| {
            let s_k = sanitize_key(k);
            !layout_keys.contains(&s_k) && s_k != "unix_generated"
        })
        .cloned()
        .collect();
    appendix_keys.sort();

    for k in appendix_keys {
        if let Some(v) = pool.get(&k) {
            let s_k = sanitize_key(&k);
            lines.push(format!("{} = {}", s_k, format_toml_value_with_cast(v, &s_k)));
        }
    }

    if let Some(v) = pool.get("unix_generated") {
        if !lines.is_empty() && lines.last().is_some_and(|s| !s.is_empty()) {
            lines.push(String::new());
        }
        lines.push(format!("unix_generated = {}", format_toml_value(v)));
    }

    lines
}



use serde_json::Value;
use std::collections::{HashMap, HashSet};
use std::path::{Path, PathBuf};

pub type GroupedTracks = HashMap<Vec, Vec<(PathBuf, serde_json::Map)>>;

pub fn normalize_tag(value: Option<&Value>) -> String {
    match value {
        Some(Value::String(s)) => s.trim().to_string(),
        Some(Value::Array(arr)) => arr
            .iter()
            .filter_map(Value::as_str)
            .collect::<Vec>()
            .join("; "),
        Some(v) => v.to_string().replace('"', "").trim().to_string(),
        None => String::new(),
    }
}

fn parse_sort_int(value: Option<&Value>) -> u32 {
    let s = normalize_tag(value);
    let s = s.split('/').next().unwrap_or("0").trim();
    s.parse().unwrap_or(0)
}

pub fn group_tracks(
    tracks: Vec<(PathBuf, serde_json::Map)>,
    keys: &[String],
) -> GroupedTracks {
    let mut buckets: GroupedTracks = HashMap::new();

    for (path, mut track) in tracks {
        let group_key: Vec = keys.iter().map(|k| normalize_tag(track.get(k))).collect();
        track.insert(
            "track_path_absolute".to_string(),
            Value::String(path.to_string_lossy().to_string()),
        );
        buckets.entry(group_key).or_default().push((path, track));
    }

    buckets
}

pub fn sort_album_tracks(tracks: &mut[(PathBuf, serde_json::Map)]) {
    tracks.sort_by(|(p_a, t_a), (p_b, t_b)| {
        let disc_a = parse_sort_int(t_a.get("discnumber"));
        let disc_b = parse_sort_int(t_b.get("discnumber"));
        if disc_a != disc_b {
            return disc_a.cmp(&disc_b);
        }

        let trk_a = parse_sort_int(t_a.get("tracknumber"));
        let trk_b = parse_sort_int(t_b.get("tracknumber"));
        if trk_a != trk_b {
            return trk_a.cmp(&trk_b);
        }

        alphanumeric_sort::compare_path(p_a, p_b)
    });
}

pub fn resolve_anchor(
    tracks: &[(PathBuf, serde_json::Map)],
    library_root: &Path,
    supported_exts: &[String],
) -> (Option, bool) {
    if tracks.is_empty() {
        return (None, false);
    }

    let mut paths = Vec::new();
    let mut group_paths_set = HashSet::new();

    for (p, _) in tracks {
        if let Ok(canon) = p.canonicalize() {
            paths.push(canon.clone());
            group_paths_set.insert(canon);
        } else {
            paths.push(p.clone());
            group_paths_set.insert(p.clone());
        }
    }

    if paths.is_empty() {
        return (None, false);
    }

    let mut anchor = paths[0].parent().unwrap_or(&paths[0]).to_path_buf();
    for p in &paths[1..] {
        while !p.starts_with(&anchor) {
            if let Some(parent) = anchor.parent() {
                anchor = parent.to_path_buf();
            } else {
                break;
            }
        }
    }

    let abs_anchor = anchor.canonicalize().unwrap_or(anchor);
    let abs_lib = library_root
        .canonicalize()
        .unwrap_or_else(|_| library_root.to_path_buf());

    if !abs_anchor.starts_with(&abs_lib) {
        return (Some(abs_anchor), false);
    }

    let mut valid = true;
    for entry in walkdir::WalkDir::new(&abs_anchor).into_iter().filter_map(Result::ok) {
        if !entry.file_type().is_file() {
            continue;
        }
        let p = entry
            .path()
            .canonicalize()
            .unwrap_or_else(|_| entry.path().to_path_buf());
        if let Some(ext) = p.extension().and_then(|e| e.to_str()) {
            let ext_lower = format!(".{}", ext.to_lowercase());
            if supported_exts.contains(&ext_lower) && !group_paths_set.contains(&p) {
                log::warn!(
                    "Exclusivity Violation: {}\nCollision from: {}",
                    abs_anchor.display(),
                    p.display()
                );
                valid = false;
                break;
            }
        }
    }

    (Some(abs_anchor), valid)
}



pub mod compressor;
pub mod engine;
pub mod grouper;

use libvellum::config::AppConfig;
use libvellum::utils::expand_path;
use libvellum::harvest::harvest_file;
use anyhow::{Context, Result};
use indicatif::{ProgressBar, ProgressStyle};
use rayon::prelude::*;
use std::fs;
use std::path::{Path, PathBuf};
use std::time::SystemTime;
use walkdir::WalkDir;

pub fn run(force: bool) -> Result<()> {
    let (config, _raw_config, _): (AppConfig, toml::Value, PathBuf) = AppConfig::load().context("Failed to load config")?;
    let lib_root = expand_path(&config.storage.library_root).canonicalize()?;

    let manifest_cfg = config.manifest.context("Missing [manifest] configuration")?;
    let supported_exts: Vec = manifest_cfg
        .supported_extensions
        .as_ref().map_or_else(|| vec![".flac".to_string()], |exts: &Vec| exts.iter().map(|e| e.to_lowercase()).collect());

    let grouping_keys = vec!["albumartist".to_string(), "album".to_string()];
    let manifest_layout = manifest_cfg.keys;

    let dirs_to_harvest = find_harvestable_directories(&lib_root, force, &supported_exts);

    if dirs_to_harvest.is_empty() {
        log::info!("No new audio directories found.");
        return Ok(());
    }

    let harvested = harvest_audio_files(dirs_to_harvest, &supported_exts);

    if harvested.is_empty() {
        return Ok(());
    }

    let buckets = grouper::group_tracks(harvested, &grouping_keys);

    let pb = ProgressBar::new(buckets.len() as u64);
    pb.set_style(
        ProgressStyle::default_bar()
            .template(
                "{spinner:.green}[{elapsed_precise}][{bar:40.cyan/blue}] {pos}/{len} ({eta})",
            )
            .unwrap()
            .progress_chars("#>-"),
    );

    for (_group_id, mut tracks) in buckets {
        pb.inc(1);
        let (anchor_opt, is_valid) = grouper::resolve_anchor(&tracks, &lib_root, &supported_exts);
        if !is_valid {
            continue;
        }

        if let Some(anchor) = anchor_opt {
            grouper::sort_album_tracks(&mut tracks);
            let clean_tracks: Vec = tracks
                .into_iter()
                .map(|(_, mut t)| {
                    t.remove("track_path_absolute");
                    t
                })
                .collect();

            let (mut album_pool, track_pools) =
                compressor::compress(clean_tracks, manifest_layout.as_ref());

            let unix_generated = SystemTime::now()
                .duration_since(SystemTime::UNIX_EPOCH)
                .unwrap_or_default()
                .as_secs();
            album_pool.insert(
                "unix_generated".to_string(),
                serde_json::Value::Number(serde_json::Number::from(unix_generated)),
            );

            let toml_content = serialize_manifest(&album_pool, &track_pools, manifest_layout.as_ref());

            let meta_path = anchor.join("metadata.toml");
            if let Err(e) = fs::write(&meta_path, toml_content) {
                log::error!("Failed to write {}: {}", meta_path.display(), e);
            }
        }
    }

    pb.finish_with_message("Generation complete");

    Ok(())
}

fn find_harvestable_directories(lib_root: &Path, force: bool, supported_exts: &[String]) -> Vec {
    let mut dirs_to_harvest = Vec::new();
    let mut it = WalkDir::new(lib_root).into_iter();

    while let Some(Ok(entry)) = it.next() {
        if entry.file_type().is_dir() {
            let path = entry.path();
            if !force && path.join("metadata.toml").exists() {
                it.skip_current_dir();
                continue;
            }

            let has_audio = fs::read_dir(path)
                .map(|mut d| {
                    d.any(|e| {
                        if let Ok(f) = e
                            && f.file_type().is_ok_and(|ft| ft.is_file())
                                && let Some(ext) = f.path().extension().and_then(|e| e.to_str()) {
                                    let ext_lower = format!(".{}", ext.to_lowercase());
                                    return supported_exts.contains(&ext_lower);
                                }
                        false
                    })
                })
                .unwrap_or(false);

            if has_audio {
                dirs_to_harvest.push(path.to_path_buf());
            }
        }
    }
    dirs_to_harvest
}

fn harvest_audio_files(
    dirs_to_harvest: Vec,
    supported_exts: &[String],
) -> Vec<(PathBuf, serde_json::Map)> {
    let mut audio_files = Vec::new();
    for dir in dirs_to_harvest {
        if let Ok(entries) = fs::read_dir(dir) {
            for entry in entries.filter_map(Result::ok) {
                let path = entry.path();
                if path.is_file()
                    && let Some(ext) = path.extension().and_then(|e| e.to_str()) {
                        let ext_lower = format!(".{}", ext.to_lowercase());
                        if supported_exts.contains(&ext_lower) {
                            audio_files.push(path);
                        }
                    }
            }
        }
    }

    log::info!("Harvesting {} new audio files...", audio_files.len());

    audio_files
        .into_par_iter()
        .filter_map(|path| match harvest_file(&path) {
            Ok(data) => {
                let mut map = serde_json::Map::new();
                for (k, v) in data.tags {
                    map.insert(k, serde_json::Value::String(v));
                }
                Some((path, map))
            }
            Err(e) => {
                log::warn!("Failed to harvest {}: {}", path.display(), e);
                None
            }
        })
        .collect()
}

fn serialize_manifest(
    album_pool: &serde_json::Map,
    track_pools: &[serde_json::Map],
    manifest_layout: Option<&indexmap::IndexMap>,
) -> String {
    let mut toml_content = String::new();
    toml_content.push_str("[album]\n");
    let album_lines = engine::render_toml_block(album_pool, manifest_layout, "album");
    toml_content.push_str(&album_lines.join("\n"));
    toml_content.push_str("\n\n");

    for tp in track_pools {
        toml_content.push_str("[[tracks]]\n");
        let track_lines = engine::render_toml_block(tp, manifest_layout, "track");
        toml_content.push_str(&track_lines.join("\n"));
        toml_content.push_str("\n\n");
    }

    toml_content
}



use anyhow::{Context, Result};
use lava_torrent::torrent::v1::Torrent;
use std::collections::HashMap;
use std::fs;
use std::path::Path;
use std::process::Command;
use libvellum::config::AppConfig;
use libvellum::utils::expand_path;

pub fn run(album_path: Option) -> Result<()> {
    let (config, _, _) = AppConfig::load().context("Failed to load config")?;
    let nix_config = config.nix.as_ref().context("Missing [nix] configuration in config.toml")?;
    let store_path = expand_path(&nix_config.store)
        .canonicalize()
        .context("Custom nix store path does not exist or is inaccessible")?;

    let mut flake_uri = nix_config.flake.clone();
    if flake_uri.starts_with('/') || flake_uri.starts_with('~') {
        let expanded = expand_path(&flake_uri);
        let canon = expanded.canonicalize().context("Could not find flake path")?;

        let flake_dir = if canon.is_file() {
            canon.parent().context("Flake path has no parent")?.to_path_buf()
        } else {
            canon
        };

        flake_uri = format!("path:{}", flake_dir.display());
    }

    let target_path = if let Some(a) = album_path {
        let p = expand_path(&a).canonicalize().context("Album path does not exist")?;
        if p.is_dir() && p.join("album.nix").exists() {
            p.join("album.nix")
        } else if p.is_file() && p.file_name().unwrap_or_default() == "album.nix" {
            p
        } else {
            anyhow::bail!("No album.nix found at specified path");
        }
    } else {
        let curr = std::env::current_dir()?;
        if curr.join("album.nix").exists() {
            curr.join("album.nix")
        } else {
            anyhow::bail!("No album.nix found in current directory");
        }
    };

    build_album(&target_path, &store_path, &flake_uri, &config)?;

    Ok(())
}

fn build_album(
    target_path: &Path,
    store_path: &Path,
    flake_uri: &str,
    config: &AppConfig,
) -> Result<()> {
    let target = target_path.parent().unwrap();
    let album_info = crate::nix::get::parse_album_nix(target_path)?;
    let source_disk = crate::nix::get::resolve_source_disk(&album_info, target, config);

    let physical_source_disk = source_disk
        .canonicalize()
        .unwrap_or_else(|_| source_disk.clone());

    let staging_src_env = physical_source_disk.to_string_lossy().to_string();

    verify_source_hash(&physical_source_disk, &album_info.source_disk_hash)?;

    let torrent_file_path = if album_info.torrent_file.starts_with("./") {
        target.join(album_info.torrent_file.trim_start_matches("./"))
    } else {
        target.join(&album_info.torrent_file)
    };

    let torrent_name = Torrent::read_from_file(&torrent_file_path)
        .map_or_else(|_| album_info.pname.clone(), |t| t.name);

    let mut vars = HashMap::new();
    vars.insert(
        "sourceDisk.path".to_string(),
        physical_source_disk.to_string_lossy().to_string(),
    );
    vars.insert(
        "sourceTorrent.file".to_string(),
        torrent_file_path.to_string_lossy().to_string(),
    );
    vars.insert(
        "sourceTorrent.hash".to_string(),
        album_info.torrent_hash.clone(),
    );
    vars.insert("sourceTorrent.name".to_string(), torrent_name);

    run_verification(config, &vars, target)?;

    let truncated_hash = crate::nix::get::get_nix32_truncate(&album_info.torrent_hash);
    let sanitized_pname = album_info.pname.replace('"', "").trim().replace(' ', "-");
    let link_name = format!("{sanitized_pname}-{truncated_hash}");

    let gc_roots_albums = store_path.join("gcroots").join("albums");
    fs::create_dir_all(&gc_roots_albums).context("Failed to create gcroots/albums directory")?;

    let result_link = gc_roots_albums.join(&link_name);
    execute_nix_build(target, store_path, &staging_src_env, flake_uri, &result_link)?;

    let logical_path = fs::read_link(&result_link).with_context(|| {
        format!(
            "Nix build claimed success but result link {} was not found",
            result_link.display()
        )
    })?;

    let physical_store_path =
        store_path.join(logical_path.strip_prefix("/").unwrap_or(&logical_path));

    materialize_output(&physical_store_path, target, store_path)?;

    pin_source_and_seed(
        target,
        store_path,
        &staging_src_env,
        flake_uri,
        config,
        &link_name,
        &mut vars,
    )?;

    Ok(())
}

fn verify_source_hash(source_disk: &Path, expected_hash: &str) -> Result<()> {
    if !source_disk.exists() {
        anyhow::bail!("Source path does not exist at: {}", source_disk.display());
    }

    let hash_output = Command::new("nix")
        .args(["hash", "path", source_disk.to_str().unwrap()])
        .output()
        .context("Failed to compute source hash using nix")?;

    let actual_hash = String::from_utf8_lossy(&hash_output.stdout).trim().to_string();

    if expected_hash.is_empty() || expected_hash != actual_hash {
        anyhow::bail!(
            "Source hash mismatch or missing in manifest.\n\nExpected: '{}'\nActual:   '{}'\n\nPlease update `sourceDisk.hash` in album.nix to the actual value.",
            if expected_hash.is_empty() { "none" } else { expected_hash },
            actual_hash
        );
    }

    Ok(())
}

fn run_verification(config: &AppConfig, vars: &HashMap, target: &Path) -> Result<()> {
    if let Some(nix_cfg) = &config.nix
        && let Some(cmds) = &nix_cfg.commands
        && let Some(verify_cmd_tpl) = cmds.get("verify_torrent")
    {
        let final_cmd = crate::nix::get::resolve_template(verify_cmd_tpl, vars);
        log::info!("Executing verification: {final_cmd}");

        let status = Command::new("sh")
            .arg("-c")
            .arg(&final_cmd)
            .current_dir(target)
            .status()?;

        if !status.success() {
            anyhow::bail!("Verification command failed with status: {status}");
        }
        log::info!("Seeding check passed!");
    }
    Ok(())
}

fn execute_nix_build(
    target: &Path,
    store_path: &Path,
    staging_src_env: &str,
    flake_uri: &str,
    result_link: &Path,
) -> Result<()> {
    let expr =
        format!("(import ./album.nix {{ vellum = (builtins.getFlake \"{flake_uri}\").lib; }})");
    let mut cmd = Command::new("nix");
    cmd.env("VELLUM_STAGING_SRC", staging_src_env);
    cmd.arg("build")
        .arg("--store")
        .arg(store_path)
        .arg("--impure")
        .arg("--expr")
        .arg(&expr)
        .arg("--out-link")
        .arg(result_link)
        .current_dir(target);

    let status = cmd.status().context("Failed to execute nix build binary")?;
    if !status.success() {
        anyhow::bail!(
            "Nix build failed with exit code {} for {}",
            status.code().unwrap_or(-1),
            target.display()
        );
    }
    Ok(())
}

fn pin_source_and_seed(
    target: &Path,
    store_path: &Path,
    staging_src_env: &str,
    flake_uri: &str,
    config: &AppConfig,
    link_name: &str,
    vars: &mut HashMap,
) -> Result<()> {
    let expr_source = format!(
        "(import ./album.nix {{ vellum = (builtins.getFlake \"{flake_uri}\").lib; }}).sourceStorePath"
    );

    let eval_output = Command::new("nix")
        .env("VELLUM_STAGING_SRC", staging_src_env)
        .arg("eval")
        .arg("--store")
        .arg(store_path)
        .arg("--raw")
        .arg("--impure")
        .arg("--expr")
        .arg(&expr_source)
        .current_dir(target)
        .output()?;

    let source_store_path_raw = String::from_utf8_lossy(&eval_output.stdout).trim().to_string();
    if source_store_path_raw.is_empty() || !source_store_path_raw.starts_with("/nix/store") {
        return Ok(());
    }

    let mapped_source_store_path = source_store_path_raw.strip_prefix("/").map_or_else(
        || source_store_path_raw.clone(),
        |stripped| store_path.join(stripped).to_string_lossy().to_string(),
    );

    let gc_roots_source = store_path.join("gcroots").join("source");
    fs::create_dir_all(&gc_roots_source)?;
    let source_link = gc_roots_source.join(link_name);

    if source_link.exists() || source_link.symlink_metadata().is_ok() {
        fs::remove_file(&source_link)?;
    }

    if let Err(e) = std::os::unix::fs::symlink(&mapped_source_store_path, &source_link) {
        log::warn!(
            "Failed to create source GC root link {}: {}",
            source_link.display(),
            e
        );
    }

    vars.insert("sourceStorePath".to_string(), mapped_source_store_path);

    if let Some(nix_cfg) = &config.nix
        && let Some(cmds) = &nix_cfg.commands
        && let Some(seed_cmd_tpl) = cmds.get("seed_torrent")
    {
        let final_seed_cmd = crate::nix::get::resolve_template(seed_cmd_tpl, vars);
        log::info!("Executing seed command: {final_seed_cmd}");
        let _ = Command::new("sh")
            .arg("-c")
            .arg(&final_seed_cmd)
            .current_dir(target)
            .status();
    }

    Ok(())
}

fn materialize_output(store_dir: &Path, target_dir: &Path, store_path: &Path) -> Result<()> {
    let entries = fs::read_dir(store_dir).with_context(|| {
        format!(
            "Could not read nix store directory: {}",
            store_dir.display()
        )
    })?;

    for entry in entries {
        let entry = entry?;
        let file_name = entry.file_name();
        let file_type = entry.file_type()?;

        if file_name == "album.nix" {
            continue;
        }

        let mut store_file = entry.path();
        let target_file = target_dir.join(&file_name);

        if let Ok(meta) = fs::symlink_metadata(&target_file) {
            if meta.is_dir() {
                fs::remove_dir_all(&target_file)?;
            } else {
                fs::remove_file(&target_file)?;
            }
        }

        if file_type.is_symlink() {
            let resolved_path = fs::read_link(&store_file)?;
            if resolved_path.starts_with("/nix/store") {
                let stripped = resolved_path.strip_prefix("/").unwrap();
                store_file = store_path.join(stripped);
            } else if resolved_path.is_relative() {
                store_file = store_dir.join(resolved_path);
            } else {
                store_file = resolved_path;
            }
        }

        if fs::hard_link(&store_file, &target_file).is_err() {
            std::os::unix::fs::symlink(&store_file, &target_file).with_context(|| {
                format!(
                    "Failed to create link (hard or sym) for {} at {}",
                    store_file.display(),
                    target_file.display()
                )
            })?;
        }
    }
    Ok(())
}



use anyhow::{Context, Result};
use lava_torrent::torrent::v1::Torrent;
use std::path::{Path, PathBuf};
use std::process::Command;
use libvellum::config::AppConfig;
use libvellum::utils::expand_path;

#[derive(Debug)]
pub struct AlbumInfo {
    pub pname: String,
    pub source_disk_path: String,
    pub source_disk_hash: String,
    pub torrent_file: String,
    pub torrent_hash: String,
}

pub fn get_nix32_truncate(hash: &str) -> String {
    if hash.is_empty() {
        return "nohash".to_string();
    }

    let output = Command::new("nix")
        .args(["hash", "to-base32", hash])
        .output();

    if let Ok(out) = output && out.status.success() {
        let nix32 = String::from_utf8(out.stdout).unwrap_or_default().trim().to_string();
        return nix32.chars().take(32).collect();
    }

    hash.trim_start_matches("sha256-").chars().take(32).collect::().replace('/', "_").replace('+', "-")
}

fn eval_nix_field(path: &Path, field_path: &str) -> Result {
    let path_str = path.to_string_lossy();
    let expr = format!(
        "let res = (import (/. + \"{path_str}\") {{ vellum = {{ mkAlbum = x: x; }}; }}); in builtins.toString (res.{field_path} or \"\")"
    );

    let output = Command::new("nix")
        .args(["eval", "--raw", "--impure", "--expr", &expr])
        .output()
        .context("Failed to execute nix eval")?;

    if !output.status.success() {
        let err = String::from_utf8_lossy(&output.stderr);
        anyhow::bail!("Nix evaluation failed for field {field_path}: {err}");
    }

    Ok(String::from_utf8_lossy(&output.stdout).trim().to_string())
}

pub fn resolve_source_disk(album_info: &AlbumInfo, base_dir: &Path, config: &AppConfig) -> PathBuf {
    if !album_info.source_disk_path.is_empty() && album_info.source_disk_path != "." {
        let p = &album_info.source_disk_path;
        if p.starts_with("./") {
            base_dir.join(p.trim_start_matches("./"))
        } else if p.starts_with('/') {
            PathBuf::from(p)
        } else {
            base_dir.join(p)
        }
    } else {
        let store_root = config.nix.as_ref().map_or_else(
            || base_dir.join(".vellum/store"),
            |n| libvellum::utils::expand_path(&n.store),
        );

        let truncated = get_nix32_truncate(&album_info.torrent_hash);
        let sanitized_pname = album_info.pname.replace('"', "").trim().replace(' ', "-");
        let link_name = format!("{sanitized_pname}-{truncated}");

        let gc_root = store_root.join("gcroots").join("source").join(&link_name);
        if gc_root.exists() {
            return gc_root;
        }

        let stage_root = config.nix.as_ref()
            .and_then(|n| n.stage.clone())
            .map_or_else(|| base_dir.join(".vellum/stage"), |s| libvellum::utils::expand_path(&s));

        stage_root.join(link_name)
    }
}

pub fn resolve_template(template: &str, vars: &std::collections::HashMap) -> String {
    let re = regex::Regex::new(r"\$\{([^\}]+)\}").unwrap();

    let mut result = template.to_string();
    for caps in re.captures_iter(template) {
        let key = &caps[1];
        if let Some(val) = vars.get(key) {
            result = result.replace(&caps[0], val);
        }
    }
    result
}

pub fn parse_album_nix(path: &Path) -> Result {
    let abs_path = path.canonicalize().context("Failed to canonicalize album.nix path")?;

    let pname = eval_nix_field(&abs_path, "pname")?;
    let source_disk_path = eval_nix_field(&abs_path, "sourceDisk.path")?;
    let source_disk_hash = eval_nix_field(&abs_path, "sourceDisk.hash")?;
    let torrent_file = eval_nix_field(&abs_path, "sourceTorrent.file")?;
    let torrent_hash = eval_nix_field(&abs_path, "sourceTorrent.hash")?;

    Ok(AlbumInfo { 
        pname: if pname.is_empty() { "unknown".to_string() } else { pname },
        source_disk_path, 
        source_disk_hash, 
        torrent_file, 
        torrent_hash 
    })
}

pub fn run(album_path: Option) -> Result<()> {
    let (config, _, _) = AppConfig::load().context("Failed to load config")?;
    let nix_config = config.nix.as_ref().context("Missing [nix] configuration")?;
    let cmds = nix_config.commands.as_ref().context("Missing [nix.commands] configuration")?;

    let target_path = if let Some(a) = album_path {
        let p = expand_path(&a)
            .canonicalize()
            .context("Album path does not exist")?;
        if p.is_dir() && p.join("album.nix").exists() {
            p.join("album.nix")
        } else if p.is_file() && p.file_name().unwrap_or_default() == "album.nix" {
            p
        } else {
            anyhow::bail!("No album.nix found at specified path");
        }
    } else {
        let curr = std::env::current_dir()?;
        if curr.join("album.nix").exists() {
            curr.join("album.nix")
        } else {
            anyhow::bail!("No album.nix found in current directory");
        }
    };

    let album_info = parse_album_nix(&target_path)?;
    let album_dir = target_path.parent().unwrap();

    let torrent_path = album_dir.join(album_info.torrent_file.trim_start_matches("./"));
    if !torrent_path.exists() {
        anyhow::bail!("Torrent file not found: {}", torrent_path.display());
    }

    let output = Command::new("nix")
        .args(["hash", "file", torrent_path.to_str().unwrap()])
        .output()?;
    let current_sha256 = String::from_utf8(output.stdout)?.trim().to_string();

    if current_sha256 != album_info.torrent_hash {
        anyhow::bail!("Torrent file hash mismatch! Expected {}, got {}", album_info.torrent_hash, current_sha256);
    }

    let torrent_file_path = if album_info.torrent_file.starts_with("./") {
        album_dir.join(album_info.torrent_file.trim_start_matches("./"))
    } else {
        album_dir.join(&album_info.torrent_file)
    };

    let source_disk = resolve_source_disk(&album_info, album_dir, &config);

    let torrent_name = Torrent::read_from_file(&torrent_file_path)
        .map_or_else(|_| album_info.pname.clone(), |t| t.name);

    let mut vars = std::collections::HashMap::new();
    vars.insert("sourceDisk.path".to_string(), source_disk.to_string_lossy().to_string());
    vars.insert("sourceTorrent.file".to_string(), torrent_file_path.to_string_lossy().to_string());
    vars.insert("sourceTorrent.hash".to_string(), album_info.torrent_hash);
    vars.insert("sourceTorrent.name".to_string(), torrent_name);

    let cmd_tpl = cmds.get("get_torrent").context("No 'get_torrent' command configured")?;
    let final_cmd = resolve_template(cmd_tpl, &vars);

    log::info!("Executing: {final_cmd}");
    let status = std::process::Command::new("sh").arg("-c").arg(&final_cmd).status()?;

    if status.success() {
        log::info!("Download initiated to {}", source_disk.display());
    } else {
        log::error!("Command failed with status: {status}");
    }

    Ok(())
}



use anyhow::{Context, Result};
use globset::{Glob, GlobSet, GlobSetBuilder};

pub fn build_globset(filter: &str) -> Result {
    let mut builder = GlobSetBuilder::new();

    for part in filter.split(',') {
        let trimmed = part.trim();
        if trimmed.is_empty() {
            continue;
        }

        let pattern = if !trimmed.contains('/') && !trimmed.contains('*') && !trimmed.contains('?') {
            let ext = trimmed.trim_start_matches('.');
            format!("**/*.{ext}")
        } else {
            trimmed.to_string()
        };

        builder.add(
            Glob::new(&pattern)
                .with_context(|| format!("Invalid glob pattern: {pattern}"))?
        );
    }

    builder.build().context("Failed to build GlobSet")
}



pub mod globbing;

use anyhow::Result;
use lava_torrent::torrent::v1::Torrent;
use std::fmt::Write;
use std::path::Path;

pub fn run(torrent_path_str: &str, tracks_filter: &str) -> Result<()> {
    let torrent_path = Path::new(torrent_path_str).canonicalize()?;
    let current_dir = std::env::current_dir()?;

    let output = std::process::Command::new("nix")
        .args(["hash", "file", torrent_path.to_str().unwrap()])
        .output()?;

    if !output.status.success() {
        anyhow::bail!("Failed to hash torrent file with nix");
    }

    let torrent_hash = String::from_utf8(output.stdout)?.trim().to_string();
    let torrent = Torrent::read_from_file(&torrent_path)
        .map_err(|e| anyhow::anyhow!("Failed to parse torrent: {e}"))?;

    let globset = globbing::build_globset(tracks_filter)?;

    let mut valid_paths = Vec::new();

    if let Some(files) = &torrent.files {
        for f in files {
            let path_buf = f.path.clone();
            let path_str = path_buf.to_string_lossy();
            if globset.is_match(path_str.as_ref()) {
                valid_paths.push(path_buf);
            }
        }
    } else {
        let name_str = &torrent.name;
        if globset.is_match(name_str) {
            let path = Path::new(name_str);
            valid_paths.push(path.to_path_buf());
        }
    }

    valid_paths.sort_by(|a, b| alphanumeric_sort::compare_path(a, b));

    let mut track_lines = Vec::new();
    let mut track_no = 1;

    if torrent.files.is_some() {
        for path_buf in valid_paths {
            let inner_path_str = path_buf.to_string_lossy();
            let file_path = format!("{}/{}", torrent.name, inner_path_str);
            let title = path_buf.file_stem().unwrap_or_default().to_string_lossy().replace('"', "\\\"");

            track_lines.push(format!(
                "    {{\n      file = \"{file_path}\";\n      metadata = {{\n        tracknumber = {track_no};\n        title = \"{title}\";\n      }};\n    }}"
            ));
            track_no += 1;
        }
    } else {
        for path_buf in valid_paths {
            let file_path = path_buf.to_string_lossy();
            let title = path_buf.file_stem().unwrap_or_default().to_string_lossy().replace('"', "\\\"");

            track_lines.push(format!(
                "    {{\n      file = \"{file_path}\";\n      metadata = {{\n        tracknumber = {track_no};\n        title = \"{title}\";\n      }};\n    }}"
            ));
            track_no += 1;
        }
    }

    let rel_torrent = torrent_path
        .strip_prefix(&current_dir)
        .map_or_else(|_| torrent_path.clone(), Path::to_path_buf);

    let torrent_nix_path = if rel_torrent.is_absolute() {
        rel_torrent.to_string_lossy().into_owned()
    } else {
        format!("./{}", rel_torrent.to_string_lossy())
    };

    let sanitized_pname = torrent.name.replace(' ', "-").replace(['(', ')', '[', ']', '_'], "-").to_lowercase();

    let mut out = String::new();
    out.push_str("{ vellum }:\n\n");
    out.push_str("vellum.mkAlbum {\n\n");
    let _ = writeln!(out, "  pname = \"{sanitized_pname}\";\n");
    out.push_str("  sourceTorrent = {\n");
    let _ = writeln!(out, "    file = {torrent_nix_path};");
    let _ = writeln!(out, "    hash = \"{torrent_hash}\";");
    out.push_str("  };\n\n");
    out.push_str("  sourceDisk.hash = \"sha256-AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=\";\n\n");
    out.push_str("  album = {\n");
    out.push_str("    metadata = {\n");
    out.push_str("      albumartist = \"\";\n");
    let _ = writeln!(out, "      album = \"{}\";", torrent.name.replace('\"', "\\\""));
    out.push_str("      date = \"\";\n");
    out.push_str("      genre = \"\";\n");
    out.push_str("    };\n");
    out.push_str("  };\n\n");
    out.push_str("  cover = ./cover.png;\n\n");
    out.push_str("  tracks = [\n");
    for (i, line) in track_lines.iter().enumerate() {
        out.push_str(line);
        if i < track_lines.len() - 1 {
            out.push('\n');
        }
    }
    out.push_str("\n  ];\n");
    out.push_str("}\n");

    println!("{out}");
    Ok(())
}



