use anyhow::{Context, Result};
use libvellum::config::AppConfig;
use libvellum::utils::expand_path;

pub struct QueryFlags {
    pub playing: bool,
    pub toml: bool,
    pub lock: bool,
    pub raw: bool,
    pub id: bool,
}

pub async fn run(query_str: Option, flags: QueryFlags) -> Result<()> {
    let (config, _, _): (AppConfig, toml::Value, std::path::PathBuf) = AppConfig::load().context("Failed to load config")?;
    let lib_root = expand_path(&config.storage.library_root)
        .canonicalize()
        .unwrap_or_else(|_| expand_path(&config.storage.library_root));

    let mut target_ids = Vec::new();

    if let Some(q) = query_str {
        let q_trim = q.trim();
        let full_sql = if q_trim.is_empty() {
            "SELECT id FROM albums".to_string()
        } else {
            let upper_q = q_trim.to_uppercase();
            if upper_q.starts_with("SELECT") {
                q_trim.to_string()
            } else {
                let prefix = if upper_q.starts_with("WHERE")
                    || upper_q.starts_with("ORDER")
                    || upper_q.starts_with("LIMIT")
                {
                    "SELECT id FROM albums "
                } else {
                    "SELECT id FROM albums WHERE "
                };
                format!("{prefix}{q_trim}")
            }
        };

        let client = reqwest::Client::new();
        let res = client
            .post("http://127.0.0.1:8000/api/internal/query")
            .json(&serde_json::json!({ "query": full_sql }))
            .send()
            .await
            .context("Failed to connect to the Vellum server. Is it running?")?;

        if !res.status().is_success() {
            let err_text = res.text().await.unwrap_or_default();
            anyhow::bail!("Server rejected query: {err_text}");
        }

        let ids: Vec = res.json().await.context("Invalid response from server")?;
        target_ids = ids;
    } else if flags.playing {
        let playing_path = crate::run::get_playing_album(&config.storage.library_root).await?;
        let rel_path = playing_path.strip_prefix(&lib_root).map_or_else(|_| playing_path.to_string_lossy().to_string(), |p| p.to_string_lossy().to_string());
        target_ids.push(rel_path);
    } else {
        anyhow::bail!("No query provided. Use --playing or provide an SQL query.");
    }

    for id in target_ids {
        if flags.raw {
            let lock_file_path = lib_root.join(&id).join("metadata.lock.json");
            if let Ok(content) = std::fs::read_to_string(&lock_file_path) {
                println!("{content}");
            }
        } else if flags.id {
            println!("{id}");
        } else {
            let base_path = lib_root.join(&id);
            let final_path = if flags.toml {
                base_path.join("metadata.toml")
            } else if flags.lock {
                base_path.join("metadata.lock.json")
            } else {
                base_path
            };
            println!("{}", final_path.display());
        }
    }

    Ok(())
}



use anyhow::{Context, Result};
use libvellum::config::AppConfig;
use crate::compile::builder::assets::COVER_CANDIDATES;
use crate::compile::resolvers::cover_palette;
use std::path::Path;
use serde_json::json;

pub fn run(config: &AppConfig, target_album: &Path) -> Result<()> {
    let mut cover_path = None;
    for c in COVER_CANDIDATES {
        let p = target_album.join(c);
        if p.exists() {
            cover_path = Some(p);
            break;
        }
    }

    let Some(cp) = cover_path else {
        anyhow::bail!("No cover image found in {}", target_album.display());
    };

    let img = image::open(&cp).context("Failed to open cover image")?;

    let default_cfg = json!({
        "type": "kmeansnv",
        "sort": "gradient",
        "args": "k=24,n=6,d=0.2",
        "threshold": 0.02
    });

    let cfg = config
        .compiler
        .as_ref()
        .and_then(|c| c.cover_palette.clone())
        .map(|p| serde_json::to_value(p).unwrap_or_else(|_| default_cfg.clone()))
        .unwrap_or(default_cfg);

    let palette = cover_palette::process_image_to_palette(&img, &cfg, Vec::new(), false)
        .context("Failed to extract palette")?;

    println!("[album]\n");
    println!("cover_palette = [");
    for (srgb, _) in palette {
        let r = (srgb.red.clamp(0.0, 1.0) * 255.0).round() as u8;
        let g = (srgb.green.clamp(0.0, 1.0) * 255.0).round() as u8;
        let b = (srgb.blue.clamp(0.0, 1.0) * 255.0).round() as u8;
        println!("  \"#{r:02X}{g:02X}{b:02X}\",");
    }
    println!("]");

    Ok(())
}



use libvellum::config::AppConfig;
use anyhow::{Context, Result};
use std::collections::HashMap;
use std::path::Path;
use std::process::Command;

pub async fn run(
    config: &AppConfig,
    target_album: &Path,
    env_vars: &HashMap,
) -> Result<()> {
    let script_path_str = config
        .run
        .as_ref()
        .and_then(|r: &HashMap| r.get("get-lyrics"))
        .cloned()
        .unwrap_or_else(|| "python/loose_scripts/fetch_lyrics.py".to_string());

    log::info!("Running get-lyrics on {}", target_album.display());

    let status = Command::new("python")
        .envs(env_vars)
        .arg(&script_path_str)
        .arg(target_album)
        .status()
        .context("Failed to execute get-lyrics script")?;

    if status.success() {
        log::info!("get-lyrics completed successfully. Triggering library update...");
        crate::update::run(Some(target_album.to_path_buf()), false, None, false, false).await?;
    } else {
        log::error!("get-lyrics script failed with status: {status}");
    }

    Ok(())
}



pub mod get_cover_palette;
pub mod get_lyrics;

use libvellum::config::AppConfig;
use libvellum::utils::expand_path;
use anyhow::{Context, Result};
use mpd_client::Client;
use std::collections::HashMap;
use std::path::PathBuf;
use tokio::net::TcpStream;

pub async fn execute(cmd: String, path_arg: Option, playing: bool, id_arg: Option) -> Result<()> {
    let (config, _, _): (AppConfig, toml::Value, PathBuf) = AppConfig::load().context("Failed to load config")?;

    let mut env_vars = HashMap::new();
    if let Some(env_path) = &config.storage.environment {
        let expanded = expand_path(env_path);
        if let Ok(content) = std::fs::read_to_string(&expanded) {
            for line in content.lines() {
                let line = line.trim();
                if line.is_empty() || line.starts_with('#') {
                    continue;
                }
                if let Some((k, v)) = line.split_once('=') {
                    env_vars.insert(
                        k.trim().to_string(),
                        v.trim().trim_matches(|c| c == '"' || c == '\'').to_string(),
                    );
                }
            }
        }
    }

    let target_album = if playing {
        get_playing_album(&config.storage.library_root).await?
    } else if let Some(id) = id_arg {
        expand_path(&config.storage.library_root).join(id)
    } else if let Some(p) = path_arg {
        expand_path(&p).canonicalize().unwrap_or_else(|_| expand_path(&p))
    } else {
        get_playing_album(&config.storage.library_root).await?
    };

    env_vars.insert(
        "ALBUM_PATH".to_string(),
        target_album.to_string_lossy().to_string(),
    );

    match cmd.as_str() {
        "get-cover-palette" => get_cover_palette::run(&config, &target_album),
        "get-lyrics" => get_lyrics::run(&config, &target_album, &env_vars).await,
        _ => {
            if let Some(script_path) = config.run.as_ref().and_then(|r: &HashMap| r.get(&cmd)) {
                log::info!("Running script '{}' on {}", cmd, target_album.display());
                let status = std::process::Command::new("python")
                    .envs(&env_vars)
                    .arg(script_path)
                    .arg(&target_album)
                    .status()
                    .context("Failed to execute script")?;

                if status.success() {
                    log::info!("Script completed successfully. Triggering library update...");
                    crate::update::run(Some(target_album), false, None, false, false).await?;
                } else {
                    log::error!("Script failed with status: {status}");
                }
                Ok(())
            } else {
                anyhow::bail!("Unknown command and no script configured for '{cmd}'");
            }
        }
    }
}

pub async fn get_playing_album(lib_root: &str) -> Result {
    let host = std::env::var("MPD_HOST").unwrap_or_else(|_| "127.0.0.1".to_string());
    let port = std::env::var("MPD_PORT").unwrap_or_else(|_| "6600".to_string());
    let addr = format!("{host}:{port}");

    let stream = TcpStream::connect(&addr)
        .await
        .context("Failed to connect to MPD")?;
    let (client, _) = Client::connect(stream)
        .await
        .context("Failed to initialize MPD client")?;

    let current_song = client.command(mpd_client::commands::CurrentSong).await?;
    let song = current_song.context("No song is currently playing")?;

    let rel_path = song.song.url;
    let root = expand_path(lib_root);
    let full_path = root.join(rel_path);

    let album_dir = full_path
        .parent()
        .context("Invalid track path")?
        .to_path_buf();

    Ok(album_dir)
}



use crate::compile::builder::assets::generate_master_blob;
use crate::server::state::AppState;
use axum::extract::{Path, State};
use axum::http::{HeaderValue, StatusCode, header};
use axum::response::{IntoResponse, Response};
use fast_image_resize::images::Image;
use fast_image_resize::{FilterType, ResizeAlg, ResizeOptions, Resizer};
use fast_image_resize::PixelType;
use std::path::PathBuf;
use std::sync::Arc;
use tokio::fs::File;
use tokio::io::AsyncReadExt;

pub async fn get_resized_cover(
    Path((width_str, hash)): Path<(String, String)>,
    State(state): State<Arc>,
) -> Response {
    let width = width_str
        .strip_suffix("px")
        .unwrap_or(&width_str)
        .parse::()
        .unwrap_or(200)
        .clamp(16, 2048);

    let (cache_root, library_root) = {
        let guard = state.config.read().await;
        (guard.cache_root.clone(), guard.library_root.clone())
    };

    let master_blob_path = cache_root.join("covers").join(format!("{hash}.bmp"));

    if !master_blob_path.exists() {
        let source_info = {
            let query = state.query.lock().await;
            query.dict.values().find(|v| {
                v.get("cover_hash").and_then(|h| h.as_str()) == Some(&hash)
            }).map(|v| {
                (
                    v.get("id").and_then(|i| i.as_str()).unwrap_or("").to_string(),
                    v.get("cover_path").and_then(|p| p.as_str()).unwrap_or("cover.jpg").to_string()
                )
            })
        };

        if let Some((album_id, cover_path)) = source_info {
            let original_path = library_root.join(album_id).join(cover_path);
            let blob_path_clone = master_blob_path.clone();

            let gen_result = tokio::task::spawn_blocking(move || {
                generate_master_blob(&original_path, &blob_path_clone)
            }).await;

            if gen_result.is_err() || gen_result.unwrap().is_err() {
                return StatusCode::NOT_FOUND.into_response();
            }
        } else {
            return StatusCode::NOT_FOUND.into_response();
        }
    }

    let result = tokio::task::spawn_blocking(move || {
        let img = image::open(&master_blob_path).ok()?.into_rgb8();
        let src_width = img.width();
        let src_height = img.height();
        let min_dim = std::cmp::min(src_width, src_height);

        let src_image = Image::from_vec_u8(src_width, src_height, img.into_raw(), PixelType::U8x3).ok()?;
        let mut dst_image = Image::new(width, width, PixelType::U8x3);
        let mut resizer = Resizer::new();
        let options = ResizeOptions::new()
            .crop(
                f64::from((src_width - min_dim) / 2),
                f64::from((src_height - min_dim) / 2),
                f64::from(min_dim),
                f64::from(min_dim),
            )
            .resize_alg(ResizeAlg::Convolution(FilterType::Mitchell));

        resizer.resize(&src_image, &mut dst_image, &options).ok()?;

        let mut buf = Vec::new();
        let img_buffer = image::RgbImage::from_raw(width, width, dst_image.into_vec())?;
        let mut cursor = std::io::Cursor::new(&mut buf);
        img_buffer.write_to(&mut cursor, image::ImageFormat::Png).ok()?;

        Some(buf)
    }).await;

    match result {
        Ok(Some(buf)) => {
            ([
                (header::CONTENT_TYPE, HeaderValue::from_static("image/png")),
                (header::CACHE_CONTROL, HeaderValue::from_static("public, max-age=86400")),
                (header::ACCESS_CONTROL_ALLOW_ORIGIN, HeaderValue::from_static("*")),
            ], buf).into_response()
        },
        _ => StatusCode::INTERNAL_SERVER_ERROR.into_response()
    }
}

pub async fn get_cover_thumbnail(
    Path((size, hash)): Path<(String, String)>,
    State(state): State<Arc>,
) -> Response {
    let root = {
        let guard = state.config.read().await;
        guard.cache_root.clone()
    };

    let path = root.join("thumbnails").join(&size).join(format!("{hash}.png"));

    match serve_image(path.clone(), true).await {
        resp if resp.status() == StatusCode::OK => resp,
        _ => {
            log::error!("FS 404: File not found at -> {}", path.display());
            StatusCode::NOT_FOUND.into_response()
        }
    }
}

pub async fn get_album_metadata(
    Path(id): Path,
    State(state): State<Arc>,
) -> Response {
    let json_str = {
        let query = state.query.lock().await;
        query.get_album_json(&id)
    };
    if let Some(data) = json_str {
        return ([(header::CONTENT_TYPE, "application/json")],
            data
        ).into_response();
    }
    StatusCode::NOT_FOUND.into_response()
}

pub async fn get_album_cover(
    Path(id): Path,
    State(state): State<Arc>,
) -> Response {
    let path_opt = {
        let query = state.query.lock().await;
        let config_guard = state.config.read().await;

        query.dict.get(&id).map(|meta| {
            let cp = meta.get("cover_path").and_then(|v| v.as_str()).unwrap_or("default_cover.png");
            config_guard.library_root.join(&id).join(cp)
        })
    };

    if let Some(path) = path_opt {
        return serve_image(path, false).await;
    }
    StatusCode::NOT_FOUND.into_response()
}

pub async fn get_lyrics(
    Path((id, path)): Path<(String, String)>,
    State(state): State<Arc>,
) -> Response {
    let full_path = {
        let config_guard = state.config.read().await;
        config_guard.library_root.join(&id).join(&path)
    };

    if full_path.exists()
        && full_path.is_file()
        && let Ok(mut file) = File::open(&full_path).await
    {
        let mut buf = String::new();
        if file.read_to_string(&mut buf).await.is_ok() {
            return ([
                    (
                        header::CONTENT_TYPE,
                        HeaderValue::from_static("text/plain; charset=utf-8"),
                    ),
                    (header::CACHE_CONTROL, HeaderValue::from_static("no-cache")),
                ],
                buf,
            )
                .into_response();
        }
    }

    StatusCode::NOT_FOUND.into_response()
}

pub async fn get_custom_shader(State(state): State<Arc>) -> Response {
    let path_opt = {
        let guard = state.config.read().await;
        guard.resolved_shader_path.clone()
    };

    if let Some(path) = path_opt
        && let Ok(mut file) = File::open(&path).await {
            let mut buf = String::new();
            if file.read_to_string(&mut buf).await.is_ok() {
                return ([
                        (
                            header::CONTENT_TYPE,
                            HeaderValue::from_static("text/x-glsl; charset=utf-8"),
                        ),
                        (header::CACHE_CONTROL, HeaderValue::from_static("no-cache")),
                    ],
                    buf,
                )
                    .into_response();
            }
        }

    StatusCode::NOT_FOUND.into_response()
}

pub async fn get_custom_css(State(state): State<Arc>) -> Response {
    let path_opt = {
        let guard = state.config.read().await;
        guard.resolved_css_path.clone()
    };

    if let Some(path) = path_opt
        && let Ok(mut file) = File::open(&path).await {
            let mut buf = String::new();
            if file.read_to_string(&mut buf).await.is_ok() {
                return ([
                        (
                            header::CONTENT_TYPE,
                            HeaderValue::from_static("text/css; charset=utf-8"),
                        ),
                        (header::CACHE_CONTROL, HeaderValue::from_static("no-cache")),
                    ],
                    buf,
                )
                    .into_response();
            }
        }

    StatusCode::NOT_FOUND.into_response()
}

async fn serve_image(path: PathBuf, is_immutable: bool) -> Response {
    if let Ok(mut file) = File::open(&path).await {
        let mut buf = Vec::new();
        if file.read_to_end(&mut buf).await.is_ok() {
            let mime = if path.extension().is_some_and(|e| e == "png") {
                "image/png"
            } else {
                "image/jpeg"
            };

            let cache_header = if is_immutable {
                HeaderValue::from_static("public, max-age=31536000, immutable")
            } else {
                HeaderValue::from_static("public, max-age=86400")
            };

            return ([
                    (header::CONTENT_TYPE, HeaderValue::from_static(mime)),
                    (header::CACHE_CONTROL, cache_header),
                    (
                        header::ACCESS_CONTROL_ALLOW_ORIGIN,
                        HeaderValue::from_static("*"),
                    ),
                ],
                buf,
            )
                .into_response();
        }
    }
    StatusCode::NOT_FOUND.into_response()
}



pub mod assets;
pub mod playback;
pub mod system;
pub mod websocket;

use crate::server::state::AppState;
use axum::{
    Router,
    routing::{get, post},
};
use std::sync::Arc;

pub fn router(state: Arc) -> Router {
    Router::new()
        .route("/ws", get(websocket::ws_handler))
        .route("/api/state", post(system::update_state))
        .route("/api/internal/notify_force_update", post(system::notify_force_update))
        .route("/api/internal/reset", post(system::trigger_full_reset))
        .route("/api/internal/reload", post(system::trigger_reload))
        .route("/api/internal/batch_reload", post(system::trigger_batch_reload))
        .route("/api/internal/query", post(system::run_query))
        .route(
            "/api/covers/{size}/{hash}",
            get(assets::get_cover_thumbnail),
        )
        .route("/api/resize/{width}/{hash}", get(assets::get_resized_cover))
        .route("/api/album/{*id}", get(assets::get_album_metadata))
        .route("/api/assets/cover/{*id}", get(assets::get_album_cover))
        .route("/api/assets/lyrics/{id}/{*path}", get(assets::get_lyrics))
        .route("/api/theme/shader", get(assets::get_custom_shader))
        .route("/api/theme/css", get(assets::get_custom_css))
        .route("/api/play/{*id}", post(playback::play_album))
        .route("/api/play-disc/{*id}", post(playback::play_disc))
        .route("/api/queue/{*id}", post(playback::queue_album))
        .route("/api/jump/{index}", post(playback::jump_to_index))
        .route("/api/next", post(playback::next_track))
        .route("/api/prev", post(playback::prev_track))
        .route("/api/stop", post(playback::stop_playback))
        .route("/api/clear", post(playback::clear_queue))
        .route("/api/toggle-pause", post(playback::toggle_pause))
        .route("/api/open/{*id}", post(system::open_album_folder))
        .route("/api/open-lock/{*id}", post(system::open_lock_file))
        .route("/api/open-manifest/{*id}", post(system::open_manifest_file))
        .route("/api/update-album/{*id}", post(system::force_update_album))
        .with_state(state)
}



use crate::server::mpd::MpdCommand;
use crate::server::state::AppState;
use axum::Json;
use axum::extract::{Path, Query, State};
use axum::response::{IntoResponse, Response};
use serde_json::{Value, json};
use std::sync::Arc;

pub async fn play_album(
    Path(id): Path,
    State(state): State<Arc>,
    Query(params): Query<std::collections::HashMap>,
) -> Response {
    let offset = params
        .get("offset")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0);
    let tracks = get_tracks_internal(&id, &state, None).await;
    state
        .mpd_engine
        .send(MpdCommand::Play { tracks, offset })
        .await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn play_disc(
    Path(id): Path,
    State(state): State<Arc>,
    Query(params): Query<std::collections::HashMap>,
) -> Response {
    let disc = params.get("disc").cloned();
    let offset = params
        .get("offset")
        .and_then(|s| s.parse().ok())
        .unwrap_or(0);
    let tracks = get_tracks_internal(&id, &state, disc).await;
    state
        .mpd_engine
        .send(MpdCommand::Play { tracks, offset })
        .await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn queue_album(Path(id): Path, State(state): State<Arc>) -> Response {
    let tracks = get_tracks_internal(&id, &state, None).await;
    state.mpd_engine.send(MpdCommand::Queue { tracks }).await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn jump_to_index(
    Path(index): Path,
    State(state): State<Arc>,
) -> Response {
    state.mpd_engine.send(MpdCommand::Jump { index }).await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn next_track(State(state): State<Arc>) -> Response {
    state.mpd_engine.send(MpdCommand::Next).await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn prev_track(State(state): State<Arc>) -> Response {
    state.mpd_engine.send(MpdCommand::Prev).await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn stop_playback(State(state): State<Arc>) -> Response {
    state.mpd_engine.send(MpdCommand::Stop).await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn clear_queue(State(state): State<Arc>) -> Response {
    state.mpd_engine.send(MpdCommand::Clear).await;
    Json(json!({"status": "ok"})).into_response()
}

pub async fn toggle_pause(State(state): State<Arc>) -> Response {
    state.mpd_engine.send(MpdCommand::TogglePause).await;
    Json(json!({"status": "ok"})).into_response()
}

async fn get_tracks_internal(
    id: &str,
    state: &Arc,
    disc_filter: Option,
) -> Vec {
    let mut paths = Vec::new();
    let target_disc = disc_filter.and_then(|s| s.parse::().ok());

    let json_str = {
        let query = state.query.lock().await;
        query.get_album_json(id)
    };

    let library_root = {
        state.config.read().await.library_root.clone()
    };

    if let Some(raw) = json_str
        && let Ok(parsed) = serde_json::from_str::(&raw)
            && let Some(tracks) = parsed.get("tracks").and_then(|t| t.as_array()) {
                for track in tracks {
                    if let Some(td) = target_disc {
                        let current_disc = track.get("discnumber")
                            .and_then(serde_json::Value::as_u64)
                            .map_or(1, |v| u32::try_from(v).unwrap_or(1));
                        if current_disc != td {
                            continue;
                        }
                    }

                    if let Some(info) = track.get("info")
                        && let Some(tp) = info.get("track_library_path").and_then(|v| v.as_str()) {
                            let abs = library_root.join(tp);
                            if let Ok(rel) = abs.strip_prefix(&library_root)
                                && let Some(s) = rel.to_str() {
                                    paths.push(s.to_string());
                                }
                        }
                }
            }
    paths
}



use crate::server::state::AppState;
use axum::Json;
use axum::extract::{Path, Query, State};
use axum::http::StatusCode;
use axum::response::{IntoResponse, Response};
use serde_json::json;
use std::sync::Arc;

pub async fn update_state(
    State(state): State<Arc>,
    Json(payload): Json,
) -> Response {
    let content = {
        let mut ui = state.ui_state.write().await;
        if let Some(obj) = payload.as_object()
            && let Some(ui_obj) = ui.as_object_mut()
        {
            for (k, v) in obj {
                ui_obj.insert(k.clone(), v.clone());
            }
        }
        serde_json::to_string_pretty(&*ui).ok()
    };

    if let Some(data) = content {
        let state_file = {
            let guard = state.config.read().await;
            guard.state_root.join("state.json")
        };
        let _ = tokio::fs::write(state_file, data).await;
    }

    Json(json!({"status": "saved"})).into_response()
}

pub async fn notify_force_update() -> Response {
    log::info!("Force updating library...");
    Json(json!({"status": "ok"})).into_response()
}

pub async fn trigger_full_reset(State(state): State<Arc>) -> Response {
    log::info!("Rebuilding library database...");
    let start_time = std::time::Instant::now();

    let album_count = {
        let library_root = state.config.read().await.library_root.clone();
        let scanner = crate::server::library::scanner::Library::new(library_root);
        let mut query = state.query.lock().await;
        scanner.scan(&mut query);
        query.dict.len()
    };

    let elapsed = start_time.elapsed().as_millis();
    log::info!("Updated {album_count} albums.");
    log::info!("Rebuilt Query Engine in {elapsed}ms.");

    let _ = state.tx.send(json!({"type": "LOGIC_UPDATE"}).to_string());
    Json(json!({"status": "ok"})).into_response()
}

pub async fn trigger_batch_reload(
    State(state): State<Arc>,
    Query(params): Query<std::collections::HashMap>,
    Json(paths): Json<Vec>,
) -> Response {
    let start_time = std::time::Instant::now();
    let compile_time = params.get("time").map_or("0", std::string::String::as_str);

    let library_root = state.config.read().await.library_root.clone();
    let mut processed_ids = Vec::new();
    let mut removed_ids = Vec::new();

    {
        let mut query = state.query.lock().await;
        let scanner = crate::server::library::scanner::Library::new(library_root);
        for path in &paths {
            let res = scanner.update_album(path, &mut query);
            match res {
                crate::server::library::scanner::UpdateResult::Updated(id) => processed_ids.push(id),
                crate::server::library::scanner::UpdateResult::Removed(id) => removed_ids.push(id),
            }
        }
        if !processed_ids.is_empty() || !removed_ids.is_empty() {
            let _ = query.build_cache();
        }
    }

    if !processed_ids.is_empty() || !removed_ids.is_empty() {
        let elapsed = start_time.elapsed().as_millis();
        log::info!("Updated {} albums, Removed {} albums in {}ms.", processed_ids.len(), removed_ids.len(), compile_time);
        log::info!("Rebuilt Query Engine in {elapsed}ms.");

        if processed_ids.len() == 1 && removed_ids.is_empty() {
            let dict_entry = {
                let query = state.query.lock().await;
                query.dict.get(&processed_ids[0]).cloned()
            };
            let _ = state.tx.send(json!({
                "type": "ALBUM_UPDATED",
                "id": processed_ids[0],
                "dictEntry": dict_entry.unwrap_or_else(|| json!({}))
            }).to_string());
        } else if removed_ids.len() == 1 && processed_ids.is_empty() {
            let _ = state.tx.send(json!({
                "type": "ALBUM_REMOVED",
                "id": removed_ids[0]
            }).to_string());
        } else {
            let _ = state.tx.send(json!({"type": "LOGIC_UPDATE"}).to_string());
        }
    }

    Json(processed_ids).into_response()
}

pub async fn trigger_reload(
    State(state): State<Arc>,
    Query(params): Query<std::collections::HashMap>,
) -> Response {
    let start_time = std::time::Instant::now();
    if let Some(path) = params.get("path") {
        let library_root = state.config.read().await.library_root.clone();

        let (update_res, dict_entry) = {
            let mut query = state.query.lock().await;
            let scanner = crate::server::library::scanner::Library::new(library_root);
            let res = scanner.update_album(path, &mut query);

            let entry = match &res {
                crate::server::library::scanner::UpdateResult::Updated(id) => {
                    let _ = query.build_cache();
                    query.dict.get(id).cloned()
                },
                crate::server::library::scanner::UpdateResult::Removed(_) => None,
            };
            (res, entry)
        };

        let elapsed = start_time.elapsed().as_millis();
        log::info!("Processed 1 album.");
        log::info!("Rebuilt Query Engine in {elapsed}ms.");

        match update_res {
            crate::server::library::scanner::UpdateResult::Updated(id) => {
                let _ = state.tx.send(json!({
                    "type": "ALBUM_UPDATED",
                    "id": id,
                    "dictEntry": dict_entry.unwrap_or_else(|| json!({}))
                }).to_string());
            }
            crate::server::library::scanner::UpdateResult::Removed(id) => {
                let _ = state.tx.send(json!({
                    "type": "ALBUM_REMOVED",
                    "id": id
                }).to_string());
            }
        }

        return Json(json!({"status": "ok"})).into_response();
    }
    StatusCode::NOT_FOUND.into_response()
}

pub async fn open_album_folder(
    Path(id): Path,
    State(state): State<Arc>,
) -> Response {
    let path = {
        let config_guard = state.config.read().await;
