pub async fn force_update_album(
    Path(id): Path,
    State(state): State<Arc>,
) -> Response {
    let path = {
        let config_guard = state.config.read().await;
        config_guard.library_root.join(id)
    };
    if path.exists() {
        let _ = std::process::Command::new("vellum")
            .arg("update")
            .arg("--force")
            .arg("--silent")
            .arg(path)
            .spawn();
        return Json(json!({"status": "ok"})).into_response();
    }
    StatusCode::NOT_FOUND.into_response()
}

pub async fn run_query(
    State(state): State<Arc>,
    Json(payload): Json,
) -> Response {
    if let Some(query_str) = payload.get("query").and_then(|q| q.as_str()) {
        let expanded = crate::server::query::expand_shorthand(query_str);
        let query = state.query.lock().await;
        match query.query_ids(&expanded) {
            Ok(ids) => return Json(ids).into_response(),
            Err(e) => {
                return (
                    StatusCode::BAD_REQUEST,
                    Json(json!({"error": e.to_string()})),
                )
                    .into_response();
            }
        }
    }
    StatusCode::BAD_REQUEST.into_response()
}



use crate::server::mpd::MpdCommand;
use crate::server::state::AppState;
use ax_ws::WebSocket;
use axum::extract::ws as ax_ws;
use axum::extract::{State, WebSocketUpgrade};
use axum::response::Response;
use serde_json::json;
use std::sync::Arc;

pub async fn ws_handler(ws: WebSocketUpgrade, State(state): State<Arc>) -> Response {
    ws.on_upgrade(|socket| handle_socket(socket, state))
}

async fn handle_socket(mut socket: WebSocket, state: Arc) {
    log::info!("Client connected");

    let init_payload = {
        let (dict, track_map, manifest) = {
            let q = state.query.lock().await;
            (q.dict.clone(), q.track_lookup.clone(), q.manifest.clone())
        };
        let ui_data = state.ui_state.read().await.clone();
        let (thumbnail_size, shader) = {
            let c = state.config.read().await;
            (c.thumbnail_size, c.shader.clone())
        };

        json!({
            "type": "INIT_DICT",
            "dict": dict,
            "trackMap": track_map,
            "manifest": manifest,
            "ui_state": ui_data,
            "config": {
                "thumbnail_size": thumbnail_size,
                "shader": shader
            }
        })
        .to_string()
    };

    if socket
        .send(ax_ws::Message::Text(init_payload.into()))
        .await
        .is_err()
    {
        return;
    }

    state.mpd_engine.send(MpdCommand::Refresh).await;

    let mut rx = state.tx.subscribe();
    loop {
        tokio::select! {
            Some(msg) = socket.recv() => {
                match msg {
                    Ok(ax_ws::Message::Text(text)) => {
                        if let Ok(req) = serde_json::from_str::(&text) {
                            let req_type = req.get("type").and_then(|v| v.as_str()).unwrap_or("");
                            if req_type == "VIEW_REQUEST" {
                                let collection = req.get("collection").and_then(|v| v.as_str()).unwrap_or("library");
                                let sort = req.get("sort").and_then(|v| v.as_str()).unwrap_or("default");
                                let reverse = req.get("reverse").and_then(serde_json::Value::as_bool).unwrap_or(false);
                                let filter_key = req.get("filter").and_then(|v| v.get("key")).and_then(|v| v.as_str());
                                let filter_val = req.get("filter").and_then(|v| v.get("val")).and_then(|v| v.as_str());

                                let ids = state.query.lock().await.request_view(collection, sort, filter_key, filter_val, reverse);
                                let _ = socket.send(ax_ws::Message::Text(json!({ "type": "VIEW_DATA", "ids": ids }).to_string().into())).await;
                            } else if req_type == "SHELF_REQUEST" {
                                let shelf = req.get("shelf").and_then(|v| v.as_str()).unwrap_or("");
                                let ids = state.query.lock().await.request_shelf_view(shelf);
                                let _ = socket.send(ax_ws::Message::Text(json!({ "type": "VIEW_DATA", "ids": ids }).to_string().into())).await;
                            } else if req_type == "GROUP_REQUEST" {
                                let collection = req.get("collection").and_then(|v| v.as_str()).unwrap_or("library");
                                let key = req.get("key").and_then(|v| v.as_str()).unwrap_or("");

                                let result = state.query.lock().await.request_group(collection, key);
                                let _ = socket.send(ax_ws::Message::Text(json!({ "type": "GROUP_RESULT", "key": key, "result": result }).to_string().into())).await;
                            }
                        }
                    }
                    Ok(ax_ws::Message::Close(_)) | Err(_) => {
                        log::info!("Client disconnected");
                        break;
                    }
                    _ => {}
                }
            }
            Ok(msg) = rx.recv() => {
                if socket.send(ax_ws::Message::Text(msg.into())).await.is_err() {
                    break;
                }
            }
        }
    }
}



pub mod scanner;



use libvellum::models::LockFile;
use std::path::{Path, PathBuf};
use walkdir::WalkDir;

pub enum UpdateResult {
    Updated(String),
    Removed(String),
}

pub struct Library {
    pub root: PathBuf,
}

impl Library {
    pub const fn new(root: PathBuf) -> Self {
        Self { root }
    }

    pub fn scan(&self, query_engine: &mut crate::server::query::QueryEngine) {
        log::info!("Scanning Library at {}", self.root.display());

        let entries: Vec = WalkDir::new(&self.root)
            .into_iter()
            .filter_map(Result::ok)
            .filter(|e| e.file_name() == "metadata.lock.json")
            .map(|e| e.path().to_path_buf())
            .collect();

        let _ = query_engine.clear();

        for lock_path in entries {
            if let Ok(content) = std::fs::read_to_string(&lock_path)
                && let Ok(lock_data) = serde_json::from_str::(&content) {
                    let alb_id = lock_data.album.info.album_path;
                    let _ = query_engine.ingest(&alb_id, &content);
                }
        }

        if let Err(e) = query_engine.build_cache() {
            log::error!("Failed to build query cache: {e}");
        }

        log::info!("Library Query Engine Initialized.");
    }

    pub fn update_album(&self, folder_path_str: &str, query_engine: &mut crate::server::query::QueryEngine) -> UpdateResult {
        let folder_path = Path::new(folder_path_str);

        let rel_path = folder_path.strip_prefix(&self.root).unwrap_or(folder_path);
        let alb_id = rel_path.to_string_lossy().to_string();

        let lock_path = folder_path.join("metadata.lock.json");
        if lock_path.exists()
            && let Ok(content) = std::fs::read_to_string(&lock_path)
                && let Ok(lock_data) = serde_json::from_str::(&content) {
                    let parsed_alb_id = lock_data.album.info.album_path;
                    let _ = query_engine.remove_album(&parsed_alb_id);
                    let _ = query_engine.ingest(&parsed_alb_id, &content);
                    return UpdateResult::Updated(parsed_alb_id);
                }

        let _ = query_engine.remove_album(&alb_id);
        UpdateResult::Removed(alb_id)
    }
}



use crate::server::query::QueryEngine;
use crate::server::mpd::commands::{MpdCommand, handle_command};
use crate::server::mpd::status::broadcast_status;
use crate::server::state::AppConfig;
use mpd_client::Client;
use mpd_client::client::{ConnectionEvent, Subsystem};
use std::sync::Arc;
use tokio::net::TcpStream;
use tokio::sync::{Mutex, broadcast, mpsc};

#[derive(Clone)]
pub struct MpdEngine {
    tx: mpsc::Sender,
}

impl MpdEngine {
    pub async fn send(&self, command: MpdCommand) {
        let _ = self.tx.send(command).await;
    }
}

pub fn start_actor(
    broadcast_tx: broadcast::Sender,
    query: Arc<Mutex>,
    _app_config: Arc,
) -> MpdEngine {
    let (tx, mut rx) = mpsc::channel::(32);
    let engine_handle = MpdEngine { tx };

    let mpd_host = std::env::var("MPD_HOST").unwrap_or_else(|_| "127.0.0.1".to_string());
    let mpd_port = std::env::var("MPD_PORT").unwrap_or_else(|_| "6600".to_string());
    let addr = format!("{mpd_host}:{mpd_port}");

    tokio::spawn(async move {
        loop {
            match TcpStream::connect(&addr).await {
                Ok(stream) => match Client::connect(stream).await {
                    Ok((client, mut events)) => {
                        log::info!("MPD Connected: {addr}");

                        let _ = client
                            .command(mpd_client::commands::SetBinaryLimit(131_072))
                            .await;
                        let _ = broadcast_status(&client, &broadcast_tx, &query).await;

                        loop {
                            tokio::select! {
                                Some(event) = events.next() => {
                                    match event {
                                        ConnectionEvent::SubsystemChange(sub) => {
                                            if matches!(
                                                sub,
                                                Subsystem::Player |
                                                Subsystem::Queue |
                                                Subsystem::Options
                                            ) {
                                                let _ = broadcast_status(&client, &broadcast_tx, &query).await;
                                            }
                                        }
                                        ConnectionEvent::ConnectionClosed(e) => {
                                            log::warn!("MPD Connection closed: {e:?}");
                                            break;
                                        }
                                    }
                                }
                                Some(cmd) = rx.recv() => {
                                    if matches!(cmd, MpdCommand::Refresh) {
                                        let _ = broadcast_status(&client, &broadcast_tx, &query).await;
                                    } else {
                                        if let Err(e) = handle_command(&client, cmd).await {
                                            log::error!("MPD Execution Error: {e}");
                                        }
                                        let _ = broadcast_status(&client, &broadcast_tx, &query).await;
                                    }
                                }
                            }
                        }
                    }
                    Err(e) => {
                        log::error!("MPD Handshake Failed: {e}");
                    }
                },
                Err(e) => {
                    log::error!("MPD Connection Failed: {e}");
                }
            }
            tokio::time::sleep(std::time::Duration::from_secs(2)).await;
        }
    });

    engine_handle
}



use anyhow::Result;
use mpd_client::Client;
use mpd_client::commands::{
    Add, Command, Next, Play, Previous, SetPause, SongPosition, Status, Stop,
};
use mpd_client::protocol::command::{Command as RawCommand, CommandList as RawCommandList};
use mpd_client::responses::PlayState;

pub enum MpdCommand {
    Play { tracks: Vec, offset: usize },
    Queue { tracks: Vec },
    Jump { index: usize },
    Clear,
    Stop,
    Next,
    Prev,
    TogglePause,
    Refresh,
}

pub async fn handle_command(client: &Client, cmd: MpdCommand) -> Result<()> {
    match cmd {
        MpdCommand::Play { tracks, offset } => {
            let mut list = RawCommandList::new(RawCommand::new("clear"));
            for track in &tracks {
                list.add(Add::uri(track).command());
            }
            list.add(Play::song(SongPosition(offset)).command());
            client.raw_command_list(list).await?;
        }
        MpdCommand::Queue { tracks } => {
            if let Some((first, rest)) = tracks.split_first() {
                let mut list = RawCommandList::new(Add::uri(first).command());
                for track in rest {
                    list.add(Add::uri(track).command());
                }
                client.raw_command_list(list).await?;
            }
        }
        MpdCommand::Jump { index } => {
            client.command(Play::song(SongPosition(index))).await?;
        }
        MpdCommand::Clear => {
            client.raw_command(RawCommand::new("clear")).await?;
        }
        MpdCommand::Stop => {
            client.command(Stop).await?;
        }
        MpdCommand::Next => {
            client.command(Next).await?;
        }
        MpdCommand::Prev => {
            client.command(Previous).await?;
        }
        MpdCommand::TogglePause => {
            let status = client.command(Status).await?;
            match status.state {
                PlayState::Playing => {
                    client.command(SetPause(true)).await?;
                }
                PlayState::Paused => {
                    client.command(SetPause(false)).await?;
                }
                PlayState::Stopped => {
                    client.command(Play::current()).await?;
                }
            }
        }
        MpdCommand::Refresh => {}
    }
    Ok(())
}



