use anyhow::Result;
use indexmap::IndexMap;
use rusqlite::Connection;
use serde::{Deserialize, Serialize};
use serde_json::{Value, json};
use std::collections::{HashMap, HashSet};
use std::path::Path;

pub use libvellum::sql::expand_shorthand;

#[derive(Deserialize, Serialize, Clone, Debug)]
pub struct LogicManifest {
    pub groupers: IndexMap,
    pub sorters: IndexMap,
    pub collections: IndexMap,
    #[serde(default)]
    pub shelves: IndexMap,
    #[serde(skip_deserializing, default)]
    pub groupers_order: Vec,
    #[serde(skip_deserializing, default)]
    pub sorters_order: Vec,
    #[serde(skip_deserializing, default)]
    pub collections_order: Vec,
    #[serde(skip_deserializing, default)]
    pub shelves_order: Vec,
}

impl LogicManifest {
    pub fn normalize(&mut self) {
        self.groupers_order = self.groupers.keys().cloned().collect();
        self.sorters_order = self.sorters.keys().cloned().collect();
        self.collections_order = self.collections.keys().cloned().collect();
        self.shelves_order = self.shelves.keys().cloned().collect();

        for (_, g) in &mut self.groupers {
            let idx = g.index.unwrap_or(false);
            g.index = Some(idx);
            if g.count.is_none() {
                g.count = Some(!idx);
            }
        }

        let global_groupers: HashSet = self.groupers.iter()
            .filter(|(_, g)| !g.strict)
            .map(|(id, _)| id.clone())
            .collect();

        let global_sorters: HashSet = self.sorters.iter()
            .filter(|(_, s)| !s.strict)
            .map(|(id, _)| id.clone())
            .collect();

        for (_, collection) in &mut self.collections {
            let mut allowed_grouper_ids = HashSet::new();
            for g in &collection.groupers {
                allowed_grouper_ids.insert(g.clone());
            }
            if !collection.strict {
                for g in &global_groupers {
                    allowed_grouper_ids.insert(g.clone());
                }
            }

            let mut allowed_sorter_ids = HashSet::new();
            for s in &collection.sorters {
                allowed_sorter_ids.insert(s.clone());
            }
            if !collection.strict {
                for s in &global_sorters {
                    allowed_sorter_ids.insert(s.clone());
                }
            }

            collection.allowed_groupers = self.groupers.keys()
                .filter(|k| allowed_grouper_ids.contains(*k))
                .cloned()
                .collect();

            collection.allowed_sorters = self.sorters.keys()
                .filter(|k| allowed_sorter_ids.contains(*k))
                .cloned()
                .collect();
        }
    }
}

#[derive(Deserialize, Serialize, Clone, Debug)]
pub struct GrouperDef {
    pub label: String,
    pub select: String,
    #[serde(default)]
    pub strict: bool,
    #[serde(default)]
    pub index: Option,
    #[serde(default)]
    pub count: Option,
}

#[derive(Deserialize, Serialize, Clone, Debug)]
pub struct SorterDef {
    pub label: String,
    pub order_by: String,
    #[serde(default)]
    pub strict: bool,
}

#[derive(Deserialize, Serialize, Clone, Debug)]
pub struct CollectionDef {
    pub label: String,
    pub filter: String,
    #[serde(default)]
    pub strict: bool,
    #[serde(default)]
    pub groupers: Vec,
    #[serde(default)]
    pub sorters: Vec,
    #[serde(skip_deserializing)]
    pub allowed_groupers: Vec,
    #[serde(skip_deserializing)]
    pub allowed_sorters: Vec,
}

#[derive(Deserialize, Serialize, Clone, Debug)]
pub struct ShelfDef {
    pub label: String,
    pub filter: Option,
    pub order_by: Option,
    pub file: Option,
}

pub struct QueryEngine {
    conn: Connection,
    pub manifest: LogicManifest,
    collections_cache: HashMap<String, HashSet>,
    facets_cache: HashMap<String, HashMap<String, HashSet>>,
    sorters_cache: HashMap<String, Vec>,
    shelves_cache: HashMap<String, Vec>,
    uid_to_id: HashMap,
    pub dict: HashMap,
    pub track_lookup: HashMap,
    pub path_lookup: HashMap,
}

const DEFAULT_LOGIC: &str = include_str!("logic.toml");

impl QueryEngine {
    pub fn new() -> Result {
        let logic_path = crate::expand_path("~/.config/vellum/logic.toml");
        if !logic_path.exists() {
            std::fs::write(&logic_path, DEFAULT_LOGIC)?;
        }

        let logic_content = std::fs::read_to_string(&logic_path)?;
        let mut manifest: LogicManifest = toml::from_str(&logic_content)?;
        manifest.normalize();

        let conn = Connection::open_in_memory()?;
        conn.execute(
            "CREATE TABLE albums (
                uid INTEGER PRIMARY KEY AUTOINCREMENT,
                id TEXT UNIQUE,
                metadata TEXT
            )",[],
        )?;

        Ok(Self {
            conn,
            manifest,
            collections_cache: HashMap::new(),
            facets_cache: HashMap::new(),
            sorters_cache: HashMap::new(),
            shelves_cache: HashMap::new(),
            uid_to_id: HashMap::new(),
            dict: HashMap::new(),
            track_lookup: HashMap::new(),
            path_lookup: HashMap::new(),
        })
    }

    pub fn reload_manifest(&mut self, path: &Path) -> Result<()> {
        let logic_content = std::fs::read_to_string(path)?;
        let mut manifest: LogicManifest = toml::from_str(&logic_content)?;
        manifest.normalize();
        self.manifest = manifest;
        self.build_cache()?;
        Ok(())
    }

    pub fn clear(&mut self) -> Result<()> {
        self.conn.execute("DELETE FROM albums",[])?;
        self.collections_cache.clear();
        self.facets_cache.clear();
        self.sorters_cache.clear();
        self.shelves_cache.clear();
        self.uid_to_id.clear();
        self.dict.clear();
        self.track_lookup.clear();
        self.path_lookup.clear();
        Ok(())
    }

    pub fn remove_album(&mut self, id: &str) -> Result<()> {
        self.conn.execute("DELETE FROM albums WHERE id = ?1", [&id])?;
        self.dict.remove(id);
        self.uid_to_id.retain(|_, v| v != id);
        self.path_lookup.retain(|_, v| v != id);
        self.track_lookup.retain(|_, v| v.get("albumId").and_then(|a| a.as_str()) != Some(id));
        Ok(())
    }

    pub fn ingest(&mut self, id: &str, metadata_json: &str) -> Result<()> {
        self.conn.execute(
            "INSERT INTO albums (id, metadata) VALUES (?1, ?2)",[id, metadata_json],
        )?;
        let uid = u32::try_from(self.conn.last_insert_rowid()).unwrap_or(0);
        self.uid_to_id.insert(uid, id.to_string());

        if let Ok(parsed) = serde_json::from_str::(metadata_json)
            && let Some(album) = parsed.get("album")
                && let Some(info) = album.get("info") {
                    if let Some(tracks) = parsed.get("tracks").and_then(Value::as_array) {
                        for track in tracks {
                            if let Some(tinfo) = track.get("info") {
                                let tp = tinfo.get("track_library_path").and_then(Value::as_str).unwrap_or("").to_string();
                                let track_no = track.get("tracknumber").cloned().unwrap_or_else(|| json!(0));
                                let disc_no = track.get("discnumber").cloned().unwrap_or_else(|| json!(1));
                                let title = track.get("title").cloned().unwrap_or_else(|| json!("Unknown"));
                                let artist = track.get("artist").cloned().unwrap_or_else(|| json!("Unknown"));
                                let duration = tinfo.get("track_duration_time").cloned().unwrap_or_else(|| json!("0:00"));
                                let duration_ms = tinfo.get("track_duration").and_then(Value::as_u64).unwrap_or(0);

                                let track_light = json!({
                                    "path": tp,
                                    "trackNo": track_no,
                                    "discNo": disc_no,
                                    "title": title,
                                    "artist": artist,
                                    "duration": duration,
                                    "durationMs": duration_ms,
                                    "albumId": id
                                });
                                self.track_lookup.insert(tp.clone(), track_light);

                                let raw_rel = tinfo.get("track_path").and_then(Value::as_str).unwrap_or("");
                                let full_rel_path = Path::new(id).join(raw_rel);
                                let normalized = full_rel_path.to_string_lossy().trim_start_matches('/').to_string();
                                self.path_lookup.insert(normalized, id.to_string());
                            }
                        }
                    }

                    let entry = json!({
                        "id": id,
                        "album": album.get("album"),
                        "albumartist": album.get("albumartist"),
                        "date": album.get("date"),
                        "genre": album.get("genre"),
                        "cover_path": info.get("cover_path"),
                        "cover_hash": info.get("cover_hash"),
                        "album_duration_time": info.get("album_duration_time"),
                        "total_discs": info.get("total_discs"),
                        "total_tracks": info.get("total_tracks"),
                        "unix_added": info.get("unix_added"),
                        "tags": album.get("tags")
                    });
                    self.dict.insert(id.to_string(), entry);
                }

        Ok(())
    }

    pub fn query_ids(&self, sql: &str) -> Result<Vec> {
        let mut stmt = self.conn.prepare(sql)?;
        let ids: Vec = stmt
            .query_map([], |row| row.get(0))?
            .filter_map(Result::ok)
            .collect();
        Ok(ids)
    }

    pub fn build_cache(&mut self) -> Result<()> {
        self.collections_cache.clear();
        for (key, collection) in &self.manifest.collections {
            let expanded_filter = expand_shorthand(&collection.filter);
            let sql = format!("SELECT uid FROM albums WHERE {expanded_filter}");
            let mut stmt = self.conn.prepare(&sql)?;
            let uids: HashSet = stmt.query_map([], |row| row.get(0))?.filter_map(Result::ok).collect();
            self.collections_cache.insert(key.clone(), uids);
        }

        self.sorters_cache.clear();
        for (key, sorter) in &self.manifest.sorters {
            let expanded_order = expand_shorthand(&sorter.order_by);
            let sql = format!("SELECT uid FROM albums ORDER BY {expanded_order}");
            let mut stmt = self.conn.prepare(&sql)?;
            let uids: Vec = stmt.query_map([], |row| row.get(0))?.filter_map(Result::ok).collect();
            self.sorters_cache.insert(key.clone(), uids);
        }

        self.shelves_cache.clear();
        for (key, shelf) in &self.manifest.shelves {
            if let Some(file_path) = &shelf.file {
                let expanded = crate::expand_path(file_path);
                if let Ok(content) = std::fs::read_to_string(&expanded) {
                    let lines: Vec = content.lines()
                        .map(|l| l.trim().to_string())
                        .filter(|l| !l.is_empty() && !l.starts_with('#'))
                        .collect();

                    if let Ok(json_arr) = serde_json::to_string(&lines) {
                        let sql = "SELECT a.uid FROM json_each(?1) j JOIN albums a ON a.id = j.value ORDER BY j.key";
                        if let Ok(mut stmt) = self.conn.prepare(sql) {
                            let uids: Vec = stmt.query_map([json_arr], |row| row.get(0))
                                .map(|rows| rows.filter_map(Result::ok).collect())
                                .unwrap_or_default();
                            self.shelves_cache.insert(key.clone(), uids);
                        }
                    }
                } else {
                    self.shelves_cache.insert(key.clone(), vec![]);
                }
            } else if let (Some(filter), Some(order_by)) = (&shelf.filter, &shelf.order_by) {
                let expanded_filter = expand_shorthand(filter);
                let expanded_order = expand_shorthand(order_by);
                let sql = format!("SELECT uid FROM albums WHERE {expanded_filter} ORDER BY {expanded_order}");
                if let Ok(mut stmt) = self.conn.prepare(&sql) {
                    let uids: Vec = stmt.query_map([], |row| row.get(0))
                        .map(|rows| rows.filter_map(Result::ok).collect())
                        .unwrap_or_default();
                    self.shelves_cache.insert(key.clone(), uids);
                }
            }
        }

        self.facets_cache.clear();
        for (key, grouper) in &self.manifest.groupers {
            let expanded_select = expand_shorthand(&grouper.select);
            let sql = format!("SELECT uid, {expanded_select} FROM albums");
            let mut stmt = self.conn.prepare(&sql)?;
            let mut rows = stmt.query([])?;

            let mut map: HashMap<String, HashSet> = HashMap::new();

            while let Some(row) = rows.next()? {
                let uid: u32 = row.get(0)?;
                let raw_val: rusqlite::types::Value = row.get(1)?;

                let val_str = match raw_val {
                    rusqlite::types::Value::Text(s) => s,
                    rusqlite::types::Value::Integer(i) => i.to_string(),
                    rusqlite::types::Value::Real(f) => f.to_string(),
                    _ => continue,
                };

                if let Ok(Value::Array(arr)) = serde_json::from_str(&val_str) {
                    for v in arr {
                        if let Some(s) = v.as_str() {
                            map.entry(s.trim().to_string()).or_default().insert(uid);
                        }
                    }
                } else if let Ok(Value::String(s)) = serde_json::from_str(&val_str) {
                    map.entry(s.trim().to_string()).or_default().insert(uid);
                } else {
                    map.entry(val_str.trim().to_string()).or_default().insert(uid);
                }
            }
            self.facets_cache.insert(key.clone(), map);
        }

        Ok(())
    }

    pub fn request_view(&self, collection: &str, sort: &str, filter_key: Option<&str>, filter_val: Option<&str>, reverse: bool) -> Vec {
        let empty_set = HashSet::new();
        let collection_mask = self.collections_cache.get(collection).unwrap_or(&empty_set);
        let mut final_mask = collection_mask.clone();

        if let (Some(fk), Some(fv)) = (filter_key, filter_val) {
            if fk == "search" {
                let sql = "SELECT uid FROM albums WHERE {$.album.album} LIKE ?1 OR {$.album.albumartist} LIKE ?1";
                if let Ok(mut stmt) = self.conn.prepare(&expand_shorthand(sql)) {
                    let pattern = format!("%{fv}%");
                    if let Ok(match_uids_iter) = stmt.query_map([pattern], |row| row.get::(0)) {
                        let match_uids: HashSet = match_uids_iter.filter_map(Result::ok).collect();
                        final_mask.retain(|uid| match_uids.contains(uid));
                    }
                }
            } else if let Some(facet_vals) = self.facets_cache.get(fk) {
                if let Some(facet_mask) = facet_vals.get(fv) {
                    final_mask.retain(|uid| facet_mask.contains(uid));
                } else {
                    final_mask.clear();
                }
            }
        }

        let empty_vec = Vec::new();
        let sorted_uids = self.sorters_cache.get(sort).unwrap_or(&empty_vec);

        let mut res: Vec = sorted_uids.iter()
            .filter(|uid| final_mask.contains(*uid))
            .filter_map(|uid| self.uid_to_id.get(uid).cloned())
            .collect();

        if reverse {
            res.reverse();
        }
        res
    }

    pub fn request_shelf_view(&self, shelf_key: &str) -> Vec {
        let empty_vec = Vec::new();
        let uids = self.shelves_cache.get(shelf_key).unwrap_or(&empty_vec);
        uids.iter().filter_map(|uid| self.uid_to_id.get(uid).cloned()).collect()
    }

    pub fn request_group(&self, collection: &str, grouper: &str) -> Vec {
        let empty_set = HashSet::new();
        let collection_mask = self.collections_cache.get(collection).unwrap_or(&empty_set);

        let mut results = Vec::new();
        if let Some(facet_map) = self.facets_cache.get(grouper) {
            for (val, mask) in facet_map {
                let count = mask.intersection(collection_mask).count();
                if count > 0 {
                    results.push(json!({
                        "value": val,
                        "label": val,
                        "count": count
                    }));
                }
            }
        }

        results.sort_by(|a, b| {
            let label_a = a.get("label").and_then(Value::as_str).unwrap_or("").to_lowercase();
            let label_b = b.get("label").and_then(Value::as_str).unwrap_or("").to_lowercase();
            alphanumeric_sort::compare_str(&label_a, &label_b)
        });

        results
    }

    pub fn get_album_json(&self, id: &str) -> Option {
        let mut stmt = self.conn.prepare("SELECT metadata FROM albums WHERE id = ?1").ok()?;
        let mut rows = stmt.query([id]).ok()?;
        if let Some(row) = rows.next().ok()? {
            return row.get(0).ok();
        }
        None
    }
}



use libvellum::config::AppConfig;
use crate::server::state::AppState;
use notify::{Event, RecommendedWatcher, RecursiveMode, Watcher};
use serde_json::json;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::Duration;

struct ChangeFlags {
    config_changed: bool,
    css_changed: bool,
    logic_changed: bool,
    shelf_changed: bool,
}

pub fn start(config_path: &Path, state: Arc) {
    let (tx, mut rx) = tokio::sync::mpsc::channel::<Vec>(10);

    let canon_config_path = config_path.canonicalize().unwrap_or_else(|_| config_path.to_path_buf());
    let config_dir = canon_config_path.parent().unwrap_or_else(|| Path::new(".")).to_path_buf();

    tokio::spawn(async move {
        let tx_clone = tx.clone();
        let mut watcher = RecommendedWatcher::new(
            move |res: notify::Result| {
                if let Ok(event) = res
                    && (event.kind.is_modify() || event.kind.is_create() || event.kind.is_remove()) {
                        let _ = tx_clone.blocking_send(event.paths);
                    }
            },
            notify::Config::default(),
        )
        .expect("Failed to create config watcher");

        watcher
            .watch(&config_dir, RecursiveMode::Recursive)
            .expect("Failed to watch config directory");

        let mut current_watched_shader: Option = {
            let guard = state.config.read().await;
            guard.resolved_shader_path.clone()
        };

        if let Some(ref p) = current_watched_shader
            && p.exists() && !p.starts_with(&config_dir) {
                let _ = watcher.watch(p, RecursiveMode::NonRecursive);
            }

        let mut current_watched_shelf_files: Vec = {
            let guard = state.config.read().await;
            guard.resolved_shelf_files.clone()
        };

        for p in &current_watched_shelf_files {
            if p.exists() && !p.starts_with(&config_dir) {
                let _ = watcher.watch(p, RecursiveMode::NonRecursive);
            }
        }

        while let Some(mut paths) = rx.recv().await {
            tokio::time::sleep(Duration::from_millis(100)).await;
            while let Ok(more_paths) = rx.try_recv() {
                paths.extend(more_paths);
            }

            let flags = classify_events(&paths, &canon_config_path, current_watched_shader.as_ref(), &current_watched_shelf_files);

            if flags.css_changed {
                log::info!("Filesystem change: reloading custom CSS...");
                let mut guard = state.config.write().await;
                let css_path = config_dir.join("vellum.css");
                guard.resolved_css_path = if css_path.exists() { css_path.canonicalize().ok() } else { None };

                let payload = json!({ "type": "THEME_UPDATE" }).to_string();
                let _ = state.tx.send(payload);
            }

            if flags.logic_changed {
                current_watched_shelf_files = handle_logic_change(
                    &state, 
                    &config_dir, 
                    &mut watcher, 
                    &current_watched_shelf_files
                ).await;
            }

            if flags.shelf_changed && !flags.logic_changed {
                log::info!("Filesystem change: reloading shelf files...");
                {
                    let mut query = state.query.lock().await;
                    if let Err(e) = query.build_cache() {
                        log::error!("Failed to rebuild query cache: {e}");
                    }
                }
                let payload = json!({ "type": "LOGIC_UPDATE" }).to_string();
                let _ = state.tx.send(payload);
            }

            if flags.config_changed {
                current_watched_shader = handle_config_change(
                    &state, 
                    &config_dir, 
                    &mut watcher, 
                    current_watched_shader.as_ref()
                ).await;
            }
        }
    });
}

fn classify_events(
    paths: &[PathBuf],
    canon_config_path: &Path,
    current_watched_shader: Option<&PathBuf>,
    current_watched_shelf_files: &[PathBuf]
) -> ChangeFlags {
    let mut flags = ChangeFlags {
        config_changed: false,
        css_changed: false,
        logic_changed: false,
        shelf_changed: false,
    };

    for p in paths {
        let p = p.canonicalize().unwrap_or_else(|_| p.clone());

        if p == *canon_config_path {
            flags.config_changed = true;
        }

        if let Some(sp) = current_watched_shader
            && p == *sp {
                flags.config_changed = true;
            }

        if current_watched_shelf_files.contains(&p) {
            flags.shelf_changed = true;
        }

        if let Some(name) = p.file_name().and_then(|n| n.to_str()) {
            match name {
                "vellum.css" => {
                    flags.css_changed = true;
                }
                "logic.toml" => {
                    flags.logic_changed = true;
                }
                _ => {}
            }
        }
    }
    flags
}

async fn handle_logic_change(
    state: &Arc,
    config_dir: &Path,
    watcher: &mut RecommendedWatcher,
    current_watched_shelf_files: &[PathBuf]
) -> Vec {
    log::info!("Filesystem change: reloading logic.toml...");
    let logic_path = config_dir.join("logic.toml");
    let resolved = if logic_path.exists() { logic_path.canonicalize().ok() } else { None };

    let mut new_shelf_files = Vec::new();

    {
        let mut guard = state.config.write().await;
        guard.resolved_logic_path.clone_from(&resolved);
    }

    if let Some(ref lp) = resolved {
        let mut query = state.query.lock().await;
        if let Err(e) = query.reload_manifest(lp) {
            log::error!("Failed to reload logic.toml: {e}");
        } else {
            for shelf in query.manifest.shelves.values() {
                if let Some(file) = &shelf.file {
                    let expanded = libvellum::utils::expand_path(file);
                    new_shelf_files.push(expanded.canonicalize().unwrap_or(expanded));
                }
            }
        }
    }

    for p in current_watched_shelf_files {
        if !new_shelf_files.contains(p) && !p.starts_with(config_dir) {
            let _ = watcher.unwatch(p);
        }
    }
    for p in &new_shelf_files {
        if !current_watched_shelf_files.contains(p) && p.exists() && !p.starts_with(config_dir) {
            let _ = watcher.watch(p, RecursiveMode::NonRecursive);
        }
    }

    {
        let mut guard = state.config.write().await;
        guard.resolved_shelf_files.clone_from(&new_shelf_files);
    }

    let payload = json!({ "type": "LOGIC_UPDATE" }).to_string();
    let _ = state.tx.send(payload);

    new_shelf_files
}

async fn handle_config_change(
    state: &Arc,
    config_dir: &Path,
    watcher: &mut RecommendedWatcher,
    current_watched_shader: Option<&PathBuf>
) -> Option {
    log::info!("Filesystem change: reloading config...");

    match AppConfig::load() {
        Ok((new_config, _, _)) => {
            let thumb_size = new_config.theme.as_ref().and_then(|t| t.thumbnail_size).unwrap_or(200);
            let shader_cfg = new_config.theme.as_ref().and_then(|t| t.shader.clone());

            let next_shader_path = if let Some(s) = &shader_cfg
                && let Some(p) = &s.path {
                    let expanded = libvellum::utils::expand_path(p);
                    let absolute = if expanded.is_absolute() {
                        expanded
                    } else {
                        config_dir.join(expanded)
                    };
                    absolute.canonicalize().ok().or(Some(absolute))
                } else {
                    None
                };

            let mut updated_shader = current_watched_shader.cloned();

            if next_shader_path != updated_shader {
                if let Some(ref old_p) = updated_shader
                    && !old_p.starts_with(config_dir) {
                        let _ = watcher.unwatch(old_p);
                    }
                if let Some(ref new_p) = next_shader_path
                    && new_p.exists() && !new_p.starts_with(config_dir) {
                        let _ = watcher.watch(new_p, RecursiveMode::NonRecursive);
                    }
                updated_shader = next_shader_path.clone();
            }

            {
                let mut config_guard = state.config.write().await;
                config_guard.thumbnail_size = thumb_size;
                config_guard.shader.clone_from(&shader_cfg);
                config_guard.resolved_shader_path.clone_from(&next_shader_path);
            }

            let payload = json!({
                "type": "CONFIG_UPDATE",
                "config": {
                    "thumbnail_size": thumb_size,
                    "shader": shader_cfg
                }
            })
            .to_string();

            let _ = state.tx.send(payload);

            updated_shader
        }
        Err(e) => {
            log::error!("Failed to reload config: {e}");
            current_watched_shader.cloned()
        }
    }
}



pub mod api;
pub mod library;
pub mod mpd;
pub mod query;
pub mod state;
pub mod watchdog;

use anyhow::{Context, Result};
use std::net::SocketAddr;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::{Mutex, RwLock, broadcast};
use tower_http::cors::{Any, CorsLayer};

use self::state::{AppConfig as ServerConfig, AppState};
use libvellum::config::AppConfig;
use libvellum::utils::expand_path;

pub async fn run(port: u16) -> Result<()> {
    let (config, _, config_path): (AppConfig, toml::Value, PathBuf) = AppConfig::load().context("Failed to load application configuration")?;
    let config_dir = config_path.parent().unwrap_or_else(|| Path::new(".")).to_path_buf();

    let lib_root_str = &config.storage.library_root;
    let thumb_size = config.theme.as_ref().and_then(|t| t.thumbnail_size).unwrap_or(200);

    let library_root = expand_path(lib_root_str)
        .canonicalize()
        .context("Invalid library_root path")?;

    let cache_root = expand_path(&config.storage.cache);
    let state_root = expand_path(&config.storage.state);

    std::fs::create_dir_all(&cache_root).ok();
    std::fs::create_dir_all(cache_root.join("cover_data")).ok();
    std::fs::create_dir_all(&state_root).ok();

    let shader_cfg = config.theme.as_ref().and_then(|t| t.shader.clone());

    let resolved_shader_path = if let Some(s) = &shader_cfg
        && let Some(p) = &s.path {
            let expanded = expand_path(p);
            let absolute = if expanded.is_absolute() {
                expanded
            } else {
                config_dir.join(expanded)
            };
            absolute.canonicalize().ok().or(Some(absolute))
        } else {
            None
        };

    let css_path = config_dir.join("vellum.css");
    let resolved_css_path = css_path.canonicalize().ok();

    let logic_path = config_dir.join("logic.toml");
    let resolved_logic_path = logic_path.canonicalize().ok();

    let mut query_engine = query::QueryEngine::new()?;

    let mut resolved_shelf_files = Vec::new();
    for shelf in query_engine.manifest.shelves.values() {
        if let Some(file) = &shelf.file {
            let expanded = expand_path(file);
            resolved_shelf_files.push(expanded.canonicalize().unwrap_or(expanded));
        }
    }

    let server_config = ServerConfig {
        library_root: library_root.clone(),
        cache_root,
        state_root: state_root.clone(),
        thumbnail_size: thumb_size,
        shader: shader_cfg,
        resolved_shader_path,
        resolved_css_path,
        resolved_logic_path,
        resolved_shelf_files,
    };

    let state_file = state_root.join("state.json");
    let ui_state_val = if state_file.exists() {
        let data = std::fs::read_to_string(&state_file).unwrap_or_default();
        serde_json::from_str(&data).unwrap_or_else(|_| serde_json::json!({}))
    } else {
        serde_json::json!({
            "activeTab": "home",
            "activeCollection": "library",
            "sortKey": "default",
            "sortOrder": "default",
            "groupKey": "genre",
            "filter": {
                "key": null,
                "val": null
            },
            "queuePanels": {
                "lyrics": false,
                "tracks": true
            },
            "sidebarWidth": 280
        })
    };

    let lib_scanner = library::scanner::Library::new(library_root.clone());
    lib_scanner.scan(&mut query_engine);

    let query_arc = Arc::new(Mutex::new(query_engine));
    let (tx, _) = broadcast::channel(100);

    let mpd_engine = mpd::start_actor(
        tx.clone(),
        Arc::clone(&query_arc),
        Arc::new(server_config.clone()),
    );

    let app_state = Arc::new(AppState {
        query: Arc::clone(&query_arc),
        ui_state: RwLock::new(ui_state_val),
        tx,
        config: RwLock::new(server_config),
        mpd_engine,
    });

    watchdog::start(&config_path, Arc::clone(&app_state));

    let cors = CorsLayer::new()
        .allow_origin(Any)
        .allow_methods(Any)
        .allow_headers(Any);

    let app = api::router(Arc::clone(&app_state)).layer(cors);

    let addr = SocketAddr::from(([127, 0, 0, 1], port));
    log::info!("Vellum Server listening on http://{addr}");
    axum::serve(tokio::net::TcpListener::bind(addr).await?, app).await?;

    Ok(())
}



use crate::server::mpd::MpdEngine;
use crate::server::query::QueryEngine;
use std::path::PathBuf;
use std::sync::Arc;
use tokio::sync::{Mutex, RwLock, broadcast};
use libvellum::config::ShaderConfig;

pub struct AppState {
    pub query: Arc<Mutex>,
    pub ui_state: RwLock,
    pub tx: broadcast::Sender,
    pub config: RwLock,
    pub mpd_engine: MpdEngine,
}

#[derive(Clone)]
pub struct AppConfig {
    pub library_root: PathBuf,
    pub cache_root: PathBuf,
    pub state_root: PathBuf,
    pub thumbnail_size: u32,
    pub shader: Option,
    pub resolved_shader_path: Option,
    pub resolved_css_path: Option,
    pub resolved_logic_path: Option,
    pub resolved_shelf_files: Vec,
}



use anyhow::{Context, Result};
use rayon::prelude::*;
use serde::{Deserialize, Serialize};
use sha2::{Digest, Sha256};
use std::collections::HashMap;
use std::collections::HashSet;
use std::fs;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::SystemTime;
use tokio::sync::Mutex;
use tokio::sync::mpsc;

use crate::compile;
use libvellum::config::AppConfig;
use libvellum::error::VellumError;
use libvellum::utils::expand_path;
use libvellum::sentinel::{TrustState, verify_trust};

#[derive(Serialize, Deserialize, Clone, Debug)]
struct AlbumCacheEntry {
    pub mtime_sum: u64,
}

#[derive(Serialize, Deserialize)]
struct CurrentState {
    pub hash: String,
}

struct NotificationTaskArgs {
    notify_rx: mpsc::Receiver,
    cache_for_task: Arc<Mutex<HashMap>>,
    exts_for_task: Vec,
    manifests_for_task: Option<Vec>,
    lib_root_for_task: Arc,
    missing_paths: Vec,
    start_time: std::time::Instant,
    verbose: bool,
    silent: bool,
}

pub async fn run(
    target_path: Option,
    force: bool,
    jobs: Option,
    verbose: bool,
    silent: bool,
) -> Result<()> {
    let (config, _, _): (AppConfig, toml::Value, PathBuf) = AppConfig::load().context("Failed to load config")?;
    let library_root = expand_path(&config.storage.library_root)
        .canonicalize()
        .context("Invalid library_root")?;

    let is_full_library = target_path.is_none() || target_path.as_deref() == Some(library_root.as_path());

    if force && is_full_library {
        let client = reqwest::Client::new();
        let _ = client
            .post("http://127.0.0.1:8000/api/internal/notify_force_update")
            .timeout(std::time::Duration::from_secs(2))
            .send()
            .await;
    }

    let exts = config
        .manifest
        .as_ref()
        .and_then(|m| m.supported_extensions.clone())
        .unwrap_or_else(|| vec![".flac".to_string()]);

    let manifests = config.compiler.as_ref().and_then(|c| c.manifests.clone());

    let lib_hash = calculate_hash(&library_root.to_string_lossy());
    let base_cache_dir = expand_path(&config.storage.cache).join("libraries_cache");
    fs::create_dir_all(&base_cache_dir)?;

    validate_library_root(&base_cache_dir, &lib_hash).await?;

    let cache_file = base_cache_dir.join(format!("{lib_hash}.json"));
    let mut cache = load_cache(&cache_file);

    let scan_root = target_path.unwrap_or_else(|| library_root.clone());
    let scan_depth = config
        .compiler
        .as_ref()
        .and_then(|c| c.scan_depth)
        .unwrap_or(4);

    let all_albums = libvellum::scanner::find_target_albums(&scan_root, scan_depth)?;
    let missing_paths = find_missing_paths(&all_albums, &scan_root, &cache);

    if !silent {
        log::info!("Verifying {} albums...", all_albums.len());
    }

    let results = verify_albums_parallel(all_albums, &cache, force, jobs, &exts, manifests.as_ref())?;

    let mut work_queue = Vec::new();

    for (path, mtime, is_dirty) in results {
        if is_dirty {
            work_queue.push(path);
        } else {
            cache.insert(
                path.to_string_lossy().to_string(),
                AlbumCacheEntry { mtime_sum: mtime },
            );
        }
    }

    if work_queue.is_empty() && missing_paths.is_empty() {
        if !silent {
            log::info!("Library is up to date.");
        }
        save_cache(&cache, &cache_file)?;
        return Ok(());
    }

    let dirty_count = work_queue.len();
    let missing_count = missing_paths.len();
    let start_time = std::time::Instant::now();

    let (notify_tx, notify_rx) = mpsc::channel::(100);
    let cache_arc = Arc::new(Mutex::new(cache));

    let task_args = NotificationTaskArgs {
        notify_rx,
        cache_for_task: Arc::clone(&cache_arc),
        exts_for_task: exts.clone(),
        manifests_for_task: manifests.clone(),
        lib_root_for_task: Arc::new(library_root.clone()),
        missing_paths,
        start_time,
        verbose,
        silent,
    };
    let notification_task = start_notification_task(task_args);

    if !work_queue.is_empty() {
        let compile_options = compile::CompileOptions {
            target_path: scan_root,
            flags: vec!["default".to_string()],
            specific_albums: Some(work_queue),
            jobs,
            notify_tx: Some(notify_tx.clone()),
            compile_flags: compile::CompileFlags {
                mode: compile::CompileMode::Standard,
                target: compile::ExportTarget::File,
                pretty: false,
            },
        };
        compile::run(compile_options).await?;
    }

    drop(notify_tx);
    let _ = notification_task.await;

    let elapsed = start_time.elapsed().as_millis();
    if !silent {
        log::info!(
            "Update complete: {dirty_count} updated, {missing_count} removed. Finished in {elapsed}ms."
        );
    }

    let final_cache = Arc::try_unwrap(cache_arc).unwrap().into_inner();
    save_cache(&final_cache, &cache_file)?;

    Ok(())
}

fn find_missing_paths(all_albums: &[PathBuf], scan_root: &Path, cache: &HashMap) -> Vec {
    let mut missing_paths = Vec::new();
    let album_set: HashSet = all_albums.iter().cloned().collect();
    let scan_root_canon = scan_root.canonicalize().unwrap_or_else(|_| scan_root.to_path_buf());

    for cached_path_str in cache.keys() {
        let cached_path = PathBuf::from(cached_path_str);
        if cached_path.starts_with(&scan_root_canon) && !album_set.contains(&cached_path) {
            missing_paths.push(cached_path);
        }
    }
    missing_paths
}

fn start_notification_task(mut args: NotificationTaskArgs) -> tokio::task::JoinHandle<()> {
    tokio::spawn(async move {
        let mut updated_paths = Vec::new();
        while let Some(signal) = args.notify_rx.recv().await {
            if args.verbose && !args.silent {
                log::info!("Updated: {} - {}", signal.artist, signal.album);
            }
            updated_paths.push(signal.path);
        }

        let mut paths_for_server = Vec::new();

        {
            let mut c = args.cache_for_task.lock().await;
            for album_root in &updated_paths {
                let album_path_str = album_root.to_string_lossy().to_string();
                let metadata_path = album_root.join("metadata.toml");
                let mtime_sum = get_mtime_sum(album_root, &metadata_path, &args.exts_for_task, args.manifests_for_task.as_ref());
                c.insert(album_path_str.clone(), AlbumCacheEntry { mtime_sum });
                paths_for_server.push(album_path_str);
            }

            for missing in args.missing_paths {
                let p_str = missing.to_string_lossy().to_string();

                if args.verbose && !args.silent {
                    let display_path = missing.strip_prefix(&*args.lib_root_for_task).unwrap_or(&missing);
                    log::info!("Removed: {}", display_path.display());
                }

                c.remove(&p_str);
                paths_for_server.push(p_str);
            }
            drop(c);
        }

        if paths_for_server.is_empty() {
            return;
        }

        let client = reqwest::Client::new();
        let elapsed_ms = args.start_time.elapsed().as_millis();
        let url = format!("http://127.0.0.1:8000/api/internal/batch_reload?time={elapsed_ms}");

        let _ = client
            .post(&url)
            .json(&paths_for_server)
            .timeout(std::time::Duration::from_secs(30))
            .send()
            .await;
    })
}

async fn validate_library_root(cache_dir: &Path, current_hash: &str) -> Result<()> {
    let current_json_path = cache_dir.join("current.json");
    let mut needs_reset = false;

    if current_json_path.exists() {
        let content = fs::read_to_string(&current_json_path).unwrap_or_default();
        if let Ok(state) = serde_json::from_str::(&content) {
            if state.hash != current_hash {
                needs_reset = true;
            }
        } else {
            needs_reset = true;
        }
    } else {
        needs_reset = true;
    }

    if needs_reset {
        log::info!("Library root changed. Triggering server reset.");
        let _ = fs::write(
            &current_json_path,
            serde_json::to_string(&CurrentState {
                hash: current_hash.to_string(),
            })?,
        );
        let _ = trigger_server_reset().await;
    }
    Ok(())
}

fn verify_albums_parallel(
    albums: Vec,
    cache: &HashMap,
    force: bool,
    jobs: Option,
    exts: &[String],
    manifests: Option<&Vec>,
) -> Result<Vec<(PathBuf, u64, bool)>> {
    let default_parallelism = std::thread::available_parallelism()
        .map(std::num::NonZero::get)
        .unwrap_or(1);
    let pool = rayon::ThreadPoolBuilder::new()
        .num_threads(jobs.unwrap_or(default_parallelism))
        .build()?;

    Ok(pool.install(|| {
        albums
            .into_par_iter()
            .map(|album_root| {
                let album_path_str = album_root.to_string_lossy().to_string();
                let metadata_path = album_root.join("metadata.toml");
                let mtime_sum = get_mtime_sum(&album_root, &metadata_path, exts, manifests);

                if force {
                    return (album_root, mtime_sum, true);
                }

                if let Some(entry) = cache.get(&album_path_str)
                    && entry.mtime_sum == mtime_sum && mtime_sum != 0 {
                         return (album_root, mtime_sum, false);
                    }

                match verify_trust(&album_root, manifests) {
                    Ok(TrustState::Valid) => (album_root, mtime_sum, false),
                    Ok(_) => (album_root, mtime_sum, true),
                    Err(e) => {
                        match e {
                            VellumError::ManifestIoError(_) | VellumError::JsonError(_) => {
                                log::debug!("Cache Read Error for {}: {}. Forcing rebuild.", album_root.display(), e);
                            }
                            _ => {}
                        }
                        (album_root, mtime_sum, true)
                    }
                }
            })
            .collect()
    }))
}

fn calculate_hash(data: &str) -> String {
    let mut hasher = Sha256::new();
    hasher.update(data.as_bytes());
    format!("{:x}", hasher.finalize())
}

fn get_mtime_sum(dir: &Path, meta: &Path, exts: &[String], manifests: Option<&Vec>) -> u64 {
    let d_mtime = fs::metadata(dir)
        .and_then(|m| m.modified())
        .map(|t| {
            t.duration_since(SystemTime::UNIX_EPOCH)
                .unwrap_or_default()
                .as_secs()
        })
        .unwrap_or(0);

    let mut m_mtime = fs::metadata(meta)
        .and_then(|m| m.modified())
        .map(|t| {
            t.duration_since(SystemTime::UNIX_EPOCH)
                .unwrap_or_default()
                .as_secs()
        })
        .unwrap_or(0);

    if let Some(names) = manifests {
        for name in names {
            let p = dir.join(name);
            if p.exists() {
                m_mtime += fs::metadata(&p)
                    .and_then(|m| m.modified())
                    .map(|t| {
                        t.duration_since(SystemTime::UNIX_EPOCH)
                            .unwrap_or_default()
                            .as_secs()
                    })
                    .unwrap_or(0);
            }
        }
    }

    let mut c_mtime = 0;
    let cover_candidates =["cover.jpg", "cover.png", "folder.jpg", "front.jpg"];

    for c in cover_candidates {
        let cp = dir.join(c);
        if cp.exists() {
            c_mtime = fs::metadata(cp)
                .and_then(|m| m.modified())
                .map(|t| {
                    t.duration_since(SystemTime::UNIX_EPOCH)
                        .unwrap_or_default()
                        .as_secs()
                })
                .unwrap_or(0);
            break;
        }
    }

    let mut t_mtime = 0;
    for entry in walkdir::WalkDir::new(dir)
        .max_depth(3)
        .into_iter()
        .filter_map(Result::ok)
    {
        let p = entry.path();
        if p.is_file()
            && let Some(ext) = p.extension().and_then(|e| e.to_str()) {
                let ext_lower = format!(".{}", ext.to_lowercase());
                if exts.contains(&ext_lower) {
                    t_mtime += entry
                        .metadata()
                        .ok()
                        .and_then(|m| m.modified().ok())
                        .map_or(0, |t| {
                            t.duration_since(SystemTime::UNIX_EPOCH)
                                .unwrap_or_default()
                                .as_secs()
                        });
                }
            }
    }

    d_mtime + m_mtime + c_mtime + t_mtime
}

fn load_cache(path: &Path) -> HashMap {
    if let Ok(content) = fs::read_to_string(path)
        && let Ok(cache) = serde_json::from_str::<HashMap>(&content) {
             return cache;
        }
    HashMap::new()
}

fn save_cache(cache: &HashMap, path: &Path) -> Result<()> {
    let content = serde_json::to_string_pretty(cache)?;
    fs::write(path, content)?;
    Ok(())
}

async fn trigger_server_reset() -> Result<()> {
    let client = reqwest::Client::new();
    let _ = client
        .post("http://127.0.0.1:8000/api/internal/reset")
        .timeout(std::time::Duration::from_secs(2))
        .send()
        .await;
    Ok(())
}



mod compile;
mod harvest;
mod manifest;
mod nix;
mod query;
mod run;
mod server;
mod update;

use anyhow::{Context, Result};
use clap::{Parser, Subcommand};
use libvellum::utils::expand_path;

#[derive(Parser)]
#[command(author, version, about, long_about = None)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    Harvest {
        #[arg(value_name = "PATHS", required = true, num_args = 1..)]
        paths: Vec,
        #[arg(long)]
        pretty: bool,
        #[arg(long, short = 'j')]
        jobs: Option,
    },
    Server {
        #[arg(long, default_value = "8000")]
        port: u16,
    },
    Compile {
        #[arg(value_name = "PATH", required = true)]
        path: String,
        #[arg(long)]
        stdout: bool,
        #[arg(long)]
        intermediary: bool,
        #[arg(long)]
        pretty: bool,
        #[arg(long, value_delimiter = ',')]
        flags: Vec,
    },
    Update {
        #[arg(value_name = "PATH")]
        path: Option,
        #[arg(long)]
        force: bool,
        #[arg(long, short = 'j')]
        jobs: Option,
        #[arg(long)]
        verbose: bool,
        #[arg(long)]
        silent: bool,
    },
    Manifest {
        #[arg(long)]
        force: bool,
    },
    Run {
        #[arg(value_name = "COMMAND", required = true)]
        script_cmd: String,
        #[arg(value_name = "PATH")]
        path: Option,
        #[arg(long)]
        playing: bool,
        #[arg(long)]
        id: Option,
    },
    Query {
        #[arg(value_name = "QUERY")]
        query_str: Option,
        #[arg(long)]
        playing: bool,
        #[arg(long)]
        toml: bool,
        #[arg(long)]
        lock: bool,
        #[arg(long)]
        raw: bool,
        #[arg(long)]
        id: bool,
    },
    Nix {
        #[command(subcommand)]
        command: NixCommands,
    },
}

#[derive(Subcommand)]
enum NixCommands {
    Manifest {
        #[arg(long)]
        torrent: String,
        #[arg(long, default_value = "flac,wav")]
        tracks: String,
    },
    Get {
        #[arg(value_name = "PATH")]
        path: Option,
    },
    Build {
        #[arg(value_name = "PATH")]
        path: Option,
    },
}

#[tokio::main]
async fn main() -> Result<()> {
    simple_logger::SimpleLogger::new()
        .with_level(log::LevelFilter::Info)
        .with_module_level("mpd_protocol", log::LevelFilter::Warn)
        .with_module_level("mpd_client", log::LevelFilter::Warn)
        .with_module_level("tracing", log::LevelFilter::Warn)
        .env()
        .init()
        .ok();

    let cli = Cli::parse();

    match cli.command {
        Commands::Harvest {
            paths,
            pretty,
            jobs,
        } => {
            if let Some(j) = jobs {
                rayon::ThreadPoolBuilder::new()
                    .num_threads(j)
                    .build_global()
                    .context("Failed to build thread pool")?;
            }

            let mut targets = Vec::new();
            for p in paths {
                let expanded = expand_path(&p);
                if let Ok(canon) = expanded.canonicalize() {
                    targets.push(canon);
                } else {
                    targets.push(expanded);
                }
            }

            harvest::run(targets, pretty);
            Ok(())
        }
        Commands::Server { port } => server::run(port).await,
        Commands::Compile {
            path,
            stdout,
            intermediary,
            pretty,
            flags,
        } => {
            let expanded = expand_path(&path);
            let options = compile::CompileOptions {
                target_path: expanded,
                flags,
                specific_albums: None,
                jobs: None,
                notify_tx: None,
                compile_flags: compile::CompileFlags {
                    mode: if intermediary {
                        compile::CompileMode::Intermediary
                    } else {
                        compile::CompileMode::Standard
                    },
                    target: if stdout {
                        compile::ExportTarget::Stdout
                    } else {
                        compile::ExportTarget::File
                    },
                    pretty,
                },
            };
            compile::run(options).await
        }
        Commands::Update {
            path,
            force,
            jobs,
            verbose,
            silent,
        } => {
            let expanded = path.map(|p| expand_path(&p));
            update::run(expanded, force, jobs, verbose, silent).await
        }
        Commands::Manifest { force } => manifest::run(force),
        Commands::Run { script_cmd, path, playing, id } => run::execute(script_cmd, path, playing, id).await,
        Commands::Query { query_str, playing, toml, lock, raw, id } => {
            let flags = query::QueryFlags { playing, toml, lock, raw, id };
            query::run(query_str, flags).await
        }
        Commands::Nix { command } => match command {
            NixCommands::Manifest { torrent, tracks } => nix::manifest::run(&torrent, &tracks),
            NixCommands::Get { path } => nix::get::run(path),
            NixCommands::Build { path } => nix::build::run(path),
        },
    }
}



