import { LayoutManager } from "./Layout.svelte.ts";
import { ScrollEngine } from "./Scroll.svelte.ts";

export class GridController {
  layout = new LayoutManager();
  scroll = new ScrollEngine();
  viewportHeight: number = $state(0);

  getAlbums: () => any[] = () => [];

  constructor(getAlbums: () => any[]) {
    this.getAlbums = getAlbums;
  }

  allRows = $derived(this.layout.chunk(this.getAlbums()));

  visibleRows = $derived(Math.ceil(this.viewportHeight / this.layout.rowHeight));

  maxSlots = $derived(Math.max(0, (this.allRows.length + 1 - this.visibleRows)));

  contentHeight = $derived(
    this.layout.getTotalHeight(this.allRows.length) + this.layout.rowHeight
  );

  virtualRows = $derived.by(() => {
    const { start, end } = this.layout.getVisibleIndices(
      this.scroll.currentY, 
      this.viewportHeight, 
      this.allRows.length
    );

    const indicesToRender: number[] =[];
    for (let i = start; i <= end; i++) {
      indicesToRender.push(i);
    }

    return indicesToRender.map(i => ({
      index: i,
      y: this.layout.getRowY(i),
      data: this.allRows[i]
    }));
  });

  update(mainEl: HTMLElement | null, dpr: number = 1) {
    this.scroll.update(this.layout.rowHeight, dpr);

    if (mainEl) {
      mainEl.scrollTop = this.scroll.currentY;
    }
  }

  handleWheel(e: WheelEvent) {
    this.scroll.handleWheel(e, this.maxSlots);
  }

  scrollRow(delta: number) {
    const newSlot = this.scroll.targetSlot + delta;
    this.scroll.targetSlot = Math.max(0, Math.min(newSlot, this.maxSlots));
  }

  resetScroll() {
    this.scroll.syncToSlot(0);
    this.scroll.currentY = 0;
  }
}



import { theme } from "../../../theme.svelte.ts";

export class LayoutManager {
  containerWidth: number = $state(0);

  gapX: number = $derived(theme.albumGrid["gap-x"] ?? 24);
  gapY: number = $derived(theme.albumGrid["gap-y"] ?? 12);
  cardSize: number = $derived(theme.albumGrid["cover-size"] ?? 200);

  creaseHeight: number = $derived(theme.albumGrid["crease-height"] ?? 0);

  rowHeight: number = $derived(
    this.gapY +       
    this.cardSize +     
    (theme.albumGrid["text-gap-main"] ?? 8) +  
    (theme.albumGrid["font-line-height-title"] ?? 18) +     
    (theme.albumGrid["text-gap-lesser"] ?? 2) +
    (theme.albumGrid["font-line-height-artist"] ?? 16)
  );

  cols: number = $derived(Math.max(1, Math.floor((this.containerWidth - 40 + this.gapX) / (this.cardSize + this.gapX))));
  gridWidth: number = $derived((this.cols * this.cardSize) + ((this.cols - 1) * this.gapX));

  get topOffset(): number {
    return this.creaseHeight - this.gapY;
  }

  getTotalHeight(rowCount: number): number {
    return (rowCount * this.rowHeight) + this.topOffset;
  }

  getRowY(index: number): number {
    return (index * this.rowHeight) + this.topOffset;
  }

  getVisibleIndices(scrollY: number, viewportHeight: number, rowCount: number): { start: number, end: number } {
    const buffer = 4;
    const start = Math.floor(scrollY / this.rowHeight) - buffer;
    const end = Math.ceil((scrollY + viewportHeight) / this.rowHeight) + buffer;

    return {
      start: Math.max(0, start),
      end: Math.min(Math.max(0, rowCount - 1), end)
    };
  }

  chunk(arr: T[]): T[][] {
    const results: T[][] =[];
    const columns = this.cols;
    for (let i = 0; i < arr.length; i += columns) {
      results.push(arr.slice(i, i + columns));
    }
    return results;
  }
}



export class ScrollEngine {
  currentY: number = $state(0);
  targetSlot: number = $state(0); 
  wheelAccumulator: number = 0;
  damping: number;
  threshold: number;

  constructor(damping: number = 0.18, threshold: number = 40) {
    this.damping = damping;
    this.threshold = threshold;
  }

  update(rowHeight: number, dpr: number = 1) {
    const idealTargetY = this.targetSlot * rowHeight;
    const snappedTargetY = Math.round(idealTargetY * dpr) / dpr;

    const diff = snappedTargetY - this.currentY;
    const velocity = diff * this.damping;

    if (Math.abs(diff) < 0.01) {
      this.currentY = snappedTargetY;
    } else {
      this.currentY += velocity;
    }
  }

  handleWheel(e: WheelEvent, maxSlots: number) {
    this.wheelAccumulator += e.deltaY;

    if (Math.abs(this.wheelAccumulator) > this.threshold) {
      const direction = this.wheelAccumulator > 0 ? 1 : -1;
      const base = Math.round(this.targetSlot);

      this.targetSlot = Math.max(0, Math.min(base + direction, maxSlots));
      this.wheelAccumulator = 0;
    }
  }

  syncToSlot(slot: number) {
    this.targetSlot = slot;
  }

  shiftPosition(deltaY: number, rowHeight: number, maxSlots: number) {
    this.currentY += deltaY;
    const slotDelta = deltaY / rowHeight;
    this.targetSlot = Math.max(0, Math.min(this.targetSlot + slotDelta, maxSlots));
  }
}




