  }

  function handlePlayDisc(discNumber: number) {
    if (onplaydisc) {
      onplaydisc(discNumber);
    } else {
      const firstIndex = tracks.findIndex(t => t.discnumber === discNumber);
      if (firstIndex !== -1 && onplay) {
        onplay(firstIndex);
      }
    }
  }

  function handleKeydown(e: KeyboardEvent, index: number) {
    if (e.key === 'Enter') {
      handlePlay(index);
    }
  }




