export const player = $state<{
  state: string;
  currentAlbumId: string | null;
  currentFile: string | null;
  title: string;
  artist: string;
  elapsed: number;
  duration: number;
  lastUpdated: number;
  queue: any[];
}>({
  state: "stop",
  currentAlbumId: null,
  currentFile: null,
  title: "",
  artist: "",
  elapsed: 0,
  duration: 0,
  lastUpdated: 0,
  queue:[]
});

export function updatePlayerState(data: any) {
  player.state = data.state;
  player.currentAlbumId = data.album_id;
  player.currentFile = data.file;
  player.title = data.title || "";
  player.artist = data.artist || "";
  player.elapsed = parseFloat(data.elapsed || 0);
  player.duration = parseFloat(data.duration || 0);
  player.lastUpdated = performance.now();

  if (data.queue) {
    player.queue = data.queue;
  }
}



export function connectSocket(onOpen?: () => void, onMessage?: (e: MessageEvent) => void): WebSocket {
  const protocol = 'ws:';
  const host = '127.0.0.1:8000'; 
  const url = `${protocol}//${host}/ws`;

  let socket = new WebSocket(url);

  socket.onopen = () => {
    console.log("Vellum WebSocket: Connected to backend");
    if (onOpen) onOpen();
  };

  socket.onmessage = (event: MessageEvent) => {
    if (onMessage) onMessage(event);
  };

  socket.onclose = () => {
    console.log("Vellum WebSocket: Disconnected. Reconnecting...");
    setTimeout(() => {
      connectSocket(onOpen, onMessage);
    }, 2000);
  };

  socket.onerror = (err: Event) => {
    console.error("Vellum WebSocket: Error", err);
  };

  return socket;
}

export async function playAlbum(id: string, offset: number = 0): Promise {
  const encodedId = encodeURIComponent(id);
  const response = await fetch(`/api/play/${encodedId}?offset=${offset}`, { method: "POST" });
  return await response.json();
}

